INSERT INTO public.framework_nodes (id, framework_id, parent_id, node_type, reference_code, name, name_ar, description, description_ar, guidance, guidance_ar, sort_order, path, depth, is_active, is_assessable, weight, max_score, metadata_json, created_at, updated_at, maturity_level, evidence_type, acceptance_criteria, acceptance_criteria_en, spec_references, priority, assessment_type) VALUES ('1b5345d1-55a3-4988-a267-4028c37bcd65', '23cdd151-eef3-499f-9db5-e46ae7f7e1f2', '1f02e28a-a75c-41f0-ac63-8e2eddb5c647', 'Question', 'DSI.MQ.1', 'Has the entity developed and implemented a Data Sharing and Integration (DSI) Plan in line with the Data Sharing Policies?', 'هل قامت الجهة بوضع وتنفيذ خطة مشاركة البيانات وتكاملها بما يتماشى مع سياسات مشاركة البيانات؟', NULL, NULL, NULL, NULL, 0, '/1f02e28a-a75c-41f0-ac63-8e2eddb5c647/1b5345d1-55a3-4988-a267-4028c37bcd65/', 1, true, false, NULL, NULL, '{"maturity_levels": [{"level": 0, "name_ar": "غير موجود", "name_en": "Non-Existent", "evidence_ar": "", "evidence_en": "N/A", "description_ar": "", "description_en": "No data sharing standards practices exist within the entity."}, {"level": 1, "name_ar": "مبدئي", "name_en": "Initial", "evidence_ar": "", "evidence_en": "Meeting minutes, internal memos discussing data sharing standards needs.", "description_ar": "", "description_en": "Initial awareness of data sharing standards. Ad-hoc activities with no formal processes."}, {"level": 2, "name_ar": "مُدار", "name_en": "Managed", "evidence_ar": "", "evidence_en": "Approved policy documents, organizational structure for data sharing standards.", "description_ar": "", "description_en": "data sharing standards processes have been drafted and partially approved. Initial structure documented."}, {"level": 3, "name_ar": "محدد", "name_en": "Defined", "evidence_ar": "", "evidence_en": "Complete framework document, distribution records, training certificates.", "description_ar": "", "description_en": "Comprehensive data sharing standards framework implemented across the entity with standardized procedures."}, {"level": 4, "name_ar": "مُقاس", "name_en": "Measured", "evidence_ar": "", "evidence_en": "KPI dashboards, compliance scorecards, quarterly reports.", "description_ar": "", "description_en": "data sharing standards effectiveness is measured through defined KPIs. Regular monitoring and reporting."}, {"level": 5, "name_ar": "محسّن", "name_en": "Optimized", "evidence_ar": "", "evidence_en": "Improvement initiative reports, innovation documentation, external audit results.", "description_ar": "", "description_en": "Continuous improvement of data sharing standards through data-driven insights. Industry-leading practices."}], "acceptance_criteria": {"0": [{"order": 1, "text_ar": "لا توجد ممارسات أو عمليات data sharing standards موثقة", "text_en": "No data sharing standards practices or processes are documented"}, {"order": 2, "text_ar": "لا يوجد وعي بمتطلبات data sharing standards", "text_en": "No awareness of data sharing standards requirements"}], "1": [{"order": 1, "text_ar": "وعي أساسي بمتطلبات data sharing standards لدى أصحاب المصلحة الرئيسيين", "text_en": "Basic awareness of data sharing standards requirements exists among key stakeholders"}, {"order": 2, "text_ar": "يتم تنفيذ أنشطة data sharing standards بشكل عشوائي", "text_en": "Ad-hoc data sharing standards activities are performed reactively"}, {"order": 3, "text_ar": "يتم تطوير مسودات أو وثائق غير رسمية", "text_en": "Draft or informal documents are being developed"}], "2": [{"order": 1, "text_ar": "تمت صياغة سياسة data sharing standards والموافقة عليها رسمياً", "text_en": "data sharing standards policy has been formally drafted and approved by leadership"}, {"order": 2, "text_ar": "هيكل العمليات موثق لـ data sharing standards", "text_en": "Process structure is documented for data sharing standards"}, {"order": 3, "text_ar": "تم تحديد معايير أولية للمجالات الحرجة", "text_en": "Initial standards are defined for critical areas"}, {"order": 4, "text_ar": "تم إنشاء فريق أو لجنة مسؤولة", "text_en": "Responsible team or committee has been established"}], "3": [{"order": 1, "text_ar": "تم تنفيذ إطار data sharing standards بالكامل عبر الجهة", "text_en": "data sharing standards framework is fully implemented across the entity"}, {"order": 2, "text_ar": "تم إبلاغ السياسات والمعايير لجميع أصحاب المصلحة", "text_en": "Policies and standards are communicated to all relevant stakeholders"}, {"order": 3, "text_ar": "تمت جدولة مراجعات وتحديثات منتظمة", "text_en": "Regular reviews and updates are scheduled"}, {"order": 4, "text_ar": "الأدوار مدمجة في الهيكل التنظيمي", "text_en": "Roles are integrated into organizational structure"}], "4": [{"order": 1, "text_ar": "تم تحديد وتتبع مؤشرات أداء data sharing standards", "text_en": "KPIs and metrics for data sharing standards are defined and actively tracked"}, {"order": 2, "text_ar": "يتم إجراء مراقبة امتثال منتظمة", "text_en": "Regular compliance monitoring is conducted"}, {"order": 3, "text_ar": "يتم تقديم تقارير الأداء للقيادة العليا بشكل دوري", "text_en": "Performance is reported to senior leadership periodically"}, {"order": 4, "text_ar": "المقارنة المرجعية مع المعايير الوطنية والدولية", "text_en": "Benchmarking against national and international standards"}], "5": [{"order": 1, "text_ar": "تم إنشاء دورة تحسين مستمر لـ data sharing standards وهي قيد التشغيل", "text_en": "Continuous improvement cycle for data sharing standards is established and operational"}, {"order": 2, "text_ar": "يتم السعي النشط للابتكارات وأفضل الممارسات واعتمادها", "text_en": "Innovations and best practices are actively pursued and adopted"}, {"order": 3, "text_ar": "تعمل الجهة كنموذج أو تساهم في المعايير الوطنية", "text_en": "Entity serves as a model or contributes to national standards"}, {"order": 4, "text_ar": "آليات المراقبة والإنفاذ المؤتمتة مطبقة", "text_en": "Automated monitoring and enforcement mechanisms are in place"}]}}', '2026-04-08 12:12:09.276579+00', '2026-04-08 12:12:09.276579+00', NULL, NULL, NULL, NULL, NULL, NULL, NULL);
