ion_ar": "", "description_en": "Comprehensive enterprise data models framework implemented across the entity with standardized procedures."}, {"level": 4, "name_ar": "مُقاس", "name_en": "Measured", "evidence_ar": "", "evidence_en": "KPI dashboards, compliance scorecards, quarterly reports.", "description_ar": "", "description_en": "enterprise data models effectiveness is measured through defined KPIs. Regular monitoring and reporting."}, {"level": 5, "name_ar": "محسّن", "name_en": "Optimized", "evidence_ar": "", "evidence_en": "Improvement initiative reports, innovation documentation, external audit results.", "description_ar": "", "description_en": "Continuous improvement of enterprise data models through data-driven insights. Industry-leading practices."}], "acceptance_criteria": {"0": [{"order": 1, "text_ar": "لا توجد ممارسات أو عمليات enterprise data models موثقة", "text_en": "No enterprise data models practices or processes are documented"}, {"order": 2, "text_ar": "لا يوجد وعي بمتطلبات enterprise data models", "text_en": "No awareness of enterprise data models requirements"}], "1": [{"order": 1, "text_ar": "وعي أساسي بمتطلبات enterprise data models لدى أصحاب المصلحة الرئيسيين", "text_en": "Basic awareness of enterprise data models requirements exists among key stakeholders"}, {"order": 2, "text_ar": "يتم تنفيذ أنشطة enterprise data models بشكل عشوائي", "text_en": "Ad-hoc enterprise data models activities are performed reactively"}, {"order": 3, "text_ar": "يتم تطوير مسودات أو وثائق غير رسمية", "text_en": "Draft or informal documents are being developed"}], "2": [{"order": 1, "text_ar": "تمت صياغة سياسة enterprise data models والموافقة عليها رسمياً", "text_en": "enterprise data models policy has been formally drafted and approved by leadership"}, {"order": 2, "text_ar": "هيكل العمليات موثق لـ enterprise data models", "text_en": "Process structure is documented for enterprise data models"}, {"order": 3, "text_ar": "تم تحديد معايير أولية للمجالات الحرجة", "text_en": "Initial standards are defined for critical areas"}, {"order": 4, "text_ar": "تم إنشاء فريق أو لجنة مسؤولة", "text_en": "Responsible team or committee has been established"}], "3": [{"order": 1, "text_ar": "تم تنفيذ إطار enterprise data models بالكامل عبر الجهة", "text_en": "enterprise data models framework is fully implemented across the entity"}, {"order": 2, "text_ar": "تم إبلاغ السياسات والمعايير لجميع أصحاب المصلحة", "text_en": "Policies and standards are communicated to all relevant stakeholders"}, {"order": 3, "text_ar": "تمت جدولة مراجعات وتحديثات منتظمة", "text_en": "Regular reviews and updates are scheduled"}, {"order": 4, "text_ar": "الأدوار مدمجة في الهيكل التنظيمي", "text_en": "Roles are integrated into organizational structure"}], "4": [{"order": 1, "text_ar": "تم تحديد وتتبع مؤشرات أداء enterprise data models", "text_en": "KPIs and metrics for enterprise data models are defined and actively tracked"}, {"order": 2, "text_ar": "يتم إجراء مراقبة امتثال منتظمة", "text_en": "Regular compliance monitoring is conducted"}, {"order": 3, "text_ar": "يتم تقديم تقارير الأداء للقيادة العليا بشكل دوري", "text_en": "Performance is reported to senior leadership periodically"}, {"order": 4, "text_ar": "المقارنة المرجعية مع المعايير الوطنية والدولية", "text_en": "Benchmarking against national and international standards"}], "5": [{"order": 1, "text_ar": "تم إنشاء دورة تحسين مستمر لـ enterprise data models وهي قيد التشغيل", "text_en": "Continuous improvement cycle for enterprise data models is established and operational"}, {"order": 2, "text_ar": "يتم السعي النشط للابتكارات وأفضل الممارسات واعتمادها", "text_en": "Innovations and best practices are actively pursued and adopted"}, {"order": 3, "text_ar": "تعمل الجهة كنموذج أو تساهم في المعايير الوطنية", "text_en": "Entity serves as a model or contributes to national standards"}, {"order": 4, "text_ar": "آليات المراقبة والإنفاذ المؤتمتة مطبقة", "text_en": "Automated monitoring and enforcement mechanisms are in place"}]}}', '2026-04-08 12:12:09.276578+00', '2026-04-08 12:12:09.276578+00', NULL, NULL, NULL, NULL, NULL, NULL, NULL);
