r metadata integration"}, {"order": 3, "text_ar": "تم تحديد معايير أولية للمجالات الحرجة", "text_en": "Initial standards are defined for critical areas"}, {"order": 4, "text_ar": "تم إنشاء فريق أو لجنة مسؤولة", "text_en": "Responsible team or committee has been established"}], "3": [{"order": 1, "text_ar": "تم تنفيذ إطار metadata integration بالكامل عبر الجهة", "text_en": "metadata integration framework is fully implemented across the entity"}, {"order": 2, "text_ar": "تم إبلاغ السياسات والمعايير لجميع أصحاب المصلحة", "text_en": "Policies and standards are communicated to all relevant stakeholders"}, {"order": 3, "text_ar": "تمت جدولة مراجعات وتحديثات منتظمة", "text_en": "Regular reviews and updates are scheduled"}, {"order": 4, "text_ar": "الأدوار مدمجة في الهيكل التنظيمي", "text_en": "Roles are integrated into organizational structure"}], "4": [{"order": 1, "text_ar": "تم تحديد وتتبع مؤشرات أداء metadata integration", "text_en": "KPIs and metrics for metadata integration are defined and actively tracked"}, {"order": 2, "text_ar": "يتم إجراء مراقبة امتثال منتظمة", "text_en": "Regular compliance monitoring is conducted"}, {"order": 3, "text_ar": "يتم تقديم تقارير الأداء للقيادة العليا بشكل دوري", "text_en": "Performance is reported to senior leadership periodically"}, {"order": 4, "text_ar": "المقارنة المرجعية مع المعايير الوطنية والدولية", "text_en": "Benchmarking against national and international standards"}], "5": [{"order": 1, "text_ar": "تم إنشاء دورة تحسين مستمر لـ metadata integration وهي قيد التشغيل", "text_en": "Continuous improvement cycle for metadata integration is established and operational"}, {"order": 2, "text_ar": "يتم السعي النشط للابتكارات وأفضل الممارسات واعتمادها", "text_en": "Innovations and best practices are actively pursued and adopted"}, {"order": 3, "text_ar": "تعمل الجهة كنموذج أو تساهم في المعايير الوطنية", "text_en": "Entity serves as a model or contributes to national standards"}, {"order": 4, "text_ar": "آليات المراقبة والإنفاذ المؤتمتة مطبقة", "text_en": "Automated monitoring and enforcement mechanisms are in place"}]}}', '2026-04-08 12:12:09.276573+00', '2026-04-08 12:12:09.276573+00', NULL, NULL, NULL, NULL, NULL, NULL, NULL);
INSERT INTO public.framework_nodes (id, framework_id, parent_id, node_type, reference_code, name, name_ar, description, description_ar, guidance, guidance_ar, sort_order, path, depth, is_active, is_assessable, weight, max_score, metadata_json, created_at, updated_at, maturity_level, evidence_type, acceptance_criteria, acceptance_criteria_en, spec_references, priority, assessment_type) VALUES ('df75f8c6-9c7b-435f-99ff-dc270aa71c64', '23cdd151-eef3-499f-9db5-e46ae7f7e1f2', '6d9c31a2-8b0f-4c21-8817-ac565c05c7ab', 'Question', 'DG.MQ.1', 'Has the entity established and implemented a Data Management and Personal Data Protection (DM & PDP) Strategy and a DM & PDP Plan with Key Performance Indicators (KPIs) that can be continuously measured to ensure optimization?', 'هل قامت الجهة بوضع وتنفيذ استراتيجية إدارة البيانات وحماية البيانات الشخصية وخطة إدارة البيانات وحماية البيانات الشخصية مع مؤشرات الأداء الرئيسية التي يمكن قياسها باستمرار لضمان التحسين؟', NULL, NULL, NULL, NULL, 0, '/6d9c31a2-8b0f-4c21-8817-ac565c05c7ab/df75f8c6-9c7b-435f-99ff-dc270aa71c64/', 1, true, false, NULL, NULL, '{"maturity_levels": [{"level": 0, "name_ar": "غير موجود", "name_en": "Non-Existent", "evidence_ar": "", "evidence_en": "N/A", "description_ar": "", "description_en": "No data governance framework, policies, or standards exist."}, {"level": 1, "name_ar": "مبدئي", "name_en": "Initial", "evidence_ar": "", "evidence_en": "Meeting minutes, internal memos discussing data governance needs.", "description_ar": "", "description_en": "Initial awareness of data governance. Ad-hoc governance activities with no formal framework."}, {"level": 2, "name_ar": "مُدار", "name_en": "Managed", "evidence_ar": "", "evidence_en": "Approved governance policy documents, organizational structure for data governance.", "description_ar": "", "description_en": "Data governance policies have been drafted and partially approved. Initial framework structure documented."}, {"level": 3, "name_ar": "محدد", "name_en": "Defined", "evidence_ar": "", "evidence_en": "Complete governance framework document, policy distribution records, training completion certificates.", "description_ar": "", "description_en": "Comprehensive data governance framework implemented across the entity with standardized policies and procedures."}, {"level": 4, "name_ar": "مُقاس", "name_en": "Measured", "evidence_ar": "", "evidence_en": "Governance KPI dashboards, compliance scorecards, quarterly governance reports.", "description_ar": "", "description_en": "Data governance effectiveness is measured through defined KPIs. Regular monitoring and reporting."}, {"level": 5, "name_ar": "محسّن", "name_en": "Optimized", "evidence_ar": "", "evidence_en": "Improvement initiative reports, innovation documentation, external audit results.", "description_ar": "", "description_en": "Continuous improvement of governance framework through data-driven insights. Industry-leading governance practices."}], "acceptance_criteria": {"0": [{"order": 1, "text_ar": "لا يوجد سياسة أو إطار لحوكمة البيانات", "text_en": "No data governance policy or framework exists"}, {"order": 2, "text_ar": "لا توجد معايير أو إرشادات موثقة متعلقة بالبيانات", "text_en": "No data-related standards or guidelines are documented"}], "1": [{"order": 1, "text_ar": "وعي أساسي بمتطلبات حوكمة البيانات لدى أصحاب المصلحة الرئيسيين", "text_en": "Basic awareness of data governance requirements exists among key stakeholders"}, {"order": 2, "text_ar": "يتم تنفيذ أنشطة حوكمة البيانات بشكل عشوائي ورد فعل", "text_en": "Ad-hoc data governance activities are performed reactively"}, {"order": 3, "text_ar": "يتم تطوير مسودات أو وثائق حوكمة غير رسمية", "text_en": "Draft or informal governance documents are being developed"}], "2": [{"order": 1, "text_ar": "تمت صياغة سياسة حوكمة البيانات والموافقة عليها رسمياً من القيادة", "text_en": "Data governance policy has been formally drafted and approved by leadership"}, {"order": 2, "text_ar": "هيكل إطار حوكمة البيانات موثق", "text_en": "Data governance framework structure is documented"}, {"order": 3, "text_ar": "تم تحديد معايير بيانات أولية للمجالات الحرجة", "text_en": "Initial data standards are defined for critical data domains"}, {"order": 4, "text_ar": "تم إنشاء لجنة أو مجلس حوكمة البيانات", "text_en": "Data governance committee or council has been established"}], "3": [{"order": 1, "text_ar": "تم تنفيذ إطار حوكمة البيانات بالكامل عبر الجهة", "text_en": "Data governance framework is fully implemented across the entity"}, {"order": 2, "text_ar": "تم إبلاغ السياسات والمعايير لجميع أصحاب المصلحة المعنيين", "text_en": "Policies and standards are communicated to all relevant stakeholders"}, {"order": 3, "text_ar": "تمت جدولة مراجعات وتحديثات الحوكمة المنتظمة", "text_en": "Regular governance reviews and updates are scheduled"}, {"order": 4, "text_ar": "أدوار حوكمة البيانات مدمجة في الهيكل التنظيمي", "text_en": "Data governance roles are integrated into organizational structure"}], "4": [{"order": 1, "text_ar": "تم تحديد وتتبع مؤشرات أداء حوكمة البيانات", "text_en": "Data governance KPIs and metrics are defined and actively tracked"}, {"order": 2, "text_ar": "يتم إجراء مراقبة امتثال منتظمة لسياسات الحوكمة", "text_en": "Regular compliance monitoring against governance policies is conducted"}, {"order": 3, "text_ar": "يتم تقديم تقارير أداء الحوكمة للقيادة العليا بشكل دوري", "text_en": "Governance performance is reported to senior leadership periodically"}, {"order": 4, "text_ar": "المقارنة المرجعية مع معايير الحوكمة الوطنية والدولية", "text_en": "Benchmarking against national and international governance standards"}], "5": [{"order": 1, "text_ar": "تم إنشاء دورة تحسين مستمر لإطار الحوكمة وهي قيد التشغيل", "text_en": "Continuous improvement cycle for governance framework is established and operational"}, {"order": 2, "text_ar": "يتم السعي النشط لابتكارات الحوكمة وأفضل الممارسات واعتمادها", "text_en": "Governance innovations and best practices are actively pursued and adopted"}, {"order": 3, "text_ar": "تعمل الجهة كنموذج للحوكمة أو تساهم في معايير حوكمة البيانات الوطنية", "text_en": "Entity serves as a governance model or contributes to national data governance standards"}, {"order": 4, "text_ar": "آليات مراقبة وإنفاذ الحوكمة المؤتمتة مطبقة", "text_en": "Automated governance monitoring and enforcement mechanisms are in place"}]}}', '2026-04-08 12:12:09.276564+00', '2026-04-08 12:12:09.276568+00', NULL, NULL, NULL, NULL, NULL, NULL, NULL);
INSERT INTO public.framework_nodes (id, framework_id, parent_id, node_type, reference_code, name, name_ar, description, description_ar, guidance, guidance_ar, sort_order, path, depth, is_active, is_assessable, weight, max_score, metadata_json, created_at, updated_at, maturity_level, evidence_type, acceptance_criteria, acceptance_criteria_en, spec_references, priority, assessment_type) VALUES ('fbaa35f7-8a25-430c-8fa8-de95fde00ced', '23cdd151-eef3-499f-9db5-e46ae7f7e1f2', '6d9c31a2-8b0f-4c21-8817-ac565c05c7ab', 'Question', 'DG.MQ.2', 'Has the entity established and implemented Data Management (DM) Policies, Standards, and Guidelines across all Data Management (DM) Domains?', 'هل قامت الجهة بوضع وإعداد وتنفيذ سياسات ومعايير وإرشادات إدارة البيانات عبر جميع مجالات إدارة البيانات؟', NULL, NULL, NULL, NULL, 1, '/6d9c31a2-8b0f-4c21-8817-ac565c05c7ab/fbaa35f7-8a25-430c-8fa8-de95fde00ced/', 1, true, false, NULL, NULL, '{"maturity_levels": [{"level": 0, "name_ar": "غير موجود", "name_en": "Non-Existent", "evidence_ar": "", "evidence_en": "N/A", "description_ar": "", "description_en": "No data governance roles or responsibilities are defined."}, {"level": 1, "name_ar": "مبدئي", "name_en": "Initial", "evidence_ar": "", "evidence_en": "Internal discussions or memos identifying need for data roles.", "description_ar": "", "description_en": "Informal recognition that data governance roles are needed. Some individuals perform governance tasks ad-hoc."}, {"level": 2, "name_ar": "مُدار", "name_en": "Managed", "evidence_ar": "", "evidence_en": "Role descriptions, appointment letters, RACI matrix for data governance.", "description_ar": "", "description_en": "Data governance roles are formally defined. Data Owners and Stewards are appointed for key data domains."}, {"level": 3, "name_ar": "محدد", "name_en": "Defined", "evidence_ar": "", "evidence_en": "Complete organizational chart for data governance, role descriptions, competency frameworks.", "description_ar": "", "description_en": "Data governance roles are fully staffed across all data domains with clear accountability."}, {"level": 4, "name_ar": "مُقاس", "name_en": "Measured", "evidence_ar": "", "evidence_en": "Governance role performance reports, stakeholder satisfaction surveys.", "description_ar": "", "description_en": "Governance role effectiveness is measured. Performance indicators track accountability and responsiveness."}, {"level": 5, "name_ar": "محسّن", "name_en": "Optimized", "evidence_ar": "", "evidence_en": "Innovation reports, inter-entity governance collaboration documentation.", "description_ar": "", "description_en": "Governance roles drive continuous organizational improvement. Cross-entity collaboration on data governance."}], "acceptance_criteria": {"0": [{"order": 1, "text_ar": "لا توجد أدوار حوكمة بيانات محددة (مالك، مشرف، أمين)", "text_en": "No data governance roles (Data Owner, Steward, Custodian) are defined"}, {"order": 2, "text_ar": "لا توجد مساءلة عن أنشطة إدارة البيانات", "text_en": "No accountability for data management activities"}], "1": [{"order": 1, "text_ar": "الاعتراف بالحاجة لأدوار حوكمة البيانات", "text_en": "Recognition that data governance roles are needed"}, {"order": 2, "text_ar": "بعض الأفراد يؤدون مهام حوكمة البيانات بشكل غير رسمي", "text_en": "Some individuals perform data governance tasks informally"}, {"order": 3, "text_ar": "لا توجد أوصاف أو تفويضات رسمية للأدوار", "text_en": "No formal role descriptions or mandates exist"}], "2": [{"order": 1, "text_ar": "تم تحديد أدوار مالك البيانات ومشرف البيانات وأمين البيانات رسمياً", "text_en": "Data Owner, Data Steward, and Data Custodian roles are formally defined"}, {"order": 2, "text_ar": "تم تعيين الأدوار للمجالات الحرجة للبيانات", "text_en": "Roles are appointed for critical data domains"}, {"order": 3, "text_ar": "مصفوفة RACI لأنشطة حوكمة البيانات موثقة", "text_en": "RACI matrix for data governance activities is documented"}, {"order": 4, "text_ar": "تم توفير تدريب أولي للأدوار المعينة في الحوكمة", "text_en": "Initial training provided to appointed governance roles"}], "3": [{"order": 1, "text_ar": "جميع مجالات البيانات لديها مالكين ومشرفين معينين", "text_en": "All data domains have assigned Data Owners and Stewards"}, {"order": 2, "text_ar": "مسؤوليات أدوار الحوكمة مدمجة في التوصيف الوظيفي", "text_en": "Governance role responsibilities are integrated into job descriptions"}, {"order": 3, "text_ar": "برامج تدريب وبناء قدرات منتظمة لأدوار الحوكمة", "text_en": "Regular training and capacity building programs for governance roles"}, {"order": 4, "text_ar": "إجراءات التصعيد لمشاكل البيانات محددة ومتبعة", "text_en": "Escalation procedures for data issues are defined and followed"}], "4": [{"order": 1, "text_ar": "مقاييس أداء أدوار الحوكمة محددة ومتتبعة", "text_en": "Performance metrics for governance roles are defined and tracked"}, {"order": 2, "text_ar": "يتم قياس رضا أصحاب المصلحة عن أدوار الحوكمة", "text_en": "Stakeholder satisfaction with governance roles is measured"}, {"order": 3, "text_ar": "آليات المساءلة مطبقة ومراجعة", "text_en": "Accountability mechanisms are enforced and reviewed"}, {"order": 4, "text_ar": "يتم قياس هيكل الحوكمة مقابل أفضل الممارسات", "text_en": "Governance structure is benchmarked against best practices"}], "5": [{"order": 1, "text_ar": "أدوار الحوكمة تقود الابتكار في إدارة البيانات بنشاط", "text_en": "Governance roles actively drive innovation in data management"}, {"order": 2, "text_ar": "تم إنشاء تعاون حوكمة بيانات بين الجهات", "text_en": "Cross-entity data governance collaboration is established"}, {"order": 3, "text_ar": "هيكل الحوكمة يتطور باستمرار بناءً على احتياجات المنظمة", "text_en": "Governance structure continuously evolves based on organizational needs"}, {"order": 4, "text_ar": "تساهم الجهة في أفضل ممارسات حوكمة البيانات الوطنية", "text_en": "Entity contributes to national data governance best practices"}]}}', '2026-04-08 12:12:09.276569+00', '2026-04-08 12:12:09.276569+00', NULL, NULL, NULL, NULL, NULL, NULL, NULL);
