INSERT INTO public.framework_nodes (id, framework_id, parent_id, node_type, reference_code, name, name_ar, description, description_ar, guidance, guidance_ar, sort_order, path, depth, is_active, is_assessable, weight, max_score, metadata_json, created_at, updated_at, maturity_level, evidence_type, acceptance_criteria, acceptance_criteria_en, spec_references, priority, assessment_type) VALUES ('0a8640ce-ea67-4184-8257-75ceb08968c4', '23cdd151-eef3-499f-9db5-e46ae7f7e1f2', '6d9c31a2-8b0f-4c21-8817-ac565c05c7ab', 'Question', 'DG.MQ.3', 'Has the entity established and operationalized all roles required for the Data Management Organization as per the NDMO Controls & Specifications?', 'هل قامت الجهة بتأسيس وتفعيل جميع الأدوار المطلوبة لمنظمة إدارة البيانات وفقاً لضوابط ومواصفات مكتب إدارة البيانات الوطنية؟', NULL, NULL, NULL, NULL, 2, '/6d9c31a2-8b0f-4c21-8817-ac565c05c7ab/0a8640ce-ea67-4184-8257-75ceb08968c4/', 1, true, false, NULL, NULL, '{"maturity_levels": [{"level": 0, "name_ar": "غير موجود", "name_en": "Non-Existent", "evidence_ar": "", "evidence_en": "N/A", "description_ar": "", "description_en": "No data governance processes exist."}, {"level": 1, "name_ar": "مبدئي", "name_en": "Initial", "evidence_ar": "", "evidence_en": "Incident logs showing ad-hoc data issue resolution.", "description_ar": "", "description_en": "Reactive data issue handling. No formal governance processes."}, {"level": 2, "name_ar": "مُدار", "name_en": "Managed", "evidence_ar": "", "evidence_en": "Process documentation, issue tracking system, change request forms.", "description_ar": "", "description_en": "Core governance processes are documented. Data issue tracking and basic change management established."}, {"level": 3, "name_ar": "محدد", "name_en": "Defined", "evidence_ar": "", "evidence_en": "Integrated process maps, compliance audit reports, change management records.", "description_ar": "", "description_en": "Governance processes are standardized and integrated into business operations."}, {"level": 4, "name_ar": "مُقاس", "name_en": "Measured", "evidence_ar": "", "evidence_en": "Process KPI dashboards, cycle time reports, compliance trend analysis.", "description_ar": "", "description_en": "Process effectiveness is measured with quantitative metrics. Process optimization based on data."}, {"level": 5, "name_ar": "محسّن", "name_en": "Optimized", "evidence_ar": "", "evidence_en": "Automation documentation, AI/ML-based governance tools, process innovation reports.", "description_ar": "", "description_en": "Automated governance processes with predictive analytics. Continuous process innovation."}], "acceptance_criteria": {"0": [{"order": 1, "text_ar": "لا توجد عمليات رسمية لحل مشاكل البيانات", "text_en": "No formal processes for data issue resolution"}, {"order": 2, "text_ar": "لا توجد إدارة تغيير أو مراقبة امتثال للبيانات", "text_en": "No change management or compliance monitoring for data"}], "1": [{"order": 1, "text_ar": "يتم التعامل مع مشاكل البيانات بشكل رد فعل كل حالة على حدة", "text_en": "Data issues are handled reactively on a case-by-case basis"}, {"order": 2, "text_ar": "لا توجد عملية موحدة لإدارة تغيير البيانات", "text_en": "No standardized process for data change management"}, {"order": 3, "text_ar": "قد يوجد تتبع أساسي للمشاكل ولكنه غير رسمي", "text_en": "Basic issue tracking may exist but is informal"}], "2": [{"order": 1, "text_ar": "عملية حل مشاكل البيانات موثقة ومنفذة جزئياً", "text_en": "Data issue resolution process is documented and partially implemented"}, {"order": 2, "text_ar": "تم إنشاء إجراءات إدارة تغيير البيانات", "text_en": "Data change management procedures are established"}, {"order": 3, "text_ar": "توجد أنشطة مراقبة امتثال أساسية", "text_en": "Basic compliance monitoring activities are in place"}, {"order": 4, "text_ar": "نظام تتبع المشاكل يعمل", "text_en": "Issue tracking system is operational"}], "3": [{"order": 1, "text_ar": "عمليات حوكمة البيانات موحدة عبر الجهة", "text_en": "Data governance processes are standardized across the entity"}, {"order": 2, "text_ar": "مراقبة الامتثال منهجية ومنتظمة", "text_en": "Compliance monitoring is systematic and regular"}, {"order": 3, "text_ar": "عمليات إدارة التغيير تتضمن تقييم الأثر", "text_en": "Change management processes include impact assessment"}, {"order": 4, "text_ar": "عمليات الحوكمة مدمجة مع سير العمل", "text_en": "Governance processes are integrated with business workflows"}], "4": [{"order": 1, "text_ar": "مقاييس عمليات الحوكمة (وقت الدورة، معدل الحل) متتبعة", "text_en": "Governance process metrics (cycle time, resolution rate) are tracked"}, {"order": 2, "text_ar": "يتم تحليل اتجاهات الامتثال وتقديم التقارير للقيادة", "text_en": "Compliance trends are analyzed and reported to leadership"}, {"order": 3, "text_ar": "يتم تحديد اختناقات العمليات من خلال تحليل البيانات", "text_en": "Process bottlenecks are identified through data analysis"}, {"order": 4, "text_ar": "يتم اتخاذ إجراءات وقائية بناءً على تحليل الأنماط", "text_en": "Preventive actions are taken based on pattern analysis"}], "5": [{"order": 1, "text_ar": "عمليات الحوكمة تستفيد من الأتمتة والذكاء الاصطناعي", "text_en": "Governance processes leverage automation and AI for efficiency"}, {"order": 2, "text_ar": "يتم استخدام التحليلات التنبؤية للحوكمة الاستباقية", "text_en": "Predictive analytics are used for proactive governance"}, {"order": 3, "text_ar": "التحسين المستمر للعمليات مدفوع بالابتكار", "text_en": "Continuous process improvement is driven by innovation"}, {"order": 4, "text_ar": "يتم مشاركة واعتماد أفضل الممارسات عبر الجهات", "text_en": "Best practices are shared and adopted across entities"}]}}', '2026-04-08 12:12:09.27657+00', '2026-04-08 12:12:09.27657+00', NULL, NULL, NULL, NULL, NULL, NULL, NULL);
INSERT INTO public.framework_nodes (id, framework_id, parent_id, node_type, reference_code, name, name_ar, description, description_ar, guidance, guidance_ar, sort_order, path, depth, is_active, is_assessable, weight, max_score, metadata_json, created_at, updated_at, maturity_level, evidence_type, acceptance_criteria, acceptance_criteria_en, spec_references, priority, assessment_type) VALUES ('0404fafc-f3b0-4379-877a-1c89db86dc6d', '23cdd151-eef3-499f-9db5-e46ae7f7e1f2', '6d9c31a2-8b0f-4c21-8817-ac565c05c7ab', 'Question', 'DG.MQ.4', 'Has the entity established and implemented practices for Change Management including awareness, communication, change control, and capability development?', 'هل قامت الجهة بوضع وتنفيذ ممارسات لإدارة التغيير بما في ذلك التوعية والتواصل والتحكم في التغيير وتطوير القدرات؟', NULL, NULL, NULL, NULL, 3, '/6d9c31a2-8b0f-4c21-8817-ac565c05c7ab/0404fafc-f3b0-4379-877a-1c89db86dc6d/', 1, true, false, NULL, NULL, '{"maturity_levels": [{"level": 0, "name_ar": "غير موجود", "name_en": "Non-Existent", "evidence_ar": "", "evidence_en": "N/A", "description_ar": "", "description_en": "No change management practices practices exist within the entity."}, {"level": 1, "name_ar": "مبدئي", "name_en": "Initial", "evidence_ar": "", "evidence_en": "Meeting minutes, internal memos discussing change management practices needs.", "description_ar": "", "description_en": "Initial awareness of change management practices. Ad-hoc activities with no formal processes."}, {"level": 2, "name_ar": "مُدار", "name_en": "Managed", "evidence_ar": "", "evidence_en": "Approved policy documents, organizational structure for change management practices.", "description_ar": "", "description_en": "change management practices processes have been drafted and partially approved. Initial structure documented."}, {"level": 3, "name_ar": "محدد", "name_en": "Defined", "evidence_ar": "", "evidence_en": "Complete framework document, distribution records, training certificates.", "description_ar": "", "description_en": "Comprehensive change management practices framework implemented across the entity with standardized procedures."}, {"level": 4, "name_ar": "مُقاس", "name_en": "Measured", "evidence_ar": "", "evidence_en": "KPI dashboards, compliance scorecards, quarterly reports.", "description_ar": "", "description_en": "change management practices effectiveness is measured through defined KPIs. Regular monitoring and reporting."}, {"level": 5, "name_ar": "محسّن", "name_en": "Optimized", "evidence_ar": "", "evidence_en": "Improvement initiative reports, innovation documentation, external audit results.", "description_ar": "", "description_en": "Continuous improvement of change management practices through data-driven insights. Industry-leading practices."}], "acceptance_criteria": {"0": [{"order": 1, "text_ar": "لا توجد ممارسات أو عمليات change management practices موثقة", "text_en": "No change management practices practices or processes are documented"}, {"order": 2, "text_ar": "لا يوجد وعي بمتطلبات change management practices", "text_en": "No awareness of change management practices requirements"}], "1": [{"order": 1, "text_ar": "وعي أساسي بمتطلبات change management practices لدى أصحاب المصلحة الرئيسيين", "text_en": "Basic awareness of change management practices requirements exists among key stakeholders"}, {"order": 2, "text_ar": "يتم تنفيذ أنشطة change management practices بشكل عشوائي", "text_en": "Ad-hoc change management practices activities are performed reactively"}, {"order": 3, "text_ar": "يتم تطوير مسودات أو وثائق غير رسمية", "text_en": "Draft or informal documents are being developed"}], "2": [{"order": 1, "text_ar": "تمت صياغة سياسة change management practices والموافقة عليها رسمياً", "text_en": "change management practices policy has been formally drafted and approved by leadership"}, {"order": 2, "text_ar": "هيكل العمليات موثق لـ change management practices", "text_en": "Process structure is documented for change management practices"}, {"order": 3, "text_ar": "تم تحديد معايير أولية للمجالات الحرجة", "text_en": "Initial standards are defined for critical areas"}, {"order": 4, "text_ar": "تم إنشاء فريق أو لجنة مسؤولة", "text_en": "Responsible team or committee has been established"}], "3": [{"order": 1, "text_ar": "تم تنفيذ إطار change management practices بالكامل عبر الجهة", "text_en": "change management practices framework is fully implemented across the entity"}, {"order": 2, "text_ar": "تم إبلاغ السياسات والمعايير لجميع أصحاب المصلحة", "text_en": "Policies and standards are communicated to all relevant stakeholders"}, {"order": 3, "text_ar": "تمت جدولة مراجعات وتحديثات منتظمة", "text_en": "Regular reviews and updates are scheduled"}, {"order": 4, "text_ar": "الأدوار مدمجة في الهيكل التنظيمي", "text_en": "Roles are integrated into organizational structure"}], "4": [{"order": 1, "text_ar": "تم تحديد وتتبع مؤشرات أداء change management practices", "text_en": "KPIs and metrics for change management practices are defined and actively tracked"}, {"order": 2, "text_ar": "يتم إجراء مراقبة امتثال منتظمة", "text_en": "Regular compliance monitoring is conducted"}, {"order": 3, "text_ar": "يتم تقديم تقارير الأداء للقيادة العليا بشكل دوري", "text_en": "Performance is reported to senior leadership periodically"}, {"order": 4, "text_ar": "المقارنة المرجعية مع المعايير الوطنية والدولية", "text_en": "Benchmarking against national and international standards"}], "5": [{"order": 1, "text_ar": "تم إنشاء دورة تحسين مستمر لـ change management practices وهي قيد التشغيل", "text_en": "Continuous improvement cycle for change management practices is established and operational"}, {"order": 2, "text_ar": "يتم السعي النشط للابتكارات وأفضل الممارسات واعتمادها", "text_en": "Innovations and best practices are actively pursued and adopted"}, {"order": 3, "text_ar": "تعمل الجهة كنموذج أو تساهم في المعايير الوطنية", "text_en": "Entity serves as a model or contributes to national standards"}, {"order": 4, "text_ar": "آليات المراقبة والإنفاذ المؤتمتة مطبقة", "text_en": "Automated monitoring and enforcement mechanisms are in place"}]}}', '2026-04-08 12:12:09.27657+00', '2026-04-08 12:12:09.27657+00', NULL, NULL, NULL, NULL, NULL, NULL, NULL);
