INSERT INTO public.framework_nodes (id, framework_id, parent_id, node_type, reference_code, name, name_ar, description, description_ar, guidance, guidance_ar, sort_order, path, depth, is_active, is_assessable, weight, max_score, metadata_json, created_at, updated_at, maturity_level, evidence_type, acceptance_criteria, acceptance_criteria_en, spec_references, priority, assessment_type) VALUES ('d90dc97b-4197-4e3c-a55c-de23a123975a', '23cdd151-eef3-499f-9db5-e46ae7f7e1f2', '4a27fc17-c95e-4878-8675-264137ba8265', 'Specification', 'BIA.M.26', 'تقرير مراقبة فعالية ممارسات وعمليات إدارة وحوكمة ذكاء الأعمال والتحليلات عبر مؤشرات الأداء الرئيسية (KPIs) المحددة مسبقًا.', 'تقرير مراقبة فعالية ممارسات وعمليات إدارة وحوكمة ذكاء الأعمال والتحليلات عبر مؤشرات الأداء الرئيسية (KPIs) المحددة مسبقًا.', NULL, NULL, NULL, NULL, 17, '/611fa68a-94dc-4ef3-b4cc-fb414ef2722d/4a27fc17-c95e-4878-8675-264137ba8265/d90dc97b-4197-4e3c-a55c-de23a123975a/', 2, true, true, 1.00, NULL, NULL, '2026-04-11 01:39:31.914688+00', '2026-04-11 01:57:38.934226+00', 4, 'تقرير مراقبة فعالية ممارسات وعمليات إدارة وحوكمة ذكاء الأعمال والتحليلات عبر مؤشرات الأداء الرئيسية (KPIs) المحددة مسبقًا.', 'يجب على الجهة أن ترفق تقريراً محدثاً ومعتمداً من صاحب الصلاحية لمراقبة فعالية ممارسات وعمليات إدارة وحوكمة مجال ذكاء الأعمال والتحليلات بناءً على مؤشرات الأداء الرئيسية (KPIs) وبطاقات المؤشرات المحددة والمعرفة مسبقاً. 
