INSERT INTO public.framework_nodes (id, framework_id, parent_id, node_type, reference_code, name, name_ar, description, description_ar, guidance, guidance_ar, sort_order, path, depth, is_active, is_assessable, weight, max_score, metadata_json, created_at, updated_at, maturity_level, evidence_type, acceptance_criteria, acceptance_criteria_en, spec_references, priority, assessment_type) VALUES ('727a258b-55ef-46c1-8754-052545659f5f', '23cdd151-eef3-499f-9db5-e46ae7f7e1f2', 'c2651b0f-9049-4a36-8ada-01315145fa6f', 'Specification', 'FOI.C.3.1', 'وثائق الإجراءات والعمليات المطورة والمعتمدة لطلبات حرية المعلومات', 'وثائق الإجراءات والعمليات المطورة والمعتمدة لطلبات حرية المعلومات', NULL, NULL, NULL, NULL, 1, '/56be3711-3885-42c9-9aac-d845e62c30fb/c2651b0f-9049-4a36-8ada-01315145fa6f/727a258b-55ef-46c1-8754-052545659f5f/', 2, true, true, 1.00, NULL, NULL, '2026-04-11 01:39:34.721889+00', '2026-04-11 01:57:41.671363+00', 2, 'وثائق الإجراءات والعمليات المطورة والمعتمدة لطلبات حرية المعلومات', 'يجب على الجهة إرفاق الإجراءات والعمليات المطورة والمعتمدة لطلبات حرية المعلومات، حيث يجب على الجهة أن تصمم وتوثّق عملية موحّدة لطلبات المعلومات، وأن تطور إجراءات لإدارة ومعالجة وتوثيق طلبات الوصول إلى المعلومات العامة (Public Information) وفقًا لسياسات / لوائح حرية المعلومات الصادرة عن مكتب إدارة البيانات الوطنية (NDMO).', NULL, 'FOI.3.1', 'P1', 'compliance');
