INSERT INTO public.framework_nodes (id, framework_id, parent_id, node_type, reference_code, name, name_ar, description, description_ar, guidance, guidance_ar, sort_order, path, depth, is_active, is_assessable, weight, max_score, metadata_json, created_at, updated_at, maturity_level, evidence_type, acceptance_criteria, acceptance_criteria_en, spec_references, priority, assessment_type) VALUES ('3e420105-8bdc-43c4-9b55-669b01068ae0', 'b2c124a4-92e9-4fae-bf22-ad5424209b6b', '38b373ec-939f-43f4-b861-ee1a210da06f', 'Requirement', 'S5.5.1.R1', '1) Prepare an analytical study of the current situation, identify training needs for digital transformation leaders, and needs for digital leadership and national specialized competencies in digital government fields.', '1) إعداد دراسة تحليلية للوضع الراهن، وتحديد الاحتياجات التدريبية لقيادات التحول الرقمى فى الجهة، والاحتياجات من الكفاءات القيادية الرقمية والكفاءات الوطنية المتخصصة فى مجالات أعمال الحكومة الرقمية.', NULL, NULL, NULL, NULL, 1, '/5530232e-d754-4d10-a280-2f2cc285340d/7f7a255b-80d9-4d28-b56b-89c6948acfd1/38b373ec-939f-43f4-b861-ee1a210da06f/3e420105-8bdc-43c4-9b55-669b01068ae0/', 3, true, true, 1.00, NULL, NULL, '2026-04-11 04:22:30.182167+00', '2026-04-11 04:28:56.77092+00', NULL, NULL, '1) إرفاق الدراسة التحليلية للوضع الراهن وفق متطلبات تطبيق هذا المعيار.', '1) Attach the current situation analytical study per this standard''s requirements.', NULL, NULL, NULL);
INSERT INTO public.framework_nodes (id, framework_id, parent_id, node_type, reference_code, name, name_ar, description, description_ar, guidance, guidance_ar, sort_order, path, depth, is_active, is_assessable, weight, max_score, metadata_json, created_at, updated_at, maturity_level, evidence_type, acceptance_criteria, acceptance_criteria_en, spec_references, priority, assessment_type) VALUES ('aabdb6c6-2a2f-4d44-bc92-0732b4acd21d', 'b2c124a4-92e9-4fae-bf22-ad5424209b6b', '7364454e-53cc-49ec-b94f-bc1660344e8b', 'Requirement', 'S5.11.4.R1', '1) Use beneficiary relationship management systems with all components and activate contact centers and technical support to ensure rapid response to beneficiary requirements, complaints, and suggestions and raise satisfaction levels.', '1) استخدام نظم إدارة العلاقة مع المستفيدين بجميع مكوناتها وتفعيل مراكز الاتصال والدعم الفني، بما يضمن رفع مستوى الاستجابة السريعة لمتطلبات وشكاوى ومقترحات المستفيدين باختلاف شرائحهم، ورفع مستوى الرضا لديهم.', NULL, NULL, NULL, NULL, 1, '/eaa87d00-46fc-440d-b0af-6fb89269407c/b697414a-0b0d-41c6-8c15-d0353044012f/7364454e-53cc-49ec-b94f-bc1660344e8b/aabdb6c6-2a2f-4d44-bc92-0732b4acd21d/', 3, true, true, 1.00, NULL, NULL, '2026-04-11 04:22:31.741642+00', '2026-04-11 04:28:57.925067+00', NULL, NULL, '1) إرفاق (3) عينات حديثة من شاشات نظم إدارة العلاقة مع المستفيدين.', '1) Attach (3) recent screenshots from beneficiary relationship management systems.', NULL, NULL, NULL);
INSERT INTO public.framework_nodes (id, framework_id, parent_id, node_type, reference_code, name, name_ar, description, description_ar, guidance, guidance_ar, sort_order, path, depth, is_active, is_assessable, weight, max_score, metadata_json, created_at, updated_at, maturity_level, evidence_type, acceptance_criteria, acceptance_criteria_en, spec_references, priority, assessment_type) VALUES ('9e6019a6-9eac-4ef4-b27c-1fc1cbaa918f', 'b2c124a4-92e9-4fae-bf22-ad5424209b6b', '86ffa3c4-1298-4f30-a0e4-a912c9846c9a', 'Requirement', 'S5.10.7.R1', '1) Review the BCMS periodically (at least annually) through a qualified internal or external auditor.', '1) مراجعة نظام إدارة استمرارية الأعمال بشكل دوري (سنوياً على الأقل) عبر مدقق داخلي أو خارجي يمتلك المؤهلات والخبرات الكافية.', NULL, NULL, NULL, NULL, 1, '/1da7ecaf-95c5-4402-aa7b-f34786019aa6/1f95de6d-8d99-409f-bf82-49fde52aa796/86ffa3c4-1298-4f30-a0e4-a912c9846c9a/9e6019a6-9eac-4ef4-b27c-1fc1cbaa918f/', 3, true, true, 1.00, NULL, NULL, '2026-04-11 04:22:31.550405+00', '2026-04-11 04:28:57.781234+00', NULL, NULL, '1) إرفاق تقرير يوضح نتائج مراجعة إدارة استمرارية الأعمال.', '1) Attach a report showing business continuity management review results.', NULL, NULL, NULL);
INSERT INTO public.framework_nodes (id, framework_id, parent_id, node_type, reference_code, name, name_ar, description, description_ar, guidance, guidance_ar, sort_order, path, depth, is_active, is_assessable, weight, max_score, metadata_json, created_at, updated_at, maturity_level, evidence_type, acceptance_criteria, acceptance_criteria_en, spec_references, priority, assessment_type) VALUES ('f04527ae-b443-4a0e-86d8-80218e010c57', 'b2c124a4-92e9-4fae-bf22-ad5424209b6b', 'f196cc2e-42b9-4a42-9734-1f5ab2a8a0a3', 'Requirement', 'S5.5.3.R1', '1) Involve qualified digital transformation leaders in active committees and decision-making, leveraging their expertise in implementing strategic digital transformation initiatives.', '1) إشراك القادة المؤهلين فى مجال التحول الرقمى فى اللجان الفاعلة فى عملية التحول الرقمى وعمليات صنع القرار، والاستفادة من خبراتهم ومؤهلاتهم فى تنفيذ المبادرات الإستراتيجية فى التحول الرقمى.', NULL, NULL, NULL, NULL, 1, '/5530232e-d754-4d10-a280-2f2cc285340d/7f7a255b-80d9-4d28-b56b-89c6948acfd1/f196cc2e-42b9-4a42-9734-1f5ab2a8a0a3/f04527ae-b443-4a0e-86d8-80218e010c57/', 3, true, true, 1.00, NULL, NULL, '2026-04-11 04:22:30.238838+00', '2026-04-11 04:28:56.814108+00', NULL, NULL, '1) إرفاق عينات حديثة من قرارات تكوين اللجان الفاعلة فى عملية التحول الرقمى مع تحديد أسماء الأعضاء من القادة المؤهلين والمشاركين فى دعم التحول الرقمى.', '1) Attach recent samples of committee formation decisions identifying qualified leader members participating in digital transformation.', NULL, NULL, NULL);
INSERT INTO public.framework_nodes (id, framework_id, parent_id, node_type, reference_code, name, name_ar, description, description_ar, guidance, guidance_ar, sort_order, path, depth, is_active, is_assessable, weight, max_score, metadata_json, created_at, updated_at, maturity_level, evidence_type, acceptance_criteria, acceptance_criteria_en, spec_references, priority, assessment_type) VALUES ('623bd484-764f-4b54-ae21-8eb78cdbcd8e', 'b2c124a4-92e9-4fae-bf22-ad5424209b6b', '0d64734f-eef0-44b7-bf59-a75e010d533e', 'Requirement', 'S5.8.1.R1', '1) Link all existing digital circuits added in the digital circuits inventory service with purchase order numbers from the framework agreement via the ''Etimad'' electronic market.', '1) ربط جميع الدوائر الرقمية القائمة لدى الجهة والمضافة فى خدمة حصر الدوائر الرقمية بأرقام أوامر الشراء التى تمت من الاتفاقية الإطارية لخدمات الإنترنت والدوائر الرقمية عن طريق السوق الإلكترونى لمنصة "اعتماد".', NULL, NULL, NULL, NULL, 1, '/67c04d75-3ce8-4615-9784-464e399ce0cb/3059ba0d-feee-46b8-9640-bf112a65f1d6/0d64734f-eef0-44b7-bf59-a75e010d533e/623bd484-764f-4b54-ae21-8eb78cdbcd8e/', 3, true, true, 1.00, NULL, NULL, '2026-04-11 04:22:30.562583+00', '2026-04-11 04:28:56.978223+00', NULL, NULL, '1) لايتطلب إرفاق مستند إئبات، وسيتم التحقق من خلال منصة "رقمى".', '1) No proof document required. Verification through the ''Raqmi'' platform.', NULL, NULL, NULL);
INSERT INTO public.framework_nodes (id, framework_id, parent_id, node_type, reference_code, name, name_ar, description, description_ar, guidance, guidance_ar, sort_order, path, depth, is_active, is_assessable, weight, max_score, metadata_json, created_at, updated_at, maturity_level, evidence_type, acceptance_criteria, acceptance_criteria_en, spec_references, priority, assessment_type) VALUES ('e70cbff6-930a-4ddf-9dbf-921a20fe324c', 'b2c124a4-92e9-4fae-bf22-ad5424209b6b', '23149bbf-e7ac-44b5-b28c-c5a6c92d121c', 'Requirement', 'S5.18.1.R1', '1) Inventory necessary and appropriate electronic channels for beneficiaries to share opinions, observations, and suggestions about services, including social media channels and official application.', '1) حصر القنوات الإلكترونية اللازمة والملائمة للمستفيدين، التي تمكنهم من مشاركة آرائهم وملحوظاتهم ومقترحاتهم حول الخدمات المقدمة؛ بما يشمل عرض قنوات التواصل الاجتماعي والتطبيق الرسمي.', NULL, NULL, NULL, NULL, 1, '/f8a69d5b-caeb-4dbd-b746-b483f0570fb4/12905427-3213-4f5f-8f08-94db72538b17/23149bbf-e7ac-44b5-b28c-c5a6c92d121c/e70cbff6-930a-4ddf-9dbf-921a20fe324c/', 3, true, true, 1.00, NULL, NULL, '2026-04-11 04:22:33.241327+00', '2026-04-11 04:28:59.124922+00', NULL, NULL, '1) إرفاق وثيقة حديثة لجميع القنوات التي أتاحتها الجهة لمشاركة المستفيدين، وفق متطلبات تطبيق هذا المعيار.', '1) Attach a recent document listing all channels made available for beneficiary participation per this standard''s requirements.', NULL, NULL, NULL);
INSERT INTO public.framework_nodes (id, framework_id, parent_id, node_type, reference_code, name, name_ar, description, description_ar, guidance, guidance_ar, sort_order, path, depth, is_active, is_assessable, weight, max_score, metadata_json, created_at, updated_at, maturity_level, evidence_type, acceptance_criteria, acceptance_criteria_en, spec_references, priority, assessment_type) VALUES ('9cd70062-2573-4059-a888-ac807f2b1ca1', 'b2c124a4-92e9-4fae-bf22-ad5424209b6b', 'f6156b29-9ce5-403b-84cf-78b6ae3a50a4', 'Requirement', 'S5.8.3.R1', '1) The government entity''s use of the unified framework agreement item number (339000113).', '1) استخدام الجهة الحكومية البند الخاص بالاتفاقية الإطارية الموحد رقم (339000113).', NULL, NULL, NULL, NULL, 1, '/67c04d75-3ce8-4615-9784-464e399ce0cb/3059ba0d-feee-46b8-9640-bf112a65f1d6/f6156b29-9ce5-403b-84cf-78b6ae3a50a4/9cd70062-2573-4059-a888-ac807f2b1ca1/', 3, true, true, 1.00, NULL, NULL, '2026-04-11 04:22:30.646984+00', '2026-04-11 04:28:57.047185+00', NULL, NULL, '1) إرفاق صورة من السوق الإلكترونى لمنصة "اعتماد" توضح الرقم المرجعى لأمر الشراء وحالته؛ حيث يجب أن تكون إحدى الحالات الآتية: (تم إكمال الطلب أو بانتظار التوريد أو بانتظار دفع الرسوم).', '1) Attach a screenshot from ''Etimad'' electronic market showing purchase order reference number and status: (order completed, awaiting delivery, or awaiting fee payment).', NULL, NULL, NULL);
INSERT INTO public.framework_nodes (id, framework_id, parent_id, node_type, reference_code, name, name_ar, description, description_ar, guidance, guidance_ar, sort_order, path, depth, is_active, is_assessable, weight, max_score, metadata_json, created_at, updated_at, maturity_level, evidence_type, acceptance_criteria, acceptance_criteria_en, spec_references, priority, assessment_type) VALUES ('3a846887-3520-40dc-86d3-90414ba67c28', 'b2c124a4-92e9-4fae-bf22-ad5424209b6b', 'd4c8db44-5997-4faa-bcc0-f1b48ea6e72f', 'Requirement', 'S5.6.3.R1', '1) Sign MOUs or cooperation agreements with other government entities for integration in capacity building programs.', '1) توقيع مذكرات تفاهم أو اتفاقيات تعاون مع جهات حكومية أخرى، لتحقيق التكامل فى إنجاز الجهة لبرامج بناء الكفاءات.', NULL, NULL, NULL, NULL, 1, '/5530232e-d754-4d10-a280-2f2cc285340d/081d6452-1478-495c-bc55-178a5b83dd3e/d4c8db44-5997-4faa-bcc0-f1b48ea6e72f/3a846887-3520-40dc-86d3-90414ba67c28/', 3, true, true, 1.00, NULL, NULL, '2026-04-11 04:22:30.367016+00', '2026-04-11 04:28:56.891691+00', NULL, NULL, '1) إرفاق عينات من مذكرات التفاهم أو اتفاقيات التعاون القائمة مع جهات حكومية أخرى؛ لتحقيق التكامل في إنجاز الجهة لبرامج بناء الكفاءات.', '1) Attach samples of existing MOUs or cooperation agreements with other entities for capacity building integration.', NULL, NULL, NULL);
