INSERT INTO public.framework_nodes (id, framework_id, parent_id, node_type, reference_code, name, name_ar, description, description_ar, guidance, guidance_ar, sort_order, path, depth, is_active, is_assessable, weight, max_score, metadata_json, created_at, updated_at, maturity_level, evidence_type, acceptance_criteria, acceptance_criteria_en, spec_references, priority, assessment_type) VALUES ('4963a558-cb55-4965-bcea-c9f82023f7d0', 'b2c124a4-92e9-4fae-bf22-ad5424209b6b', '53eb7d16-32e3-48ac-9ab4-ecc9b75405e4', 'Requirement', 'S5.11.2.R1', '1) Use digital systems and tools for project management and digitize project request, planning, control, and monitoring of projects, tasks, and timelines.', '1) استخدام الجهة للأنظمة والأدوات الرقمية الخاصة بإدارة المشاريع ورقمنة عمليات طلب وتخطيط وضبط ومتابعة المشاريع والمهام والجداول الزمنية.', NULL, NULL, NULL, NULL, 1, '/eaa87d00-46fc-440d-b0af-6fb89269407c/b697414a-0b0d-41c6-8c15-d0353044012f/53eb7d16-32e3-48ac-9ab4-ecc9b75405e4/4963a558-cb55-4965-bcea-c9f82023f7d0/', 3, true, true, 1.00, NULL, NULL, '2026-04-11 04:22:31.647677+00', '2026-04-11 04:28:57.844345+00', NULL, NULL, '1) إرفاق (4) عينات حديثة من شاشات النظم الرقمية الخاصة بإدارة المشاريع (طلب مشروع، التخطيط، والمتابعة والتقارير، والتسليمات)، وفق متطلبات تطبيق هذا المعيار.', '1) Attach (4) recent screenshots from digital project management systems (request, planning, monitoring/reporting, deliverables) per this standard''s requirements.', NULL, NULL, NULL);
INSERT INTO public.framework_nodes (id, framework_id, parent_id, node_type, reference_code, name, name_ar, description, description_ar, guidance, guidance_ar, sort_order, path, depth, is_active, is_assessable, weight, max_score, metadata_json, created_at, updated_at, maturity_level, evidence_type, acceptance_criteria, acceptance_criteria_en, spec_references, priority, assessment_type) VALUES ('d5b21774-b693-4223-91ea-e42a4b4258e9', 'b2c124a4-92e9-4fae-bf22-ad5424209b6b', 'da98520f-520d-4178-ac54-ab0f181c8afb', 'Requirement', 'S5.20.2.R1', '1) The entity has a vision for measuring and improving beneficiary experience covering all beneficiaries, services, and procedures.', '1) وجود رؤية لدى الجهة لقياس وتحسين تجربة المستفيد بحيث تشمل جميع المستفيدين، والخدمات، واإلجراءات.', NULL, NULL, NULL, NULL, 1, '/f8a69d5b-caeb-4dbd-b746-b483f0570fb4/355108bd-50ab-461c-81a7-0169b4c985f0/da98520f-520d-4178-ac54-ab0f181c8afb/d5b21774-b693-4223-91ea-e42a4b4258e9/', 3, true, true, 1.00, NULL, NULL, '2026-04-11 04:22:33.623541+00', '2026-04-11 04:28:59.353636+00', NULL, NULL, '1) إرفاق وثيقة معتمدة تحدد رؤية الجهة لتجربة المستفيد وفق متطلبات تطبيق هذا المعيار.', '1) Attach an approved document defining the entity''s beneficiary experience vision per this standard''s requirements.', NULL, NULL, NULL);
INSERT INTO public.framework_nodes (id, framework_id, parent_id, node_type, reference_code, name, name_ar, description, description_ar, guidance, guidance_ar, sort_order, path, depth, is_active, is_assessable, weight, max_score, metadata_json, created_at, updated_at, maturity_level, evidence_type, acceptance_criteria, acceptance_criteria_en, spec_references, priority, assessment_type) VALUES ('6ec9bbc7-1064-4856-9f9e-1aba9d465438', 'b2c124a4-92e9-4fae-bf22-ad5424209b6b', 'd0e54444-6bd5-49c6-bfc5-ca6e0c3e2740', 'Requirement', 'S5.15.2.R1', '1) Prepare an implementation plan to unify and merge sector platforms into a unified sectoral platform, showing platforms to be merged, services to be transferred, and merger completion date.', '1) إعداد خطة تنفيذية لتوحيد ودمج المنصات الخاصة بالقطاع ضمن منصة قطاعية موحدة، التي توضح قائمة المنصات التي ستُدمَج والخدمات التي ستُنقَل مع توضيح تاريخ اكتمال أعمال الدمج.', NULL, NULL, NULL, NULL, 1, '/d2a77bfc-3828-4697-8f64-c837e89ff585/ab80a93b-c219-43bb-aaea-5700eee62ef2/d0e54444-6bd5-49c6-bfc5-ca6e0c3e2740/6ec9bbc7-1064-4856-9f9e-1aba9d465438/', 3, true, true, 1.00, NULL, NULL, '2026-04-11 04:22:32.698049+00', '2026-04-11 04:28:58.630389+00', NULL, NULL, '1) إرفاق الخطة التنفيذية لتوحيد ودمج المنصات الخاصة بالقطاع والمعتمدة من قبل هيئة الحكومة الرقمية.', '1) Attach the implementation plan for unifying and merging sector platforms, approved by the Digital Government Authority.', NULL, NULL, NULL);
