INSERT INTO public.framework_nodes (id, framework_id, parent_id, node_type, reference_code, name, name_ar, description, description_ar, guidance, guidance_ar, sort_order, path, depth, is_active, is_assessable, weight, max_score, metadata_json, created_at, updated_at, maturity_level, evidence_type, acceptance_criteria, acceptance_criteria_en, spec_references, priority, assessment_type) VALUES ('392c2d45-a46b-45df-af6d-3e35cd2a2789', 'b2c124a4-92e9-4fae-bf22-ad5424209b6b', '5e843b48-5d94-44a0-893d-a8f8032457d4', 'Requirement', 'S5.2.3.R1', '1) Agree on a joint governance mechanism for digital transformation initiatives, shared products, and projects between entities, clarifying target entities, cooperation type, objectives, and timeline.', '1) الاتفاق على آلية مشتركة لحوكمة مبادرات ومشاريع التحول الرقمي والمنتجات المشتركة بين الجهات الحكومية، بحيث توضح آلية الجهات المستهدفة، ونوع التعاون المطلوب وأهدافه، والجدول الزمني لمراحل التنفيذ.', NULL, NULL, NULL, NULL, 1, '/633ea9b9-b470-4be6-94c9-362bfd768aba/b7320dd0-fc03-4ffc-a2e1-8c624b165952/5e843b48-5d94-44a0-893d-a8f8032457d4/392c2d45-a46b-45df-af6d-3e35cd2a2789/', 3, true, true, 1.00, NULL, NULL, '2026-04-11 04:22:29.711042+00', '2026-04-11 04:28:56.413213+00', NULL, NULL, 'إرفاق وثيقة آلية الحوكمة المشتركة، وفق متطلبات تطبيق هذا المعيار.', 'Attach the joint governance mechanism document per this standard''s requirements.', NULL, NULL, NULL);
INSERT INTO public.framework_nodes (id, framework_id, parent_id, node_type, reference_code, name, name_ar, description, description_ar, guidance, guidance_ar, sort_order, path, depth, is_active, is_assessable, weight, max_score, metadata_json, created_at, updated_at, maturity_level, evidence_type, acceptance_criteria, acceptance_criteria_en, spec_references, priority, assessment_type) VALUES ('6dcb71f8-b219-4239-8154-4d8e5639ebb2', 'b2c124a4-92e9-4fae-bf22-ad5424209b6b', 'e09199c7-f656-4ca3-b4f9-b7aeb01f43d2', 'Requirement', 'S5.6.2.R1', '1) Issue periodic monitoring reports for capacity building plan implementation in digital transformation by the e-Government/Digital Transformation Committee, including: a. Detailed list of executed programs. b. Certificate samples.', '1) إصدار تقارير المتابعة الدورية لتنفيذ خطة بناء الكفاءات فى مجال التحول الرقمى من قِبل لجنة
INSERT INTO public.framework_nodes (id, framework_id, parent_id, node_type, reference_code, name, name_ar, description, description_ar, guidance, guidance_ar, sort_order, path, depth, is_active, is_assessable, weight, max_score, metadata_json, created_at, updated_at, maturity_level, evidence_type, acceptance_criteria, acceptance_criteria_en, spec_references, priority, assessment_type) VALUES ('f9c6f76a-14fc-49ba-826b-c35800fa388b', 'b2c124a4-92e9-4fae-bf22-ad5424209b6b', 'a4cfa6f9-5f2d-41bb-a8f1-11a751df6ac6', 'Requirement', 'S5.3.1.R1', '1) Establish an organizational unit within the entity''s structure to manage, develop, and oversee enterprise architecture practices.', '1) تأسيس وحدة تنظيمية ضمن الهيكل التنظيمي للجهة على أن تتولى مهام ومسؤوليات الإدارة والتطوير والإشراف على أعمال وممارسات البنية المؤسسية.', NULL, NULL, NULL, NULL, 1, '/633ea9b9-b470-4be6-94c9-362bfd768aba/4fe1ba35-8844-4f32-9cb5-7cd7255464bd/a4cfa6f9-5f2d-41bb-a8f1-11a751df6ac6/f9c6f76a-14fc-49ba-826b-c35800fa388b/', 3, true, true, 1.00, NULL, NULL, '2026-04-11 04:22:29.7712+00', '2026-04-11 04:28:56.454151+00', NULL, NULL, 'وثيقة معتمدة تثبت تأسيس وحدة تنظيمية خاصة بالبنية المؤسسية، أو الهيكل التنظيمي المعتمد للجهة الذي يوضح تأسيس الوحدة التنظيمية.', 'An approved document proving establishment of an enterprise architecture organizational unit, or the approved organizational structure showing the unit.', NULL, NULL, NULL);
INSERT INTO public.framework_nodes (id, framework_id, parent_id, node_type, reference_code, name, name_ar, description, description_ar, guidance, guidance_ar, sort_order, path, depth, is_active, is_assessable, weight, max_score, metadata_json, created_at, updated_at, maturity_level, evidence_type, acceptance_criteria, acceptance_criteria_en, spec_references, priority, assessment_type) VALUES ('61c2d7ea-b434-4274-8a3f-f38a1a76ded7', 'b2c124a4-92e9-4fae-bf22-ad5424209b6b', '7504c7bb-ab66-4cd3-996d-7e48886981cc', 'Requirement', 'S5.17.2.R1', '1) Launch non-automated government services registered through ''Raqmi'' platform per target dates, with all services launched no later than 2026/12/31.', '1) إطلاق الخدمات الحكومية غير المؤتمتة المسجلة من خلال منصة "رقمى" (خدمة تسجيل الخدمات غير المؤتمتة) وفق التواريخ المستهدفة، مع تأكيد الإطلاق من خلال المنصة، على ألا يتجاوز موعد إطلاق جميع الخدمات تاريخ 2026/12/31م.', NULL, NULL, NULL, NULL, 1, '/66dd45a8-6ec9-4d82-9d56-a83c75b23a47/fbd949a4-48e1-44f2-851a-3243efed765b/7504c7bb-ab66-4cd3-996d-7e48886981cc/61c2d7ea-b434-4274-8a3f-f38a1a76ded7/', 3, true, true, 1.00, NULL, NULL, '2026-04-11 04:22:33.018115+00', '2026-04-11 04:28:58.951082+00', NULL, NULL, '1) لا يتطلب إرفاق مستند إثبات، وسيتم التحقق من إطلاق الخدمات الحكومية غير المؤتمتة من خلال منصة "رقمي".', '1) No proof document required. Verification of non-automated government service launch through ''Raqmi'' platform.', NULL, NULL, NULL);
