INSERT INTO public.framework_nodes (id, framework_id, parent_id, node_type, reference_code, name, name_ar, description, description_ar, guidance, guidance_ar, sort_order, path, depth, is_active, is_assessable, weight, max_score, metadata_json, created_at, updated_at, maturity_level, evidence_type, acceptance_criteria, acceptance_criteria_en, spec_references, priority, assessment_type) VALUES ('ca805318-4355-4c5f-9f6f-8854563e4f0d', 'b2c124a4-92e9-4fae-bf22-ad5424209b6b', '575d5b05-7d8f-47d4-a103-61b223ccc111', 'Requirement', 'S5.4.3.R1', '1) Provide a mechanism to fulfill staff requests for software or licenses supporting digital tools used in daily work.', '1) توفير آلية لتلبية طلبات المنسوبين لأي برمجيات أو رخص داعمة للأدوات الرقمية التي يستخدمها منسوبو الجهة في أعمالهم اليومية.', NULL, NULL, NULL, NULL, 1, '/5530232e-d754-4d10-a280-2f2cc285340d/56b7daaf-c5b7-4054-9c1c-ba55a211577c/575d5b05-7d8f-47d4-a103-61b223ccc111/ca805318-4355-4c5f-9f6f-8854563e4f0d/', 3, true, true, 1.00, NULL, NULL, '2026-04-11 04:22:30.14642+00', '2026-04-11 04:28:56.74712+00', NULL, NULL, 'إرفاق آلية لتلبية طلبات المنسوبين لأي برمجيات أو رخص داعمة للأدوات الرقمية، وصور من الشاشات التي تثبت تطبيق هذه الآلية وفق متطلبات تطبيق هذا المعيار.', 'Attach a mechanism for fulfilling staff software/license requests, and screenshots proving its application per this standard''s requirements.', NULL, NULL, NULL);
INSERT INTO public.framework_nodes (id, framework_id, parent_id, node_type, reference_code, name, name_ar, description, description_ar, guidance, guidance_ar, sort_order, path, depth, is_active, is_assessable, weight, max_score, metadata_json, created_at, updated_at, maturity_level, evidence_type, acceptance_criteria, acceptance_criteria_en, spec_references, priority, assessment_type) VALUES ('17a3bcd3-945f-4a4a-ad04-2db527b4a287', 'b2c124a4-92e9-4fae-bf22-ad5424209b6b', 'e3c11773-df7c-40aa-a884-187f820bd5cb', 'Requirement', 'S5.3.3.R1', '1) Develop an enabling policy for adopting and governing enterprise architecture practice, covering: a. EA practice governance. b. EA requirements management. c. EA output adoption. d. Initiative and project compliance with EA principles.', '1) تطوير سياسة ممكِّنة لتبني وحوكمة ممارسة البنية المؤسسية، مع مراعاة شموليتها ووضوح صياغتها وطريقة عرضها على أن تتضمن المواضيع الآتية: أ. حوكمة ممارسة البنية المؤسسية، ب. إدارة متطلبات البنية المؤسسية، ت. تبني مخرجات البنية المؤسسية، ث. امتثال المبادرات والمشاريع لمبادئ البنية المؤسسية.', NULL, NULL, NULL, NULL, 1, '/633ea9b9-b470-4be6-94c9-362bfd768aba/4fe1ba35-8844-4f32-9cb5-7cd7255464bd/e3c11773-df7c-40aa-a884-187f820bd5cb/17a3bcd3-945f-4a4a-ad04-2db527b4a287/', 3, true, true, 1.00, NULL, NULL, '2026-04-11 04:22:29.943898+00', '2026-04-11 04:28:56.601005+00', NULL, NULL, 'سياسة تبني وحوكمة ممارسة البنية المؤسسية وفق متطلبات تطبيق هذا المعيار.', 'Enterprise architecture adoption and governance policy per this standard''s requirements.', NULL, NULL, NULL);
INSERT INTO public.framework_nodes (id, framework_id, parent_id, node_type, reference_code, name, name_ar, description, description_ar, guidance, guidance_ar, sort_order, path, depth, is_active, is_assessable, weight, max_score, metadata_json, created_at, updated_at, maturity_level, evidence_type, acceptance_criteria, acceptance_criteria_en, spec_references, priority, assessment_type) VALUES ('bb041dc8-e787-4717-af80-bbb44804f77c', 'b2c124a4-92e9-4fae-bf22-ad5424209b6b', '39044ed9-4bd0-4e46-883a-a390175e75dc', 'Requirement', 'S5.11.1.R1', '1) Implement core government resource planning systems and issue user guides.', '1) تطبيق الأنظمة الرئيسية لتخطيط الموارد الحكومية وإصدار أدلة المستخدمين.', NULL, NULL, NULL, NULL, 1, '/eaa87d00-46fc-440d-b0af-6fb89269407c/b697414a-0b0d-41c6-8c15-d0353044012f/39044ed9-4bd0-4e46-883a-a390175e75dc/bb041dc8-e787-4717-af80-bbb44804f77c/', 3, true, true, 1.00, NULL, NULL, '2026-04-11 04:22:31.604458+00', '2026-04-11 04:28:57.807487+00', NULL, NULL, '1) إرفاق عينة واحدة حديثة من الشاشات وأدلة المستخدمين لكل جزء من نظم إدارة الموارد (نظام إدارة الموارد البشرية، والنظام المالي، ونظام التوريد والمشتريات، ونظام إدارة العهد والمخزون، ونظام إدارة الموردين).', '1) Attach one recent sample of screenshots and user guides for each resource management system component (HR, financial, procurement, inventory, vendor management).', NULL, NULL, NULL);
