INSERT INTO public.framework_nodes (id, framework_id, parent_id, node_type, reference_code, name, name_ar, description, description_ar, guidance, guidance_ar, sort_order, path, depth, is_active, is_assessable, weight, max_score, metadata_json, created_at, updated_at, maturity_level, evidence_type, acceptance_criteria, acceptance_criteria_en, spec_references, priority, assessment_type) VALUES ('64015753-6bd5-42f5-a6c6-da04bead21c0', 'b2c124a4-92e9-4fae-bf22-ad5424209b6b', 'd709cc23-79d4-4cf4-9f74-e4f339a0ae9e', 'Standard', 'S5.24.1', 'Inventorying and Developing Innovative Solutions', 'حصر وتطوير الحلول الابتكارية وتطبيقها', NULL, NULL, NULL, NULL, 1, '/e7c18638-4285-416e-8b87-c4bfcad9b4e9/d709cc23-79d4-4cf4-9f74-e4f339a0ae9e/64015753-6bd5-42f5-a6c6-da04bead21c0/', 2, true, false, NULL, NULL, NULL, '2026-04-11 04:22:34.115244+00', '2026-04-11 04:22:34.115247+00', NULL, NULL, NULL, NULL, NULL, NULL, NULL);
INSERT INTO public.framework_nodes (id, framework_id, parent_id, node_type, reference_code, name, name_ar, description, description_ar, guidance, guidance_ar, sort_order, path, depth, is_active, is_assessable, weight, max_score, metadata_json, created_at, updated_at, maturity_level, evidence_type, acceptance_criteria, acceptance_criteria_en, spec_references, priority, assessment_type) VALUES ('d73f04d6-eef3-4798-8726-1d935bc9e484', 'b2c124a4-92e9-4fae-bf22-ad5424209b6b', '7ff72693-b04e-4b0f-ba28-7b9ddb3b0f0f', 'Requirement', 'S5.22.1.10.R1', '4) Publish links to websites of related national/local government institutions/agencies.', '4)  نشر روابط للمواقع الخاصة بأي مؤسسات/ وكالات حكومية وطنية/ محلية ذات العلاقة بعمل الجهة.', NULL, NULL, NULL, NULL, 1, '/15002e5b-4821-4f20-8a53-6bf748d7376a/9ea5d084-0cb7-43ea-a040-7f51af94fc8e/7ff72693-b04e-4b0f-ba28-7b9ddb3b0f0f/d73f04d6-eef3-4798-8726-1d935bc9e484/', 3, true, true, 1.00, NULL, NULL, '2026-04-11 04:22:33.946521+00', '2026-04-11 04:22:33.946525+00', NULL, NULL, 'لا يتطلب إرفاق مستند إثبات، ويتم متابعة التزام الجهات الحكومية مباشرةً من قِبَل هيئة الحكومية الرقمية حسب التقارير الدورية التي تصدرها الهيئة وبما يتواءم مع "ضوابط تطوير جودة المحتوى الرقمي للمواقع والمنصات الحكومية الرقمية لتحسين ظهورها على محركات البحث".', 'No proof document required. Compliance monitored directly by the Digital Government Authority per periodic reports aligned with ''Digital Content Quality Standards''.', NULL, NULL, NULL);
INSERT INTO public.framework_nodes (id, framework_id, parent_id, node_type, reference_code, name, name_ar, description, description_ar, guidance, guidance_ar, sort_order, path, depth, is_active, is_assessable, weight, max_score, metadata_json, created_at, updated_at, maturity_level, evidence_type, acceptance_criteria, acceptance_criteria_en, spec_references, priority, assessment_type) VALUES ('b1f4959e-c7f8-4435-9687-266badcee138', 'b2c124a4-92e9-4fae-bf22-ad5424209b6b', '5fa62909-d1ff-4c45-b45a-d8e7eba23937', 'Requirement', 'S5.15.1.R1', '1) Obtain prior approval from the Digital Government Authority before creating or launching external or internal platforms.', '1) حصول الجهة على موافقة مسبقة من هيئة الحكومة الرقمية قبل إنشاء أو إطلاق المنصات الخارجية أو الداخلية، سواء كانت بنطاق رئيسي أو فرعي.', NULL, NULL, NULL, NULL, 1, '/d2a77bfc-3828-4697-8f64-c837e89ff585/ab80a93b-c219-43bb-aaea-5700eee62ef2/5fa62909-d1ff-4c45-b45a-d8e7eba23937/b1f4959e-c7f8-4435-9687-266badcee138/', 3, true, true, 1.00, NULL, NULL, '2026-04-11 04:22:32.663929+00', '2026-04-11 04:28:58.604137+00', NULL, NULL, '1) لا يتطلب إرفاق مستند إثبات، وسيتم التحقق داخليًا من منصة "رقمي".', '1) No proof document required. Internal verification through the ''Raqmi'' platform.', NULL, NULL, NULL);
INSERT INTO public.framework_nodes (id, framework_id, parent_id, node_type, reference_code, name, name_ar, description, description_ar, guidance, guidance_ar, sort_order, path, depth, is_active, is_assessable, weight, max_score, metadata_json, created_at, updated_at, maturity_level, evidence_type, acceptance_criteria, acceptance_criteria_en, spec_references, priority, assessment_type) VALUES ('8676f622-9977-43eb-a02d-b9796c7f8106', 'b2c124a4-92e9-4fae-bf22-ad5424209b6b', '4382a8d0-baf0-4d7e-bc65-ce4fa874d8db', 'Requirement', 'S5.14.1.R1', '1) Study and analyze other government systems and services and periodically identify entity data and function needs.', '1) دراسة وتحليل الأنظمة والخدمات الحكومية الأخرى وتحديد احتياجات الجهة من البيانات والوظائف بشكل دوري.', NULL, NULL, NULL, NULL, 1, '/d2a77bfc-3828-4697-8f64-c837e89ff585/bb206aae-4d83-494b-bb48-2d4ae3111473/4382a8d0-baf0-4d7e-bc65-ce4fa874d8db/8676f622-9977-43eb-a02d-b9796c7f8106/', 3, true, true, 1.00, NULL, NULL, '2026-04-11 04:22:32.375151+00', '2026-04-11 04:28:58.3728+00', NULL, NULL, '1) إرفاق التقارير التي توضح دراسة وتحليل الأنظمة والخدمات الحكومية الأخرى وتحديد احتياجات الجهة من البيانات والوظائف بشکل دوری.', '1) Attach reports showing study and analysis of government systems and services and identification of entity needs.', NULL, NULL, NULL);
INSERT INTO public.framework_nodes (id, framework_id, parent_id, node_type, reference_code, name, name_ar, description, description_ar, guidance, guidance_ar, sort_order, path, depth, is_active, is_assessable, weight, max_score, metadata_json, created_at, updated_at, maturity_level, evidence_type, acceptance_criteria, acceptance_criteria_en, spec_references, priority, assessment_type) VALUES ('38b373ec-939f-43f4-b861-ee1a210da06f', 'b2c124a4-92e9-4fae-bf22-ad5424209b6b', '7f7a255b-80d9-4d28-b56b-89c6948acfd1', 'Standard', 'S5.5.1', 'Planning for Digital Transformation Leadership Qualification', 'التخطيط لتأهيل قيادات التحول الرقمي', NULL, NULL, NULL, NULL, 1, '/5530232e-d754-4d10-a280-2f2cc285340d/7f7a255b-80d9-4d28-b56b-89c6948acfd1/38b373ec-939f-43f4-b861-ee1a210da06f/', 2, true, false, NULL, NULL, NULL, '2026-04-11 04:22:30.174145+00', '2026-04-11 04:22:30.174148+00', NULL, NULL, NULL, NULL, NULL, NULL, NULL);
INSERT INTO public.framework_nodes (id, framework_id, parent_id, node_type, reference_code, name, name_ar, description, description_ar, guidance, guidance_ar, sort_order, path, depth, is_active, is_assessable, weight, max_score, metadata_json, created_at, updated_at, maturity_level, evidence_type, acceptance_criteria, acceptance_criteria_en, spec_references, priority, assessment_type) VALUES ('94448972-f057-4c2c-976c-1454678501e3', 'b2c124a4-92e9-4fae-bf22-ad5424209b6b', 'db7550ef-4438-460a-aeaf-375a2ed69f8f', 'Requirement', 'S5.4.1.R1', '1) Prepare a study to determine staff awareness level of digital transformation and identify gaps at various entity levels.', '1) إعداد دراسة لتحديد مستوى وعي منسوبي الجهة بالتحول الرقمي ومدى أهميته، ومجالات التحول الرقمي، ثُم تحديد الفجوات في هذا الصدد على مختلف المستويات في الجهة.', NULL, NULL, NULL, NULL, 1, '/5530232e-d754-4d10-a280-2f2cc285340d/56b7daaf-c5b7-4054-9c1c-ba55a211577c/db7550ef-4438-460a-aeaf-375a2ed69f8f/94448972-f057-4c2c-976c-1454678501e3/', 3, true, true, 1.00, NULL, NULL, '2026-04-11 04:22:30.071182+00', '2026-04-11 04:28:56.691022+00', NULL, NULL, 'إرفاق دراسة حديثة لتحديد مستوى وعي منسوبي الجهة بالتحول الرقمي وفق متطلبات تطبيق هذا المعيار.', 'Attach a recent study determining staff awareness level of digital transformation per this standard''s requirements.', NULL, NULL, NULL);
INSERT INTO public.framework_nodes (id, framework_id, parent_id, node_type, reference_code, name, name_ar, description, description_ar, guidance, guidance_ar, sort_order, path, depth, is_active, is_assessable, weight, max_score, metadata_json, created_at, updated_at, maturity_level, evidence_type, acceptance_criteria, acceptance_criteria_en, spec_references, priority, assessment_type) VALUES ('07a74294-680f-40e8-a77c-910a091b0461', 'b2c124a4-92e9-4fae-bf22-ad5424209b6b', '3ddf8460-7386-4131-ba66-a9e1e67fefeb', 'Requirement', 'S5.23.1.R1', '1) Attach the digital transformation strategy including research and innovation per this standard''s requirements.', '1) إرفاق إستراتيجية التحول الرقمي بحيث تتضمن البحث والابتكار وفق متطلبات تطبيق هذا المعيار.', NULL, NULL, NULL, NULL, 1, '/e7c18638-4285-416e-8b87-c4bfcad9b4e9/032f1549-f9df-44d8-8c70-964c8590bbfb/3ddf8460-7386-4131-ba66-a9e1e67fefeb/07a74294-680f-40e8-a77c-910a091b0461/', 3, true, true, 1.00, NULL, NULL, '2026-04-11 04:22:33.98343+00', '2026-04-11 04:28:59.524188+00', NULL, NULL, 'والمنصات الحكومية الرقمية لتحسين ظهورها على محركات البحث".', 'and government digital platforms to improve their visibility on search engines.', NULL, NULL, NULL);
INSERT INTO public.framework_nodes (id, framework_id, parent_id, node_type, reference_code, name, name_ar, description, description_ar, guidance, guidance_ar, sort_order, path, depth, is_active, is_assessable, weight, max_score, metadata_json, created_at, updated_at, maturity_level, evidence_type, acceptance_criteria, acceptance_criteria_en, spec_references, priority, assessment_type) VALUES ('8e7f0a21-18a2-4133-9cf8-dcb9104ca2b4', 'b2c124a4-92e9-4fae-bf22-ad5424209b6b', 'fb83f1bc-41a2-43bf-9fd5-328ec405e600', 'Requirement', 'S5.13.3.R1', '1) Align entity policies and regulations with DGA and relevant entities'' cloud computing policies, controls, and regulations.', '1) مواءمة سياسات وتنظيمات الجهة مع السياسات والضوابط والتنظيمات الصادرة من هيئة الحكومة الرقمية والجهات ذات العلاقة بالحوسبة السحابية.', NULL, NULL, NULL, NULL, 1, '/eaa87d00-46fc-440d-b0af-6fb89269407c/3bbdd786-9e2b-4b93-a20b-cc6dd282e49c/fb83f1bc-41a2-43bf-9fd5-328ec405e600/8e7f0a21-18a2-4133-9cf8-dcb9104ca2b4/', 3, true, true, 1.00, NULL, NULL, '2026-04-11 04:22:32.307576+00', '2026-04-11 04:28:58.339312+00', NULL, NULL, '1) إرفاق ما يثبت التزام الجهة بمواءمة سياساتها وتنظيماتها مع السياسات والضوابط والتنظيمات الصادرة من هيئة الحكومة الرقمية والجهات ذات العلاقة بالحوسبة السحابية.', '1) Attach proof of entity commitment to aligning policies with DGA and relevant cloud computing regulations.', NULL, NULL, NULL);
