INSERT INTO public.framework_nodes (id, framework_id, parent_id, node_type, reference_code, name, name_ar, description, description_ar, guidance, guidance_ar, sort_order, path, depth, is_active, is_assessable, weight, max_score, metadata_json, created_at, updated_at, maturity_level, evidence_type, acceptance_criteria, acceptance_criteria_en, spec_references, priority, assessment_type) VALUES ('856d43c7-7614-4488-bf8d-68be021e9ea4', 'b2c124a4-92e9-4fae-bf22-ad5424209b6b', 'b34f422e-8b5f-4a0d-8d55-078e67245c3c', 'Requirement', 'S5.4.2.R1', '1) Implement awareness programs for staff on digital transformation importance, inform them of plans, initiatives, and progress through various channels, and conduct related activities and events.', '1) تنفيذ البرامج التوعوية لمنسوبي الجهة الحكومية بأهمية عمليات التحول الرقمي واطلاعهم على خطط ومبادرات التحول الرقمي ونسب إنجازها عبر مختلف القنوات، وإقامة الأنشطة والفعاليات اللازمة لذلك.', NULL, NULL, NULL, NULL, 1, '/5530232e-d754-4d10-a280-2f2cc285340d/56b7daaf-c5b7-4054-9c1c-ba55a211577c/b34f422e-8b5f-4a0d-8d55-078e67245c3c/856d43c7-7614-4488-bf8d-68be021e9ea4/', 3, true, true, 1.00, NULL, NULL, '2026-04-11 04:22:30.09806+00', '2026-04-11 04:28:56.710335+00', NULL, NULL, 'إرفاق التقارير والعينات الحديثة التي تثبت توعية منسوبي الجهة بأهمية التحول الرقمي حسب البرامج التوعوية المعتمدة، وفق متطلبات تطبيق هذا المعيار.', 'Attach recent reports and samples proving staff awareness of digital transformation per approved awareness programs and this standard''s requirements.', NULL, NULL, NULL);
INSERT INTO public.framework_nodes (id, framework_id, parent_id, node_type, reference_code, name, name_ar, description, description_ar, guidance, guidance_ar, sort_order, path, depth, is_active, is_assessable, weight, max_score, metadata_json, created_at, updated_at, maturity_level, evidence_type, acceptance_criteria, acceptance_criteria_en, spec_references, priority, assessment_type) VALUES ('c90b66e5-b686-4848-b95a-ce5eb28e1953', 'b2c124a4-92e9-4fae-bf22-ad5424209b6b', '1dd4303d-1460-41e8-8905-41f385cf804a', 'Requirement', 'S5.19.2.R1', '1) Implement approved marketing programs, campaigns, and activities to raise beneficiary awareness of entity digital services and access methods.', '1) تنفيذ البرامج والحمالت واألنشطة التسويقية المعتمدة، لرفع وعي المستفيدين بالخدمات الرقمية للجهة وطرق الحصول عليها عبر مختلف القنوات.', NULL, NULL, NULL, NULL, 1, '/f8a69d5b-caeb-4dbd-b746-b483f0570fb4/8a2b7c88-b8b5-45ab-aa1c-4f9fc2edc596/1dd4303d-1460-41e8-8905-41f385cf804a/c90b66e5-b686-4848-b95a-ce5eb28e1953/', 3, true, true, 1.00, NULL, NULL, '2026-04-11 04:22:33.515487+00', '2026-04-11 04:28:59.29491+00', NULL, NULL, '1) إرفاق التقارير الحديثة والصور الكافية التي تثبت أن الجهة قامت بتنفيذ البرامج المعتمدة، لتعزيز العالقة مع المستفيد بما يشمل جميع المنتجات والمنصات سواء لألفراد أو الجهات.', '1) Attach recent reports and sufficient images proving implementation of approved beneficiary relationship enhancement programs.', NULL, NULL, NULL);
INSERT INTO public.framework_nodes (id, framework_id, parent_id, node_type, reference_code, name, name_ar, description, description_ar, guidance, guidance_ar, sort_order, path, depth, is_active, is_assessable, weight, max_score, metadata_json, created_at, updated_at, maturity_level, evidence_type, acceptance_criteria, acceptance_criteria_en, spec_references, priority, assessment_type) VALUES ('2c1eb120-7fcd-4d3d-ae68-8050d22c3710', '33f661cb-69a0-4c9e-8c3c-94ab4ce40e17', '76ef0c7b-8ab5-47f6-ad2b-7ed0901a1af8', 'Report', 'CHD-86127e8a', 'Child 86127e8a', NULL, NULL, NULL, NULL, NULL, 1, '/76ef0c7b-8ab5-47f6-ad2b-7ed0901a1af8/2c1eb120-7fcd-4d3d-ae68-8050d22c3710/', 1, false, false, NULL, NULL, NULL, '2026-04-14 01:39:13.770606+00', '2026-04-14 01:39:13.781021+00', NULL, NULL, NULL, NULL, NULL, NULL, NULL);
INSERT INTO public.framework_nodes (id, framework_id, parent_id, node_type, reference_code, name, name_ar, description, description_ar, guidance, guidance_ar, sort_order, path, depth, is_active, is_assessable, weight, max_score, metadata_json, created_at, updated_at, maturity_level, evidence_type, acceptance_criteria, acceptance_criteria_en, spec_references, priority, assessment_type) VALUES ('159b568b-a147-4a5c-a89d-67ec9876389e', 'b2c124a4-92e9-4fae-bf22-ad5424209b6b', 'a9e14340-e494-47bc-99e5-649a061193aa', 'Requirement', 'S5.18.4.R1', '1) Leverage emerging technologies to analyze beneficiary requests through advanced interactive methods and support decision-making and service automation.', '1) توظيف التقنيات الناشئة فى تحليل طلبات المستفيدين بأساليب تفاعلية متطورة، وتوظيفها فى دعم اتخاذ القرار، وتنفيذ الخدمات آليًا بشكل كامل أو جزئي.', NULL, NULL, NULL, NULL, 1, '/f8a69d5b-caeb-4dbd-b746-b483f0570fb4/12905427-3213-4f5f-8f08-94db72538b17/a9e14340-e494-47bc-99e5-649a061193aa/159b568b-a147-4a5c-a89d-67ec9876389e/', 3, true, true, 1.00, NULL, NULL, '2026-04-11 04:22:33.404955+00', '2026-04-11 04:28:59.232538+00', NULL, NULL, '1) إرفاق ما يثبت توظيف التقنيات الناشئة فى تحليل طلبات المستفيدين بأساليب تفاعلية متطورة، وتنفيذ الخدمات آليًا بشكل كامل أو جزئى، وفق متطلبات تطبيق هذا المعيار.', '1) Attach proof of leveraging emerging technologies in analyzing beneficiary requests and automating services per this standard''s requirements.', NULL, NULL, NULL);
INSERT INTO public.framework_nodes (id, framework_id, parent_id, node_type, reference_code, name, name_ar, description, description_ar, guidance, guidance_ar, sort_order, path, depth, is_active, is_assessable, weight, max_score, metadata_json, created_at, updated_at, maturity_level, evidence_type, acceptance_criteria, acceptance_criteria_en, spec_references, priority, assessment_type) VALUES ('f036e4bf-5638-4145-9c30-4c9c78d2dd98', 'b2c124a4-92e9-4fae-bf22-ad5424209b6b', 'da142c6d-cbd6-4d2f-a890-4946532e3af3', 'Requirement', 'S5.8.2.R1', '1) Submit inventory of all communication circuits to DGA via digital circuits data entry service on ''Raqmi'' platform, updated for the current year.', '1) رفع حصر لجميع دوائر الاتصالات لهيئة الحكومة الرقمية وفقًا لخدمة إضافة بيانات الدوائر الرقمية على موقع الهيئة منصة "رقمى"، والتحديث عليها بما يتواءم مع السنة الحالية، وإضافة بياناتها التفصيلية المطلوبة كافة.', NULL, NULL, NULL, NULL, 1, '/67c04d75-3ce8-4615-9784-464e399ce0cb/3059ba0d-feee-46b8-9640-bf112a65f1d6/da142c6d-cbd6-4d2f-a890-4946532e3af3/f036e4bf-5638-4145-9c30-4c9c78d2dd98/', 3, true, true, 1.00, NULL, NULL, '2026-04-11 04:22:30.628897+00', '2026-04-11 04:28:57.039623+00', NULL, NULL, '1) لا يتطلب إرفاق مستند إثبات، وسيتم التحقق من خلال منصة "رقمى".', '1) No proof document required. Verification through the ''Raqmi'' platform.', NULL, NULL, NULL);
INSERT INTO public.framework_nodes (id, framework_id, parent_id, node_type, reference_code, name, name_ar, description, description_ar, guidance, guidance_ar, sort_order, path, depth, is_active, is_assessable, weight, max_score, metadata_json, created_at, updated_at, maturity_level, evidence_type, acceptance_criteria, acceptance_criteria_en, spec_references, priority, assessment_type) VALUES ('4d79173f-f5d8-4684-91aa-bc8198db1e23', 'b2c124a4-92e9-4fae-bf22-ad5424209b6b', '86d34608-0715-4bdd-82e0-3e8b3edd6d7a', 'Requirement', 'S5.7.1.R1', '1) Inventory all entity processes and procedures including at minimum: a. Name and description. b. Owning department. c. Classification (core, supporting, administrative). d. Importance level. e. Automation level (fully, partially, or non-automated).', '1) حصر جميع العمليات والإجراءات فى الجهة بحيث تشمل بحد أدنى ما يأتى:
INSERT INTO public.framework_nodes (id, framework_id, parent_id, node_type, reference_code, name, name_ar, description, description_ar, guidance, guidance_ar, sort_order, path, depth, is_active, is_assessable, weight, max_score, metadata_json, created_at, updated_at, maturity_level, evidence_type, acceptance_criteria, acceptance_criteria_en, spec_references, priority, assessment_type) VALUES ('9139c70e-1032-4897-b9b8-b90139656ccd', 'b2c124a4-92e9-4fae-bf22-ad5424209b6b', 'dd5619fa-e0b6-47bb-9424-dd3899ddf678', 'Requirement', 'S5.9.1.R1', '1) Establish an administrative unit responsible for the risk management system, appropriate to the approved organizational structure.', '1) إنشاء وحدة إدارية مسؤولة عن نظام إدارة المخاطر فى الجهة بما يتناسب مع الهيكل التنظيمي المعتمد.', NULL, NULL, NULL, NULL, 1, '/1da7ecaf-95c5-4402-aa7b-f34786019aa6/779584e2-ddb4-45cc-b4a5-e366b1d57e80/dd5619fa-e0b6-47bb-9424-dd3899ddf678/9139c70e-1032-4897-b9b8-b90139656ccd/', 3, true, true, 1.00, NULL, NULL, '2026-04-11 04:22:30.710738+00', '2026-04-11 04:28:57.07964+00', NULL, NULL, '1) إرفاق الهيكل التنظيمي المعتمد متضمنًا الوحدة الإدارية المسؤولة عن نظام إدارة المخاطر.', '1) Attach the approved organizational structure including the risk management administrative unit.', NULL, NULL, NULL);
INSERT INTO public.framework_nodes (id, framework_id, parent_id, node_type, reference_code, name, name_ar, description, description_ar, guidance, guidance_ar, sort_order, path, depth, is_active, is_assessable, weight, max_score, metadata_json, created_at, updated_at, maturity_level, evidence_type, acceptance_criteria, acceptance_criteria_en, spec_references, priority, assessment_type) VALUES ('91b33878-7636-4ccc-be85-8d15ccb2dfc8', 'b2c124a4-92e9-4fae-bf22-ad5424209b6b', '5b23e8e3-fbad-4cb0-9cb8-774f8f8f6540', 'Requirement', 'S5.9.2.R1', '1) Identify internal and external risks and threats at entity and unit levels through workshops with risk owners.', '1) تحديد المخاطر والتهديدات الداخلية والخارجية على مستوى الجهة والوحدات الإدارية عن طريق عقد ورش العمل مع ملاك المخاطر.', NULL, NULL, NULL, NULL, 1, '/1da7ecaf-95c5-4402-aa7b-f34786019aa6/779584e2-ddb4-45cc-b4a5-e366b1d57e80/5b23e8e3-fbad-4cb0-9cb8-774f8f8f6540/91b33878-7636-4ccc-be85-8d15ccb2dfc8/', 3, true, true, 1.00, NULL, NULL, '2026-04-11 04:22:30.85244+00', '2026-04-11 04:28:57.211769+00', NULL, NULL, '1) إرفاق عينة من مستندات تثبت عقد ورش العمل مع ملّاك المخاطر، وفق متطلبات تطبيق هذا المعيار.', '1) Attach sample documents proving workshops conducted with risk owners per this standard''s requirements.', NULL, NULL, NULL);
INSERT INTO public.framework_nodes (id, framework_id, parent_id, node_type, reference_code, name, name_ar, description, description_ar, guidance, guidance_ar, sort_order, path, depth, is_active, is_assessable, weight, max_score, metadata_json, created_at, updated_at, maturity_level, evidence_type, acceptance_criteria, acceptance_criteria_en, spec_references, priority, assessment_type) VALUES ('2f37e7a2-c41c-426e-9fcc-6158f9b08372', 'b2c124a4-92e9-4fae-bf22-ad5424209b6b', 'e99e6bb7-362a-4e3d-973c-84ec92362e2e', 'Requirement', 'S5.7.2.R1', '1) Establish a mechanism for versioning and numbering updated editions of processes and procedures.', '1) وضع آلية لترقيم الإصدارات والنسخ المحدثة للعمليات والإجراءات.', NULL, NULL, NULL, NULL, 1, '/67c04d75-3ce8-4615-9784-464e399ce0cb/29e6d76c-cfb0-4d11-853e-f87ce2cc6297/e99e6bb7-362a-4e3d-973c-84ec92362e2e/2f37e7a2-c41c-426e-9fcc-6158f9b08372/', 3, true, true, 1.00, NULL, NULL, '2026-04-11 04:22:30.441439+00', '2026-04-11 04:28:56.918765+00', NULL, NULL, '1) إرفاق آلية ترقيم الإصدارات والنسخ المحدثة للعمليات والإجراءات.', '1) Attach the versioning mechanism for updated process and procedure editions.', NULL, NULL, NULL);
