INSERT INTO public.framework_nodes (id, framework_id, parent_id, node_type, reference_code, name, name_ar, description, description_ar, guidance, guidance_ar, sort_order, path, depth, is_active, is_assessable, weight, max_score, metadata_json, created_at, updated_at, maturity_level, evidence_type, acceptance_criteria, acceptance_criteria_en, spec_references, priority, assessment_type) VALUES ('75f0c27f-8c17-48cb-b6e3-0f63f2ac8a05', 'b2c124a4-92e9-4fae-bf22-ad5424209b6b', 'd4575564-4f57-408e-9d88-23cb143189e9', 'Requirement', 'S5.10.3.R1', '1) Include all internal and external processes and procedures, identify dependencies during disruption, and assign process owners.', '1) تضمين جميع العمليات والإجراءات الداخلية والخارجية التي تقوم بها الجهة، وتحديد الاعتمادات الداخلية والخارجية عند حدوث انقطاع للأعمال، وتعيين ملاك العمليات والإجراءات المضمَّنة.', NULL, NULL, NULL, NULL, 1, '/1da7ecaf-95c5-4402-aa7b-f34786019aa6/1f95de6d-8d99-409f-bf82-49fde52aa796/d4575564-4f57-408e-9d88-23cb143189e9/75f0c27f-8c17-48cb-b6e3-0f63f2ac8a05/', 3, true, true, 1.00, NULL, NULL, '2026-04-11 04:22:31.229579+00', '2026-04-11 04:28:57.487669+00', NULL, NULL, '1) إرفاق قائمة أو سجل معتمد يثبت حصر جميع العمليات والإجراءات الداخلية والخارجية في تحليل أثر انقطاع الأعمال.', '1) Attach an approved list or register proving inventory of all processes in the business impact analysis.', NULL, NULL, NULL);
INSERT INTO public.framework_nodes (id, framework_id, parent_id, node_type, reference_code, name, name_ar, description, description_ar, guidance, guidance_ar, sort_order, path, depth, is_active, is_assessable, weight, max_score, metadata_json, created_at, updated_at, maturity_level, evidence_type, acceptance_criteria, acceptance_criteria_en, spec_references, priority, assessment_type) VALUES ('780b681a-af01-4310-9f89-c1b3873cd2ae', 'b2c124a4-92e9-4fae-bf22-ad5424209b6b', '8cc465d7-3c67-45bc-a0e1-7d4456702d30', 'Requirement', 'S5.17.4.R1', '1) Provide no less than (30%) or (10) digital services — whichever is higher — proactively for external beneficiaries during the (2026) measurement cycle.', '1) تقديم ما لا يقل عن (30%) أو (10) خدمات رقمية -أيهما أعلى- من إجمالي الخدمات الرقمية التي تقدمها الجهة للمستفيد الخارجي بشكل استباقي خلال دورة قياس (2026م).', NULL, NULL, NULL, NULL, 1, '/66dd45a8-6ec9-4d82-9d56-a83c75b23a47/fbd949a4-48e1-44f2-851a-3243efed765b/8cc465d7-3c67-45bc-a0e1-7d4456702d30/780b681a-af01-4310-9f89-c1b3873cd2ae/', 3, true, true, 1.00, NULL, NULL, '2026-04-11 04:22:33.14344+00', '2026-04-11 04:28:59.064248+00', NULL, NULL, '1) إرفاق ما يثبت تقديم الخدمات بشكل استباقي للمستفيد الخارجي، وفق متطلبات تطبيق هذا المعيار.', '1) Attach proof of providing proactive services to external beneficiaries per this standard''s requirements.', NULL, NULL, NULL);
INSERT INTO public.framework_nodes (id, framework_id, parent_id, node_type, reference_code, name, name_ar, description, description_ar, guidance, guidance_ar, sort_order, path, depth, is_active, is_assessable, weight, max_score, metadata_json, created_at, updated_at, maturity_level, evidence_type, acceptance_criteria, acceptance_criteria_en, spec_references, priority, assessment_type) VALUES ('fc7dbc5c-8f2a-4277-a937-bcd07d210141', 'b2c124a4-92e9-4fae-bf22-ad5424209b6b', '8a413213-3f44-43eb-827f-5a2bf9164a45', 'Requirement', 'S5.11.5.R1', '1) Increase email usage rates in daily correspondence.', '1) رفع نسب استخدام البريد الإلكتروني في المراسلات اليومية.', NULL, NULL, NULL, NULL, 1, '/eaa87d00-46fc-440d-b0af-6fb89269407c/b697414a-0b0d-41c6-8c15-d0353044012f/8a413213-3f44-43eb-827f-5a2bf9164a45/fc7dbc5c-8f2a-4277-a937-bcd07d210141/', 3, true, true, 1.00, NULL, NULL, '2026-04-11 04:22:31.787159+00', '2026-04-11 04:28:57.957551+00', NULL, NULL, '1) تقديم تقرير حديث لآخر (6) أشهر من خادم البريد الإلكتروني الخاص بالجهة يوضح عدد الرسائل.', '1) Submit a recent 6-month report from the entity''s email server showing message count.', NULL, NULL, NULL);
INSERT INTO public.framework_nodes (id, framework_id, parent_id, node_type, reference_code, name, name_ar, description, description_ar, guidance, guidance_ar, sort_order, path, depth, is_active, is_assessable, weight, max_score, metadata_json, created_at, updated_at, maturity_level, evidence_type, acceptance_criteria, acceptance_criteria_en, spec_references, priority, assessment_type) VALUES ('e8973c16-e8fc-461e-be70-77742f742000', 'b2c124a4-92e9-4fae-bf22-ad5424209b6b', '3c9cbc75-007e-4bf5-bf8d-3284124cd943', 'Requirement', 'S5.11.3.R1', '1) Adopt the National Center for Documents and Archives preservation and disposal policies, ensuring alignment with entity systems and procedures.', '1) اعتماد سياسات الحفظ والإتلاف الخاصة بالمركز الوطني للوثائق والمحفوظات، وتطوير ما يلزم لضمان توافقها مع الأنظمة والإجراءات المتبعة في الجهة.', NULL, NULL, NULL, NULL, 1, '/eaa87d00-46fc-440d-b0af-6fb89269407c/b697414a-0b0d-41c6-8c15-d0353044012f/3c9cbc75-007e-4bf5-bf8d-3284124cd943/e8973c16-e8fc-461e-be70-77742f742000/', 3, true, true, 1.00, NULL, NULL, '2026-04-11 04:22:31.695918+00', '2026-04-11 04:28:57.884622+00', NULL, NULL, '1) إرفاق ما يثبت اعتماد سياسات الحفظ والإتلاف في الجهة، والمتوائمة مع سياسات المركز الوطني للوثائق والمحفوظات، وما يثبت مشاركتها مع منسوبي الجهة.', '1) Attach proof of adopting preservation and disposal policies aligned with the National Center for Documents and Archives, and proof of sharing with staff.', NULL, NULL, NULL);
INSERT INTO public.framework_nodes (id, framework_id, parent_id, node_type, reference_code, name, name_ar, description, description_ar, guidance, guidance_ar, sort_order, path, depth, is_active, is_assessable, weight, max_score, metadata_json, created_at, updated_at, maturity_level, evidence_type, acceptance_criteria, acceptance_criteria_en, spec_references, priority, assessment_type) VALUES ('ab843353-ce5e-45aa-9413-628c5141c722', 'b2c124a4-92e9-4fae-bf22-ad5424209b6b', 'b2263ae9-da7e-4f37-ba07-e6039ffd812e', 'Requirement', 'S5.12.4.R1', '1) Inventory software assets including open-source software, covering: name, type (open/closed source), description, programming language, usage licenses, sharing capability with government repository, and upload scheduling.', '1) حصر قائمة أصول البرمجيات لدى الجهة الحكومية بما فيها البرمجيات مفتوحة المصدر، بحيث تشمل
INSERT INTO public.framework_nodes (id, framework_id, parent_id, node_type, reference_code, name, name_ar, description, description_ar, guidance, guidance_ar, sort_order, path, depth, is_active, is_assessable, weight, max_score, metadata_json, created_at, updated_at, maturity_level, evidence_type, acceptance_criteria, acceptance_criteria_en, spec_references, priority, assessment_type) VALUES ('145e29fe-9111-4c04-ac96-14a5661b09d7', 'b2c124a4-92e9-4fae-bf22-ad5424209b6b', '30c95baa-6525-4a82-9966-20c662bd5ec6', 'Requirement', 'S5.18.3.R1', '1) Involve beneficiaries in all digital government service design stages (requirements gathering, design, pilot launch, operation and improvement).', '1) إشراك المستفيدين في جميع مراحل تصميم الخدمات الحكومية الرقمية (جمع المتطلبات، التصميم، والإطلاق التجريبى، والتشغيل والتحسين).', NULL, NULL, NULL, NULL, 1, '/f8a69d5b-caeb-4dbd-b746-b483f0570fb4/12905427-3213-4f5f-8f08-94db72538b17/30c95baa-6525-4a82-9966-20c662bd5ec6/145e29fe-9111-4c04-ac96-14a5661b09d7/', 3, true, true, 1.00, NULL, NULL, '2026-04-11 04:22:33.364586+00', '2026-04-11 04:28:59.205498+00', NULL, NULL, '1) إرفاق (4) عينات حديثة (عينة عن كل ربع) تثبت تشجيع المستفيدين على المشاركة في جميع مراحل تصميم الخدمات الحكومية الرقمية.', '1) Attach (4) recent samples (one per quarter) proving beneficiary involvement in all service design stages.', NULL, NULL, NULL);
