INSERT INTO public.framework_nodes (id, framework_id, parent_id, node_type, reference_code, name, name_ar, description, description_ar, guidance, guidance_ar, sort_order, path, depth, is_active, is_assessable, weight, max_score, metadata_json, created_at, updated_at, maturity_level, evidence_type, acceptance_criteria, acceptance_criteria_en, spec_references, priority, assessment_type) VALUES ('f2c407c6-e35f-4f55-a3ea-9433385b9cf3', 'b2c124a4-92e9-4fae-bf22-ad5424209b6b', '68c4b895-b3bd-42fd-9b0e-55998dd44766', 'Requirement', 'S5.20.5.R1', '1) Inventory and define all beneficiary life journeys for various segments, identifying priority journeys to launch during (2026), no less than (3) journeys.', '1) حصر وتعريف كافة رحالت حياة المستفيدين المقدمة لمختلف الفئات في القطاع/الجهة، مع تحديد الرحالت ذات األولوية التي سيتم إطالقها خالل سنة (2026م) على أن لا تقل عن (3) رحالت.', NULL, NULL, NULL, NULL, 1, '/f8a69d5b-caeb-4dbd-b746-b483f0570fb4/355108bd-50ab-461c-81a7-0169b4c985f0/68c4b895-b3bd-42fd-9b0e-55998dd44766/f2c407c6-e35f-4f55-a3ea-9433385b9cf3/', 3, true, true, 1.00, NULL, NULL, '2026-04-11 04:22:33.704043+00', '2026-04-11 04:28:59.400845+00', NULL, NULL, '1) إرفاق نموذج حصر رحالت الحياة وفق متطلبات تطبيق هذا المعيار.', '1) Attach the life journeys inventory form per this standard''s requirements.', NULL, NULL, NULL);
