INSERT INTO public.framework_nodes (id, framework_id, parent_id, node_type, reference_code, name, name_ar, description, description_ar, guidance, guidance_ar, sort_order, path, depth, is_active, is_assessable, weight, max_score, metadata_json, created_at, updated_at, maturity_level, evidence_type, acceptance_criteria, acceptance_criteria_en, spec_references, priority, assessment_type) VALUES ('59637d4d-7e55-40b2-b585-100c86970f80', 'b2c124a4-92e9-4fae-bf22-ad5424209b6b', 'db7550ef-4438-460a-aeaf-375a2ed69f8f', 'Requirement', 'S5.4.1.R2', '2) Prepare awareness programs for staff on digital transformation importance, including: a. Target segments and awareness targets. b. Selected means, channels, and timeline.', '2) إعداد برامج توعوية لمنسوبي الجهة الحكومية بأهمية عمليات التحول الرقمي بحيث تشمل: أ. تحديد الفئات المستهدفة والمستهدفات لزيادة الوعي بالتحول الرقمي من منسوبي الجهة بمختلف الوحدات والمستويات الإدارية. ب. اختيار الوسائل والقنوات التي ستُستخدم في برامج زيادة الوعي بالتحول الرقمي والجدول الزمني لتنفيذ هذه البرامج.', NULL, NULL, NULL, NULL, 2, '/5530232e-d754-4d10-a280-2f2cc285340d/56b7daaf-c5b7-4054-9c1c-ba55a211577c/db7550ef-4438-460a-aeaf-375a2ed69f8f/59637d4d-7e55-40b2-b585-100c86970f80/', 3, true, true, 1.00, NULL, NULL, '2026-04-11 04:22:30.079999+00', '2026-04-11 04:28:56.699779+00', NULL, NULL, 'إرفاق وثيقة حديثة توضح البرامج التوعوية التي أعدتها الجهة، لزيادة وعي منسوبيها بالتحول الرقمي، وفق متطلبات تطبيق هذا المعيار.', 'Attach a recent document showing awareness programs prepared per this standard''s requirements.', NULL, NULL, NULL);
