INSERT INTO public.framework_nodes (id, framework_id, parent_id, node_type, reference_code, name, name_ar, description, description_ar, guidance, guidance_ar, sort_order, path, depth, is_active, is_assessable, weight, max_score, metadata_json, created_at, updated_at, maturity_level, evidence_type, acceptance_criteria, acceptance_criteria_en, spec_references, priority, assessment_type) VALUES ('29925782-2c17-4f4b-8bde-9c3898b9173c', 'b2c124a4-92e9-4fae-bf22-ad5424209b6b', 'dc4961c3-5fd7-4482-ab8a-154b66a72182', 'Requirement', 'S5.16.2.R1', '1) Develop digital systems and tools that measure digital service quality per approved indicators and standards.', '1) تطوير النظم والأدوات الرقمية التي تقيس جودة الخدمات الرقمية وفقًا للمؤشرات والمعايير المعتمدة لديها.', NULL, NULL, NULL, NULL, 1, '/66dd45a8-6ec9-4d82-9d56-a83c75b23a47/b076a4bd-224c-404e-8487-79c076b10168/dc4961c3-5fd7-4482-ab8a-154b66a72182/29925782-2c17-4f4b-8bde-9c3898b9173c/', 3, true, true, 1.00, NULL, NULL, '2026-04-11 04:22:32.844401+00', '2026-04-11 04:28:58.772253+00', NULL, NULL, '1) إرفاق عينات وصور شاشات حديثة للنظم المستخدمة في قياس جودة الخدمات.', '1) Attach recent samples and screenshots of systems measuring digital service quality.', NULL, NULL, NULL);
INSERT INTO public.framework_nodes (id, framework_id, parent_id, node_type, reference_code, name, name_ar, description, description_ar, guidance, guidance_ar, sort_order, path, depth, is_active, is_assessable, weight, max_score, metadata_json, created_at, updated_at, maturity_level, evidence_type, acceptance_criteria, acceptance_criteria_en, spec_references, priority, assessment_type) VALUES ('892efa43-c176-4471-a7ed-79f581f3a7bd', 'b2c124a4-92e9-4fae-bf22-ad5424209b6b', '70c1e4a8-9713-4694-928b-99cebad7ccef', 'Requirement', 'S5.14.4.R2', '2) Actual activation of digital trust services for all entity operations including internal and external beneficiaries.', '2) التفعيل الفعلي لخدمات الثقة الرقمية لجميع أعمال وخدمات الجهة بما يشمل المستفيد الداخلي والخارجي', NULL, NULL, NULL, NULL, 2, '/d2a77bfc-3828-4697-8f64-c837e89ff585/bb206aae-4d83-494b-bb48-2d4ae3111473/70c1e4a8-9713-4694-928b-99cebad7ccef/892efa43-c176-4471-a7ed-79f581f3a7bd/', 3, true, true, 1.00, NULL, NULL, '2026-04-11 04:22:32.625156+00', '2026-04-11 04:28:58.584966+00', NULL, NULL, '2) إرفاق (3) عينات غير مدمجة لكل نوع خدمة، موثقة رقم يا صادرة من الخدمة الرقمية وقابلة للتحقق بصيغة (PDF) أو (XML) وفق متطلبات تطبيق هذا المعيار.', '2) Attach (3) non-consolidated samples per service type, digitally documented and verifiable in PDF/XML format per this standard''s requirements.', NULL, NULL, NULL);
INSERT INTO public.framework_nodes (id, framework_id, parent_id, node_type, reference_code, name, name_ar, description, description_ar, guidance, guidance_ar, sort_order, path, depth, is_active, is_assessable, weight, max_score, metadata_json, created_at, updated_at, maturity_level, evidence_type, acceptance_criteria, acceptance_criteria_en, spec_references, priority, assessment_type) VALUES ('4e4fb1dc-490d-4299-9cd5-dd4fb40c8183', 'b2c124a4-92e9-4fae-bf22-ad5424209b6b', '16f5e9a5-edfa-4e5c-b82f-5b02ef1c2ba2', 'Requirement', 'S5.5.4.R2', '2) Conduct workshops and conferences for digital transformation leaders at entity or inter-entity level.', '2) عقد ورش عمل ومؤتمرات لقيادات التحول الرقمى على مستوى الجهة أو مع الجهات الخارجية الأخرى.', NULL, NULL, NULL, NULL, 2, '/5530232e-d754-4d10-a280-2f2cc285340d/7f7a255b-80d9-4d28-b56b-89c6948acfd1/16f5e9a5-edfa-4e5c-b82f-5b02ef1c2ba2/4e4fb1dc-490d-4299-9cd5-dd4fb40c8183/', 3, true, true, 1.00, NULL, NULL, '2026-04-11 04:22:30.288346+00', '2026-04-11 04:28:56.846196+00', NULL, NULL, '2)إرفاق عينات حديثة من ورش العمل والمؤتمرات التى أُقيمت مع جهات حكومية أخرى.', '2) Attach recent workshop and conference samples held with other government entities.', NULL, NULL, NULL);
