INSERT INTO public.framework_nodes (id, framework_id, parent_id, node_type, reference_code, name, name_ar, description, description_ar, guidance, guidance_ar, sort_order, path, depth, is_active, is_assessable, weight, max_score, metadata_json, created_at, updated_at, maturity_level, evidence_type, acceptance_criteria, acceptance_criteria_en, spec_references, priority, assessment_type) VALUES ('d2225fd8-38ab-4511-a245-135891258648', 'b2c124a4-92e9-4fae-bf22-ad5424209b6b', 'd0e54444-6bd5-49c6-bfc5-ca6e0c3e2740', 'Requirement', 'S5.15.2.R3', '3) Launch the unified sectoral platform approved by DGA.', '3) إطلاق المنصة القطاعية الموحدة والمعتمدة من قبل هيئة الحكومة الرقمية.', NULL, NULL, NULL, NULL, 3, '/d2a77bfc-3828-4697-8f64-c837e89ff585/ab80a93b-c219-43bb-aaea-5700eee62ef2/d0e54444-6bd5-49c6-bfc5-ca6e0c3e2740/d2225fd8-38ab-4511-a245-135891258648/', 3, true, true, 1.00, NULL, NULL, '2026-04-11 04:22:32.712319+00', '2026-04-11 04:28:58.646464+00', NULL, NULL, '3) لا يتطلب إرفاق مستند إثبات، وسيتم التحقق داخليًا من إطلاق المنصة القطاعية الموحدة.', '3) No proof document required. Internal verification of unified sectoral platform launch.', NULL, NULL, NULL);
INSERT INTO public.framework_nodes (id, framework_id, parent_id, node_type, reference_code, name, name_ar, description, description_ar, guidance, guidance_ar, sort_order, path, depth, is_active, is_assessable, weight, max_score, metadata_json, created_at, updated_at, maturity_level, evidence_type, acceptance_criteria, acceptance_criteria_en, spec_references, priority, assessment_type) VALUES ('a66ef066-759d-429f-9fde-5a49ba68f112', 'b2c124a4-92e9-4fae-bf22-ad5424209b6b', 'fac28188-7b6f-4d1e-a121-f6a8ec12e70b', 'Requirement', 'S5.5.2.R3', '3) Study and analyze periodic reports and issue corrective decisions based on monitoring results.', '3) دراسة التقارير الدورية وتحليلها وإصدار قرارات وإجراءات تصحيحية بناء على نتائج التقارير الدورية للمتابعة.', NULL, NULL, NULL, NULL, 3, '/5530232e-d754-4d10-a280-2f2cc285340d/7f7a255b-80d9-4d28-b56b-89c6948acfd1/fac28188-7b6f-4d1e-a121-f6a8ec12e70b/a66ef066-759d-429f-9fde-5a49ba68f112/', 3, true, true, 1.00, NULL, NULL, '2026-04-11 04:22:30.222787+00', '2026-04-11 04:28:56.805528+00', NULL, NULL, '3) إرفاق الدراسة التحليلية لتقارير المتابعة الدورية وعينات حديثة من المحاضر التى تثبت متابعة لجنة التعاملات الإلكترونية الحكومية -لجنة التحول الرقمى- التنفيذ واتخاذ القرارات التصحيحية.', '3) Attach analytical study of periodic reports and recent minutes proving committee monitoring and corrective decisions.', NULL, NULL, NULL);
INSERT INTO public.framework_nodes (id, framework_id, parent_id, node_type, reference_code, name, name_ar, description, description_ar, guidance, guidance_ar, sort_order, path, depth, is_active, is_assessable, weight, max_score, metadata_json, created_at, updated_at, maturity_level, evidence_type, acceptance_criteria, acceptance_criteria_en, spec_references, priority, assessment_type) VALUES ('d3d27053-75f0-42c5-96f0-ee0e78a280d5', 'b2c124a4-92e9-4fae-bf22-ad5424209b6b', 'a551835a-dc19-4d88-9517-9305ef6a413e', 'Requirement', 'S5.14.2.R3', '2) Activate the National Single Sign-On (Nafath) shared technical resource in all government platforms providing digital services.', '2) تفعيل المورد التقنى المشترك لخدمة النفاذ الوطنى الموحد فى جميع المنصات والتطبيقات الحكومية التي تقدم خدمات رقمية، وحصر الاستفادة من خدمات الهوية الرقمية للأفراد عبر منظومة النفاذ الوطني الموحد.', NULL, NULL, NULL, NULL, 3, '/d2a77bfc-3828-4697-8f64-c837e89ff585/bb206aae-4d83-494b-bb48-2d4ae3111473/a551835a-dc19-4d88-9517-9305ef6a413e/d3d27053-75f0-42c5-96f0-ee0e78a280d5/', 3, true, true, 1.00, NULL, NULL, '2026-04-11 04:22:32.428249+00', '2026-04-11 04:28:58.41585+00', NULL, NULL, '2) لا يتطلب إرفاق مستند إثبات، وسيتم التحقق داخليا من ارتباط الجهة بخدمات النفاذ الوطنى الموحد "نفاذ".', '2) No proof document required. Internal verification of entity linkage with Nafath services.', NULL, NULL, NULL);
