INSERT INTO public.framework_nodes (id, framework_id, parent_id, node_type, reference_code, name, name_ar, description, description_ar, guidance, guidance_ar, sort_order, path, depth, is_active, is_assessable, weight, max_score, metadata_json, created_at, updated_at, maturity_level, evidence_type, acceptance_criteria, acceptance_criteria_en, spec_references, priority, assessment_type) VALUES ('26d91f52-c49c-47cb-a42f-fc3059884536', 'b2c124a4-92e9-4fae-bf22-ad5424209b6b', 'dbc6cba4-062e-4058-9b87-47a60b79dcf2', 'Requirement', 'S5.10.1.R3', '3) Establish a steering committee for BCMS oversight, chaired by entity head or deputy, with necessary authorities.', '3) إنشاء لجنة توجيهية مسؤولة عن متابعة تطبيق نظام إدارة استمرارية الأعمال بالجهة، برأسها رئيس الجهة أو نائبه، وأن تمتلك اللجنة الصلاحيات اللازمة لدعم نظام استمرارية الأعمال.', NULL, NULL, NULL, NULL, 3, '/1da7ecaf-95c5-4402-aa7b-f34786019aa6/1f95de6d-8d99-409f-bf82-49fde52aa796/dbc6cba4-062e-4058-9b87-47a60b79dcf2/26d91f52-c49c-47cb-a42f-fc3059884536/', 3, true, true, 1.00, NULL, NULL, '2026-04-11 04:22:31.096275+00', '2026-04-11 04:28:57.388984+00', NULL, NULL, '3) إرفاق قرار إنشاء اللجنة التوجيهية المسؤولة عن الإشراف على أعمال نظام استمرارية الأعمال.', '3) Attach the business continuity steering committee establishment decision.', NULL, NULL, NULL);
INSERT INTO public.framework_nodes (id, framework_id, parent_id, node_type, reference_code, name, name_ar, description, description_ar, guidance, guidance_ar, sort_order, path, depth, is_active, is_assessable, weight, max_score, metadata_json, created_at, updated_at, maturity_level, evidence_type, acceptance_criteria, acceptance_criteria_en, spec_references, priority, assessment_type) VALUES ('0954d986-8ddf-4c84-8654-b7fb8deaccb0', 'b2c124a4-92e9-4fae-bf22-ad5424209b6b', '23149bbf-e7ac-44b5-b28c-c5a6c92d121c', 'Requirement', 'S5.18.1.R3', '3) Publish co-development and innovation initiatives through ''Tafa''ul'' platform quarterly.', '3) نشر مبادرات للتطوير المشترك والابتكار المتعلقة بالخدمات والمنصات والتطبيقات عبر منصة "تفاعل" بشكل ربعي، على أن تشمل كل مبادرة مراحل: الطرح، والتمكين، وعرض النتائج.', NULL, NULL, NULL, NULL, 3, '/f8a69d5b-caeb-4dbd-b746-b483f0570fb4/12905427-3213-4f5f-8f08-94db72538b17/23149bbf-e7ac-44b5-b28c-c5a6c92d121c/0954d986-8ddf-4c84-8654-b7fb8deaccb0/', 3, true, true, 1.00, NULL, NULL, '2026-04-11 04:22:33.261462+00', '2026-04-11 04:28:59.14042+00', NULL, NULL, '3) لا يتطلب إرفاق مستند إثبات، وسيتم التحقق داخليًا من نشر مبادرات التطوير المشترك والابتكار على منصة "تفاعل".', '3) No proof document required. Internal verification of publishing co-development initiatives on ''Tafa''ul''.', NULL, NULL, NULL);
INSERT INTO public.framework_nodes (id, framework_id, parent_id, node_type, reference_code, name, name_ar, description, description_ar, guidance, guidance_ar, sort_order, path, depth, is_active, is_assessable, weight, max_score, metadata_json, created_at, updated_at, maturity_level, evidence_type, acceptance_criteria, acceptance_criteria_en, spec_references, priority, assessment_type) VALUES ('2330c2e4-0c59-4b00-a9f9-470ab1a774e1', 'b2c124a4-92e9-4fae-bf22-ad5424209b6b', 'fe71e6ba-eba3-466c-9ddd-89e5d030c272', 'Requirement', 'S5.23.3.R3', '1) Form an administrative unit or committee for promoting and adopting innovation within the entity.', '1) تشكيل وحدة إدارية أو لجنة لتحفيز وتبنّي الابتكار ومفاهيمه داخل الجهة، وتحديد أدوارها ومسؤولياتها.', NULL, NULL, NULL, NULL, 3, '/e7c18638-4285-416e-8b87-c4bfcad9b4e9/032f1549-f9df-44d8-8c70-964c8590bbfb/fe71e6ba-eba3-466c-9ddd-89e5d030c272/2330c2e4-0c59-4b00-a9f9-470ab1a774e1/', 3, true, true, 1.00, NULL, NULL, '2026-04-11 04:22:34.079412+00', '2026-04-11 04:28:59.581925+00', NULL, NULL, '1) إرفاق هيكل الوحدة الإدارية أو اللجنة ضمن الهيكل الإدارى للجهة وتحديد الأدوار والمسؤوليات المناطة بھا.', '1) Attach the unit/committee structure within the entity''s administrative structure with defined roles and responsibilities.', NULL, NULL, NULL);
INSERT INTO public.framework_nodes (id, framework_id, parent_id, node_type, reference_code, name, name_ar, description, description_ar, guidance, guidance_ar, sort_order, path, depth, is_active, is_assessable, weight, max_score, metadata_json, created_at, updated_at, maturity_level, evidence_type, acceptance_criteria, acceptance_criteria_en, spec_references, priority, assessment_type) VALUES ('167e792f-60bb-4c6f-8828-0614b7c73ba3', 'b2c124a4-92e9-4fae-bf22-ad5424209b6b', '7a51ec8f-8316-4a87-888f-39ef20f6609c', 'Requirement', 'S5.18.2.R3', '3) Activate the ''Digital Complaint'' service and announce it through an official channel.', '3) تفعيل خدمة "بلاغ رقمى" لدى الجهة الحكومية والإعلان عنها من خلال إحدى القنوات الرسمية المعتمدة لدى الجهة الحكومية.', NULL, NULL, NULL, NULL, 3, '/f8a69d5b-caeb-4dbd-b746-b483f0570fb4/12905427-3213-4f5f-8f08-94db72538b17/7a51ec8f-8316-4a87-888f-39ef20f6609c/167e792f-60bb-4c6f-8828-0614b7c73ba3/', 3, true, true, 1.00, NULL, NULL, '2026-04-11 04:22:33.332121+00', '2026-04-11 04:28:59.189413+00', NULL, NULL, '3) إرفاق مايثبت الإعلان عن خدمة "بلاغ رقمي" من خلال إحدى القنوات الرسمية المعتمدة لدى الجهة، وسيتم التحقق من تفعيل خدمة "بلاغ رقمى" داخليًا.', '3) Attach proof of ''Digital Complaint'' service announcement. Service activation verified internally.', NULL, NULL, NULL);
