INSERT INTO public.framework_nodes (id, framework_id, parent_id, node_type, reference_code, name, name_ar, description, description_ar, guidance, guidance_ar, sort_order, path, depth, is_active, is_assessable, weight, max_score, metadata_json, created_at, updated_at, maturity_level, evidence_type, acceptance_criteria, acceptance_criteria_en, spec_references, priority, assessment_type) VALUES ('3cf992ab-0425-4406-9ae1-18db41b778e6', 'b2c124a4-92e9-4fae-bf22-ad5424209b6b', '0d64734f-eef0-44b7-bf59-a75e010d533e', 'Requirement', 'S5.8.1.R5', '5) Government entity tenders communications services contracts via electronic market.', '5) قيام الجهة الحكومية بطرح منافساتها لخدمات الاتصالات سواء أكانت نفقات عامة أم برامج أم مشاريع على منصة "اعتماد".', NULL, NULL, NULL, NULL, 5, '/67c04d75-3ce8-4615-9784-464e399ce0cb/3059ba0d-feee-46b8-9640-bf112a65f1d6/0d64734f-eef0-44b7-bf59-a75e010d533e/3cf992ab-0425-4406-9ae1-18db41b778e6/', 3, true, true, 1.00, NULL, NULL, '2026-04-11 04:22:30.594349+00', '2026-04-11 04:28:57.012204+00', NULL, NULL, '5) إرفاق صورة من منصة "اعتماد" توضح الرقم المرجعى للمنافسة المطروحة وحالتها.', '5) Attach ''Etimad'' screenshot showing tender reference number and status.', NULL, NULL, NULL);
