INSERT INTO public.framework_nodes (id, framework_id, parent_id, node_type, reference_code, name, name_ar, description, description_ar, guidance, guidance_ar, sort_order, path, depth, is_active, is_assessable, weight, max_score, metadata_json, created_at, updated_at, maturity_level, evidence_type, acceptance_criteria, acceptance_criteria_en, spec_references, priority, assessment_type) VALUES ('f084b9e6-9f68-424f-a7ae-78ce6f4e8f59', 'b2c124a4-92e9-4fae-bf22-ad5424209b6b', 'bb725532-459b-4355-931e-868d2a523768', 'Requirement', 'S5.9.5.R6', '6) Sign NDAs with outsourcing service providers.', '6) توقيع اتفاقيات عدم الإفصاح (NDAs) مع مقدمي خدمات الإسناد المتعلقة بتقنية المعلومات للمحافظة على سرية البيانات والمعلومات، ووضع إجراءات وآليات للمراجعة والتدقيق الدوري على مقدمي خدمات الإسناد للتحقق من فعالية الضوابط الداخلية وضمان مستوى الامتثال المطلوب.', NULL, NULL, NULL, NULL, 6, '/1da7ecaf-95c5-4402-aa7b-f34786019aa6/779584e2-ddb4-45cc-b4a5-e366b1d57e80/bb725532-459b-4355-931e-868d2a523768/f084b9e6-9f68-424f-a7ae-78ce6f4e8f59/', 3, true, true, 1.00, NULL, NULL, '2026-04-11 04:22:31.049351+00', '2026-04-11 04:28:57.364809+00', NULL, NULL, '6) إرفاق حصر معتمد من المسؤول الأول في الجهة أو من ينوب عنه بقائمة الشركات المقدمة لخدمات الإسناد مع التأكيد على توقيع كل شركة على اتفاقية عدم الإفصاح وفق متطلبات تطبيق هذا المعيار، وعينة موقعة حسب النموذج المعتمد.', '6) Attach approved inventory showing NDA compliance.', NULL, NULL, NULL);
INSERT INTO public.framework_nodes (id, framework_id, parent_id, node_type, reference_code, name, name_ar, description, description_ar, guidance, guidance_ar, sort_order, path, depth, is_active, is_assessable, weight, max_score, metadata_json, created_at, updated_at, maturity_level, evidence_type, acceptance_criteria, acceptance_criteria_en, spec_references, priority, assessment_type) VALUES ('ec910f49-f7b9-47fa-9ffd-b589f902f4b9', 'b2c124a4-92e9-4fae-bf22-ad5424209b6b', 'd4575564-4f57-408e-9d88-23cb143189e9', 'Requirement', 'S5.10.3.R6', '5) Steering Committee approval of comprehensive business impact analysis report.', '5) اعتماد اللجنة التوجيهية للتقرير الشامل لنتائج تحليل أثر انقطاع الأعمال باستخدام مصفوفة تقييم الأثر.', NULL, NULL, NULL, NULL, 6, '/1da7ecaf-95c5-4402-aa7b-f34786019aa6/1f95de6d-8d99-409f-bf82-49fde52aa796/d4575564-4f57-408e-9d88-23cb143189e9/ec910f49-f7b9-47fa-9ffd-b589f902f4b9/', 3, true, true, 1.00, NULL, NULL, '2026-04-11 04:22:31.275454+00', '2026-04-11 04:28:57.529544+00', NULL, NULL, '5) إرفاق ما يثبت اعتماد اللجنة التوجيهية للتقرير الشامل لنتائج تحليل أثر انقطاع الأعمال، من قبلها.', '5) Attach proof of Steering Committee approval of comprehensive business impact analysis report.', NULL, NULL, NULL);
INSERT INTO public.framework_nodes (id, framework_id, parent_id, node_type, reference_code, name, name_ar, description, description_ar, guidance, guidance_ar, sort_order, path, depth, is_active, is_assessable, weight, max_score, metadata_json, created_at, updated_at, maturity_level, evidence_type, acceptance_criteria, acceptance_criteria_en, spec_references, priority, assessment_type) VALUES ('47213cf0-a7f2-4539-a295-67a2945de1d3', 'b2c124a4-92e9-4fae-bf22-ad5424209b6b', 'b11e0d55-dad7-4c3a-bdc8-9d665a417d6c', 'Requirement', 'S5.12.1.R6', '6) Approve controls for staff use of personal devices.', '6) اعتماد ضوابط وقواعد لاستخدام منسوبي الجهة لأجهزتهم الشخصية لأغراض العمل ومشاركتها مع منسوبي الجهة.', NULL, NULL, NULL, NULL, 6, '/eaa87d00-46fc-440d-b0af-6fb89269407c/7288b767-2e63-43e6-9f39-6e1abb5e45eb/b11e0d55-dad7-4c3a-bdc8-9d665a417d6c/47213cf0-a7f2-4539-a295-67a2945de1d3/', 3, true, true, 1.00, NULL, NULL, '2026-04-11 04:22:31.880912+00', '2026-04-11 04:28:58.026362+00', NULL, NULL, '6) إرفاق وثيقة ضوابط وقواعد استخدام المنسوبين لأجهزتهم الشخصية لأغراض العمل، وما يثبت مشاركتها مع المنسوبين.', '6) Attach controls document for staff personal device usage and proof of sharing.', NULL, NULL, NULL);
