INSERT INTO public.framework_nodes (id, framework_id, parent_id, node_type, reference_code, name, name_ar, description, description_ar, guidance, guidance_ar, sort_order, path, depth, is_active, is_assessable, weight, max_score, metadata_json, created_at, updated_at, maturity_level, evidence_type, acceptance_criteria, acceptance_criteria_en, spec_references, priority, assessment_type) VALUES ('3d32566d-298b-44e0-a81a-881fb1197aad', 'b2c124a4-92e9-4fae-bf22-ad5424209b6b', 'b8d1c09a-100e-4bc7-ac17-d7067ee507a0', 'Requirement', 'S5.3.2.R9', '9) Develop a digital transformation roadmap including initiatives and projects.', '9) تطوير خارطة طريق للتحول الرقمي تتضمن مجموعة المبادرات والمشاريع الزمنية لسد الفجوات، وتحقيق مستهدفات الوضع المستقبلي للبنية المؤسسية، بحيث تتضمن النقاط التالية: أ. البطاقات التفصيلية للمبادرات والمشاريع، ب. تحديد أولويات تنفيذ المبادرات والمشاريع وفق معايير معينة، ت. مؤشرات الأداء التي من خلالها تقييم التقدم في عمليات التنفيذ، ث. الجدول الزمني لعملية التنفيذ، ج. آليات المتابعة والقياس لمؤشرات الأداء.', NULL, NULL, NULL, NULL, 9, '/633ea9b9-b470-4be6-94c9-362bfd768aba/4fe1ba35-8844-4f32-9cb5-7cd7255464bd/b8d1c09a-100e-4bc7-ac17-d7067ee507a0/3d32566d-298b-44e0-a81a-881fb1197aad/', 3, true, true, 1.00, NULL, NULL, '2026-04-11 04:22:29.925725+00', '2026-04-11 04:28:56.591655+00', NULL, NULL, 'وثيقة خارطة طريق التحول الرقمي في الجهة وفق متطلبات تطبيق هذا المعيار.', 'Entity digital transformation roadmap document per this standard''s requirements.', NULL, NULL, NULL);
INSERT INTO public.framework_nodes (id, framework_id, parent_id, node_type, reference_code, name, name_ar, description, description_ar, guidance, guidance_ar, sort_order, path, depth, is_active, is_assessable, weight, max_score, metadata_json, created_at, updated_at, maturity_level, evidence_type, acceptance_criteria, acceptance_criteria_en, spec_references, priority, assessment_type) VALUES ('dccf64e8-2e21-45ed-b69a-07c076d18614', 'b2c124a4-92e9-4fae-bf22-ad5424209b6b', 'a551835a-dc19-4d88-9517-9305ef6a413e', 'Requirement', 'S5.14.2.R9', '8) Define a mechanism for receiving integration requests and leveraging shared systems.', '8) تحديد آلية استقبال طلبات الارتباط والاستفادة من الأنظمة والخدمات المشتركة، واتخاذ القرار بشأن
