INSERT INTO public.framework_nodes (id, framework_id, parent_id, node_type, reference_code, name, name_ar, description, description_ar, guidance, guidance_ar, sort_order, path, depth, is_active, is_assessable, weight, max_score, metadata_json, created_at, updated_at, maturity_level, evidence_type, acceptance_criteria, acceptance_criteria_en, spec_references, priority, assessment_type) VALUES ('30717e88-af01-4a02-98ad-cf1d9771f9e9', 'b2c124a4-92e9-4fae-bf22-ad5424209b6b', 'b2263ae9-da7e-4f37-ba07-e6039ffd812e', 'Requirement', 'S5.12.4.R10', '7) Submit approved digital procurement policies showing open-source purchase procedures.', '7) تقديم سياسات الشراء الرقمي المعتمدة، موصِّحة بها الإجراءات المتعلقة بشراء أو تطوير البرمجيات.', NULL, NULL, NULL, NULL, 10, '/eaa87d00-46fc-440d-b0af-6fb89269407c/7288b767-2e63-43e6-9f39-6e1abb5e45eb/b2263ae9-da7e-4f37-ba07-e6039ffd812e/30717e88-af01-4a02-98ad-cf1d9771f9e9/', 3, true, true, 1.00, NULL, NULL, '2026-04-11 04:22:32.099363+00', '2026-04-11 04:28:58.198258+00', NULL, NULL, '7) إرفاق سياسات الشراء الرقمي المعتمدة موضحة بها الإجراءات المتعلقة بشراء أو تطوير البرمجيات.', '7) Attach approved digital procurement policies showing open-source purchase procedures.', NULL, NULL, NULL);
INSERT INTO public.framework_nodes (id, framework_id, parent_id, node_type, reference_code, name, name_ar, description, description_ar, guidance, guidance_ar, sort_order, path, depth, is_active, is_assessable, weight, max_score, metadata_json, created_at, updated_at, maturity_level, evidence_type, acceptance_criteria, acceptance_criteria_en, spec_references, priority, assessment_type) VALUES ('952f7857-fafc-48f7-9f5b-37e1a91f8eb1', 'b2c124a4-92e9-4fae-bf22-ad5424209b6b', 'dd5619fa-e0b6-47bb-9424-dd3899ddf678', 'Requirement', 'S5.9.1.R10', '4) Appoint a qualified risk management system team.', '4) تعيين فريق يتولى تنفيذ الأدوار والمسؤوليات والمهام فى نظام إدارة المخاطر، بناءً على احتياجات وأعمال الجهة.', NULL, NULL, NULL, NULL, 10, '/1da7ecaf-95c5-4402-aa7b-f34786019aa6/779584e2-ddb4-45cc-b4a5-e366b1d57e80/dd5619fa-e0b6-47bb-9424-dd3899ddf678/952f7857-fafc-48f7-9f5b-37e1a91f8eb1/', 3, true, true, 1.00, NULL, NULL, '2026-04-11 04:22:30.789724+00', '2026-04-11 04:28:57.161113+00', NULL, NULL, '4) إرفاق تعريف موظفى نظام إدارة المخاطر بما يثبت تعيين فريق يتولى الأدوار والمسؤوليات فى نظام إدارة المخاطر.', '4) Attach team member employee identification proving appointment.', NULL, NULL, NULL);
INSERT INTO public.framework_nodes (id, framework_id, parent_id, node_type, reference_code, name, name_ar, description, description_ar, guidance, guidance_ar, sort_order, path, depth, is_active, is_assessable, weight, max_score, metadata_json, created_at, updated_at, maturity_level, evidence_type, acceptance_criteria, acceptance_criteria_en, spec_references, priority, assessment_type) VALUES ('f88d9210-6a56-4b3d-9f10-29a7c90f8ae7', 'b2c124a4-92e9-4fae-bf22-ad5424209b6b', 'dd5619fa-e0b6-47bb-9424-dd3899ddf678', 'Requirement', 'S5.9.1.R11', '5) Establish a steering committee for risk management system oversight.', '5) إنشاء لجنة توجيهية للإشراف على أعمال نظام إدارة المخاطر فى الجهة، يرأسها المسؤول الأول فى الجهة أو من ينوبه.', NULL, NULL, NULL, NULL, 11, '/1da7ecaf-95c5-4402-aa7b-f34786019aa6/779584e2-ddb4-45cc-b4a5-e366b1d57e80/dd5619fa-e0b6-47bb-9424-dd3899ddf678/f88d9210-6a56-4b3d-9f10-29a7c90f8ae7/', 3, true, true, 1.00, NULL, NULL, '2026-04-11 04:22:30.797007+00', '2026-04-11 04:28:57.170373+00', NULL, NULL, '5) إرفاق قرار إنشاء اللجنة التوجيهية المسؤولة عن الإشراف على أعمال نظام إدارة المخاطر، وفق متطلبات تطبيق هذا المعيار.', '5) Attach the risk management steering committee establishment decision.', NULL, NULL, NULL);
INSERT INTO public.framework_nodes (id, framework_id, parent_id, node_type, reference_code, name, name_ar, description, description_ar, guidance, guidance_ar, sort_order, path, depth, is_active, is_assessable, weight, max_score, metadata_json, created_at, updated_at, maturity_level, evidence_type, acceptance_criteria, acceptance_criteria_en, spec_references, priority, assessment_type) VALUES ('504f29c0-5c7a-41a2-b09d-e957e66d9432', 'b2c124a4-92e9-4fae-bf22-ad5424209b6b', '8a413213-3f44-43eb-827f-5a2bf9164a45', 'Requirement', 'S5.11.5.R2', '2) Include a disclaimer in email messages regarding government email content.', '2) تضمين رسائل البريد الإلكتروني بيان إخلاء المسؤولية المتعلقة بمحتويات البريد الإلكتروني الحكومي العام أو الخاص.', NULL, NULL, NULL, NULL, 2, '/eaa87d00-46fc-440d-b0af-6fb89269407c/b697414a-0b0d-41c6-8c15-d0353044012f/8a413213-3f44-43eb-827f-5a2bf9164a45/504f29c0-5c7a-41a2-b09d-e957e66d9432/', 3, true, true, 1.00, NULL, NULL, '2026-04-11 04:22:31.796479+00', '2026-04-11 04:28:57.966342+00', NULL, NULL, '2) تقديم صورة حديثة من بيان إخلاء المسؤولية الذي ضُمِّن في رسائل البريد الإلكتروني الخاصة بمنسوبي الجهة.', '2) Submit a recent image of the disclaimer included in entity staff emails.', NULL, NULL, NULL);
INSERT INTO public.framework_nodes (id, framework_id, parent_id, node_type, reference_code, name, name_ar, description, description_ar, guidance, guidance_ar, sort_order, path, depth, is_active, is_assessable, weight, max_score, metadata_json, created_at, updated_at, maturity_level, evidence_type, acceptance_criteria, acceptance_criteria_en, spec_references, priority, assessment_type) VALUES ('2d2fc33b-ce40-4873-8127-869210c2f7cd', 'b2c124a4-92e9-4fae-bf22-ad5424209b6b', 'dd5619fa-e0b6-47bb-9424-dd3899ddf678', 'Requirement', 'S5.9.1.R12', '6) Establish the Risk Management Steering Committee charter.', '6) وضع ميثاق اللجنة التوجيهية المسؤولة عن نظام إدارة المخاطر، واعتماده من قبل الإدارة العليا للجهة.', NULL, NULL, NULL, NULL, 12, '/1da7ecaf-95c5-4402-aa7b-f34786019aa6/779584e2-ddb4-45cc-b4a5-e366b1d57e80/dd5619fa-e0b6-47bb-9424-dd3899ddf678/2d2fc33b-ce40-4873-8127-869210c2f7cd/', 3, true, true, 1.00, NULL, NULL, '2026-04-11 04:22:30.805688+00', '2026-04-11 04:28:57.180024+00', NULL, NULL, '6) إرفاق ميثاق اللجنة التوجيهية المسؤولة عن الإشراف على أعمال نظام إدارة المخاطر المعتمد، وفق متطلبات تطبيق هذا المعيار.', '6) Attach the Risk Management Steering Committee charter with all required elements.', NULL, NULL, NULL);
INSERT INTO public.framework_nodes (id, framework_id, parent_id, node_type, reference_code, name, name_ar, description, description_ar, guidance, guidance_ar, sort_order, path, depth, is_active, is_assessable, weight, max_score, metadata_json, created_at, updated_at, maturity_level, evidence_type, acceptance_criteria, acceptance_criteria_en, spec_references, priority, assessment_type) VALUES ('72f828f6-5d97-4b6c-a398-ec64333596f5', 'b2c124a4-92e9-4fae-bf22-ad5424209b6b', '031993d8-6b02-49be-983b-9dcc723aad3f', 'Requirement', 'S5.10.5.R13', '9) Test IT disaster recovery plans at least annually.', '9) اختيار خطط التعافي من كوارث تقنية المعلومات والاتصالات بما يشمل تفعيل مراكز البيانات الاحتياطية واستعادة المنصات والتطبيقات الحرجة والحساسة لدى الجهة على الأقل مرة واحدة في السنة، أو عند حدوث تغيير جوهري لدى تقنية المعلومات لدى الجهة.', NULL, NULL, NULL, NULL, 13, '/1da7ecaf-95c5-4402-aa7b-f34786019aa6/1f95de6d-8d99-409f-bf82-49fde52aa796/031993d8-6b02-49be-983b-9dcc723aad3f/72f828f6-5d97-4b6c-a398-ec64333596f5/', 3, true, true, 1.00, NULL, NULL, '2026-04-11 04:22:31.497255+00', '2026-04-11 04:28:57.743252+00', NULL, NULL, '9) إرفاق عينات كافية من التقارير التي توضح اختيار خطط التعافي من الكوارث تقنية المعلومات والاتصالات بشكل سنوي.', '9) Attach sufficient report samples showing IT disaster recovery plan testing.', NULL, NULL, NULL);
INSERT INTO public.framework_nodes (id, framework_id, parent_id, node_type, reference_code, name, name_ar, description, description_ar, guidance, guidance_ar, sort_order, path, depth, is_active, is_assessable, weight, max_score, metadata_json, created_at, updated_at, maturity_level, evidence_type, acceptance_criteria, acceptance_criteria_en, spec_references, priority, assessment_type) VALUES ('590a9dbc-cb4b-4728-b5fb-60e94ab88ae1', 'b2c124a4-92e9-4fae-bf22-ad5424209b6b', 'dd5619fa-e0b6-47bb-9424-dd3899ddf678', 'Requirement', 'S5.9.1.R14', '8) Establish and approve a risk management framework.', '8) إنشاء واعتماد وثيقة إطار إدارة المخاطر.', NULL, NULL, NULL, NULL, 14, '/1da7ecaf-95c5-4402-aa7b-f34786019aa6/779584e2-ddb4-45cc-b4a5-e366b1d57e80/dd5619fa-e0b6-47bb-9424-dd3899ddf678/590a9dbc-cb4b-4728-b5fb-60e94ab88ae1/', 3, true, true, 1.00, NULL, NULL, '2026-04-11 04:22:30.824018+00', '2026-04-11 04:28:57.195678+00', NULL, NULL, '8) إرفاق إطار إدارة المخاطر موثّق ومعتمد.', '8) Attach documented and approved risk management framework.', NULL, NULL, NULL);
INSERT INTO public.framework_nodes (id, framework_id, parent_id, node_type, reference_code, name, name_ar, description, description_ar, guidance, guidance_ar, sort_order, path, depth, is_active, is_assessable, weight, max_score, metadata_json, created_at, updated_at, maturity_level, evidence_type, acceptance_criteria, acceptance_criteria_en, spec_references, priority, assessment_type) VALUES ('36b5b32b-11dc-4a60-bb55-d48ac39d003c', 'b2c124a4-92e9-4fae-bf22-ad5424209b6b', 'dd5619fa-e0b6-47bb-9424-dd3899ddf678', 'Requirement', 'S5.9.1.R15', '9) Establish and approve risk management procedures.', '9) إنشاء واعتماد إجراءات إدارة المخاطر.', NULL, NULL, NULL, NULL, 15, '/1da7ecaf-95c5-4402-aa7b-f34786019aa6/779584e2-ddb4-45cc-b4a5-e366b1d57e80/dd5619fa-e0b6-47bb-9424-dd3899ddf678/36b5b32b-11dc-4a60-bb55-d48ac39d003c/', 3, true, true, 1.00, NULL, NULL, '2026-04-11 04:22:30.833166+00', '2026-04-11 04:28:57.204252+00', NULL, NULL, '9) إرفاق الوثائق التى توضح إجراءات إدارة المخاطر الموثَّقة والمعتمدة.', '9) Attach documents showing documented and approved risk management procedures.', NULL, NULL, NULL);
INSERT INTO public.framework_nodes (id, framework_id, parent_id, node_type, reference_code, name, name_ar, description, description_ar, guidance, guidance_ar, sort_order, path, depth, is_active, is_assessable, weight, max_score, metadata_json, created_at, updated_at, maturity_level, evidence_type, acceptance_criteria, acceptance_criteria_en, spec_references, priority, assessment_type) VALUES ('b3b05017-2f91-47cb-9f2f-fe4ff05e2b4e', 'b2c124a4-92e9-4fae-bf22-ad5424209b6b', 'b34f422e-8b5f-4a0d-8d55-078e67245c3c', 'Requirement', 'S5.4.2.R3', '3) Implement awareness activities with leadership participation to increase digital tool and platform adoption.', '3) تنفيذ أنشطة توعوية يشارك فيها القادة، تهدف إلى زيادة تبني المنسوبين لعملية التحول الرقمي والمساهمة الفاعلة.', NULL, NULL, NULL, NULL, 3, '/5530232e-d754-4d10-a280-2f2cc285340d/56b7daaf-c5b7-4054-9c1c-ba55a211577c/b34f422e-8b5f-4a0d-8d55-078e67245c3c/b3b05017-2f91-47cb-9f2f-fe4ff05e2b4e/', 3, true, true, 1.00, NULL, NULL, '2026-04-11 04:22:30.117191+00', '2026-04-11 04:28:56.728734+00', NULL, NULL, 'إرفاق التقارير والعينات الحديثة التي تثبت مشاركة القادة في الأنشطة التوعوية.', 'Attach recent reports proving leadership participation in awareness activities for digital adoption.', NULL, NULL, NULL);
