INSERT INTO public.framework_nodes (id, framework_id, parent_id, node_type, reference_code, name, name_ar, description, description_ar, guidance, guidance_ar, sort_order, path, depth, is_active, is_assessable, weight, max_score, metadata_json, created_at, updated_at, maturity_level, evidence_type, acceptance_criteria, acceptance_criteria_en, spec_references, priority, assessment_type) VALUES ('06d144e5-4649-41e4-9e6f-824a908c4a28', 'b2c124a4-92e9-4fae-bf22-ad5424209b6b', 'a551835a-dc19-4d88-9517-9305ef6a413e', 'Requirement', 'S5.14.2.R2', '10) Prepare SLAs to ensure 24/7 system availability and service sustainability through multiple electronic channels.', '10) إعداد اتفاقيات مستوى الخدمة (SLA) لضمان توافر النظام على مدار الساعة واستدامة وتوافر الخدمة؛ من خلال أكثر من قناة إلكترونية؛ لتزويد الجهات الحكومية المستفيدة بالخدمة، وإعداد وثائق إجراءات التشغيل لجميع العمليات، وتفصيل اتفاقيات مستوى الخدمات الخاصة بخدمات الدعم على المنصة.', NULL, NULL, NULL, NULL, 2, '/d2a77bfc-3828-4697-8f64-c837e89ff585/bb206aae-4d83-494b-bb48-2d4ae3111473/a551835a-dc19-4d88-9517-9305ef6a413e/06d144e5-4649-41e4-9e6f-824a908c4a28/', 3, true, true, 1.00, NULL, NULL, '2026-04-11 04:22:32.41969+00', '2026-04-11 04:28:58.405781+00', NULL, NULL, '10) إرفاق نسخ من اتفاقيات مستوى الخدمة (SLA) وفق متطلبات تطبيق هذا المعيار.', '10) Attach SLA copies per this standard''s requirements.', NULL, NULL, NULL);
INSERT INTO public.framework_nodes (id, framework_id, parent_id, node_type, reference_code, name, name_ar, description, description_ar, guidance, guidance_ar, sort_order, path, depth, is_active, is_assessable, weight, max_score, metadata_json, created_at, updated_at, maturity_level, evidence_type, acceptance_criteria, acceptance_criteria_en, spec_references, priority, assessment_type) VALUES ('9eeab895-c49e-4164-8e84-db484a8b0053', 'b2c124a4-92e9-4fae-bf22-ad5424209b6b', '6c223db0-ac40-4d34-93f5-0885e721cd6b', 'Requirement', 'S5.17.3.R2', '2) Provide (10) internal digital services without forms (Pre-filled) during (2026) measurement cycle.', '2) تقديم (10) من الخدمات الرقمية الداخلية بدون نماذج (Pre-filled)، من خلال استرجاع البيانات تلقائيًا من الأنظمة ذات العلاقة بالاعتماد على مبدأ "طلب البيانات لمرة واحدة"، وعرض ملخص للمستفيد الداخلي للموافقة فقط، خلال دورة قياس (2026م).', NULL, NULL, NULL, NULL, 2, '/66dd45a8-6ec9-4d82-9d56-a83c75b23a47/fbd949a4-48e1-44f2-851a-3243efed765b/6c223db0-ac40-4d34-93f5-0885e721cd6b/9eeab895-c49e-4164-8e84-db484a8b0053/', 3, true, true, 1.00, NULL, NULL, '2026-04-11 04:22:33.118459+00', '2026-04-11 04:28:59.048186+00', NULL, NULL, '2) إرفاق ما يثبت تقديم (10) من الخدمات الرقمية بدون نماذج للمستفيد الداخلي، وفق متطلبات تطبيق هذا المعيار.', '2) Attach proof of providing (10) digital services without forms to internal beneficiaries per this standard''s requirements.', NULL, NULL, NULL);
INSERT INTO public.framework_nodes (id, framework_id, parent_id, node_type, reference_code, name, name_ar, description, description_ar, guidance, guidance_ar, sort_order, path, depth, is_active, is_assessable, weight, max_score, metadata_json, created_at, updated_at, maturity_level, evidence_type, acceptance_criteria, acceptance_criteria_en, spec_references, priority, assessment_type) VALUES ('af022948-9f9d-40dd-8994-30c6105ab72b', 'b2c124a4-92e9-4fae-bf22-ad5424209b6b', '8cc465d7-3c67-45bc-a0e1-7d4456702d30', 'Requirement', 'S5.17.4.R2', '2) Provide no less than (30%) of total digital services to external beneficiaries without forms (Pre-filled), using automatic data retrieval and ''request data once'' principle.', '2) تقديم ما لا يقل عن (30%) من إجمالي الخدمات الرقمية المقدمة للمستفيد الخارجي بدون نماذج (Pre-filled)، من خلال استرجاع البيانات تلقائيًا من الأنظمة ذات العلاقة بالاعتماد على مبدأ "طلب البيانات لمرة واحدة"، وعرض ملخص للمستفيد للموافقة فقط.', NULL, NULL, NULL, NULL, 2, '/66dd45a8-6ec9-4d82-9d56-a83c75b23a47/fbd949a4-48e1-44f2-851a-3243efed765b/8cc465d7-3c67-45bc-a0e1-7d4456702d30/af022948-9f9d-40dd-8994-30c6105ab72b/', 3, true, true, 1.00, NULL, NULL, '2026-04-11 04:22:33.152777+00', '2026-04-11 04:28:59.072041+00', NULL, NULL, '2) إرفاق ما يثبت تقديم (30%) من الخدمات الرقمية المقدمة للمستفيد الخارجي بدون نماذج، وفق متطلبات تطبيق هذا المعيار.', '2) Attach proof of providing (30%) of digital services without forms to external beneficiaries per this standard''s requirements.', NULL, NULL, NULL);
INSERT INTO public.framework_nodes (id, framework_id, parent_id, node_type, reference_code, name, name_ar, description, description_ar, guidance, guidance_ar, sort_order, path, depth, is_active, is_assessable, weight, max_score, metadata_json, created_at, updated_at, maturity_level, evidence_type, acceptance_criteria, acceptance_criteria_en, spec_references, priority, assessment_type) VALUES ('7de88cfe-ca13-4df0-b8f8-95cf480bf3e4', 'b2c124a4-92e9-4fae-bf22-ad5424209b6b', '68c4b895-b3bd-42fd-9b0e-55998dd44766', 'Requirement', 'S5.20.5.R3', '3) Launch (3) journeys during (2026), with one including at least one proactive service.', '3) إطالق (3) رحالت خالل عام (2026م)، على أن تتضمن إحداهم على األقل توظيف تقنيات الذكاء االصطناعي.', NULL, NULL, NULL, NULL, 3, '/f8a69d5b-caeb-4dbd-b746-b483f0570fb4/355108bd-50ab-461c-81a7-0169b4c985f0/68c4b895-b3bd-42fd-9b0e-55998dd44766/7de88cfe-ca13-4df0-b8f8-95cf480bf3e4/', 3, true, true, 1.00, NULL, NULL, '2026-04-11 04:22:33.72415+00', '2026-04-11 04:28:59.41734+00', NULL, NULL, '3) إرفاق ما يثبت إطالق (3) رحالت خالل عام (2026م)، على أن تتضمن إحداهم على األقل توظيف تقنيات الذكاء االصطناعي، مع تضمين رابط المنصة التي نشرت فيها الرحالت.', '3) Attach proof of launching (3) journeys during (2026) with one including a proactive service.', NULL, NULL, NULL);
