INSERT INTO public.framework_nodes (id, framework_id, parent_id, node_type, reference_code, name, name_ar, description, description_ar, guidance, guidance_ar, sort_order, path, depth, is_active, is_assessable, weight, max_score, metadata_json, created_at, updated_at, maturity_level, evidence_type, acceptance_criteria, acceptance_criteria_en, spec_references, priority, assessment_type) VALUES ('03827c4e-7137-4fbe-959c-3a69980bfcc0', 'b2c124a4-92e9-4fae-bf22-ad5424209b6b', '5fa62909-d1ff-4c45-b45a-d8e7eba23937', 'Requirement', 'S5.15.1.R2', '2) Inventory and register all external/internal entity platforms on ''Raqmi'' platform, including affiliated entities.', '2) حصر وتسجيل جميع منصات الجهة الخارجية والداخلية، بالنطاقات الرئيسية والفرعية، ومنصات الجهات التابعة لها - إن وجدت -، لدى هيئة الحكومة الرقمية عبر منصة "رقمي".', NULL, NULL, NULL, NULL, 2, '/d2a77bfc-3828-4697-8f64-c837e89ff585/ab80a93b-c219-43bb-aaea-5700eee62ef2/5fa62909-d1ff-4c45-b45a-d8e7eba23937/03827c4e-7137-4fbe-959c-3a69980bfcc0/', 3, true, true, 1.00, NULL, NULL, '2026-04-11 04:22:32.672714+00', '2026-04-11 04:28:58.613793+00', NULL, NULL, '2) لا يتطلب إرفاق مستند إثبات، وسيتم التحقق داخليًا من منصة "رقمي".', '2) No proof document required. Internal verification from ''Raqmi'' platform.', NULL, NULL, NULL);
INSERT INTO public.framework_nodes (id, framework_id, parent_id, node_type, reference_code, name, name_ar, description, description_ar, guidance, guidance_ar, sort_order, path, depth, is_active, is_assessable, weight, max_score, metadata_json, created_at, updated_at, maturity_level, evidence_type, acceptance_criteria, acceptance_criteria_en, spec_references, priority, assessment_type) VALUES ('cc7ecc08-c79c-4d8f-a6bb-33c95996e81c', 'b2c124a4-92e9-4fae-bf22-ad5424209b6b', 'f61c646a-643b-4da6-a61d-32f767440649', 'Requirement', 'S5.15.3.R2', '2) The entity uses a unified domain and may not reserve multiple domains without DGA-approved justification.', '2) التزام الجهة باستعمال نطاق موحد ولا يسمح للجهة بحجز نطاقات متعددة إلا عند وجود مبررات وافقت عليها هيئة الحكومة الرقمية.', NULL, NULL, NULL, NULL, 2, '/d2a77bfc-3828-4697-8f64-c837e89ff585/ab80a93b-c219-43bb-aaea-5700eee62ef2/f61c646a-643b-4da6-a61d-32f767440649/cc7ecc08-c79c-4d8f-a6bb-33c95996e81c/', 3, true, true, 1.00, NULL, NULL, '2026-04-11 04:22:32.766394+00', '2026-04-11 04:28:58.70783+00', NULL, NULL, '2) لا يتطلب إرفاق مستند إثبات، وسيتم التحقق داخليًا من عدد نطاقات الجهة.', '2) No proof document required. Internal verification of entity domain count.', NULL, NULL, NULL);
INSERT INTO public.framework_nodes (id, framework_id, parent_id, node_type, reference_code, name, name_ar, description, description_ar, guidance, guidance_ar, sort_order, path, depth, is_active, is_assessable, weight, max_score, metadata_json, created_at, updated_at, maturity_level, evidence_type, acceptance_criteria, acceptance_criteria_en, spec_references, priority, assessment_type) VALUES ('70c1e4a8-9713-4694-928b-99cebad7ccef', 'b2c124a4-92e9-4fae-bf22-ad5424209b6b', 'bb206aae-4d83-494b-bb48-2d4ae3111473', 'Standard', 'S5.14.4', 'Activating Digital Trust Services', 'تفعيل خدمات الثقة الرقمية', NULL, NULL, NULL, NULL, 4, '/d2a77bfc-3828-4697-8f64-c837e89ff585/bb206aae-4d83-494b-bb48-2d4ae3111473/70c1e4a8-9713-4694-928b-99cebad7ccef/', 2, true, false, NULL, NULL, NULL, '2026-04-11 04:22:32.605097+00', '2026-04-11 04:22:32.605101+00', NULL, NULL, NULL, NULL, NULL, NULL, NULL);
INSERT INTO public.framework_nodes (id, framework_id, parent_id, node_type, reference_code, name, name_ar, description, description_ar, guidance, guidance_ar, sort_order, path, depth, is_active, is_assessable, weight, max_score, metadata_json, created_at, updated_at, maturity_level, evidence_type, acceptance_criteria, acceptance_criteria_en, spec_references, priority, assessment_type) VALUES ('af3085d8-dafb-4e0d-913c-cda6179edbaa', 'b2c124a4-92e9-4fae-bf22-ad5424209b6b', 'dc4961c3-5fd7-4482-ab8a-154b66a72182', 'Requirement', 'S5.16.2.R2', '2) Develop real-time monitoring dashboards for specified indicators and grant product/application managers monitoring permissions.', '2) تطوير شاشات المراقبة اللحظية للمؤشرات المحددة، وإعطاء الصلاحية لمديري المنتجات/ التطبيقات للمراقبة اللحظية.', NULL, NULL, NULL, NULL, 2, '/66dd45a8-6ec9-4d82-9d56-a83c75b23a47/b076a4bd-224c-404e-8487-79c076b10168/dc4961c3-5fd7-4482-ab8a-154b66a72182/af3085d8-dafb-4e0d-913c-cda6179edbaa/', 3, true, true, 1.00, NULL, NULL, '2026-04-11 04:22:32.85111+00', '2026-04-11 04:28:58.782124+00', NULL, NULL, '2) إرفاق (5) عينات حديثة من شاشات المراقبة اللحظية للمؤشرات المحددة، وتوضيح صلاحيات استخدامها.', '2) Attach (5) recent real-time monitoring dashboard samples and explain usage permissions.', NULL, NULL, NULL);
INSERT INTO public.framework_nodes (id, framework_id, parent_id, node_type, reference_code, name, name_ar, description, description_ar, guidance, guidance_ar, sort_order, path, depth, is_active, is_assessable, weight, max_score, metadata_json, created_at, updated_at, maturity_level, evidence_type, acceptance_criteria, acceptance_criteria_en, spec_references, priority, assessment_type) VALUES ('58203c61-cb1d-49a2-9ad2-c678c3e77d5f', 'b2c124a4-92e9-4fae-bf22-ad5424209b6b', 'f2ee62f3-cd28-4c37-91a9-b2f18b285290', 'Requirement', 'S5.16.3.R2', '2) Link reports and corrective actions with infrastructure management practices per approved governance framework.', '2) ربط التقارير والأعمال التصحيحية بممارسات إدارة البنية التحتية وفقًا لإطار الحوكمة المعتمد.', NULL, NULL, NULL, NULL, 2, '/66dd45a8-6ec9-4d82-9d56-a83c75b23a47/b076a4bd-224c-404e-8487-79c076b10168/f2ee62f3-cd28-4c37-91a9-b2f18b285290/58203c61-cb1d-49a2-9ad2-c678c3e77d5f/', 3, true, true, 1.00, NULL, NULL, '2026-04-11 04:22:32.892645+00', '2026-04-11 04:28:58.828955+00', NULL, NULL, '2) إرفاق (3) عينات من القرارات التصحيحية المشتركة بين إدارة جودة الخدمات الرقمية والإدارات الأخرى.', '2) Attach (3) joint corrective decision samples between digital service quality management and other departments.', NULL, NULL, NULL);
