INSERT INTO public.framework_nodes (id, framework_id, parent_id, node_type, reference_code, name, name_ar, description, description_ar, guidance, guidance_ar, sort_order, path, depth, is_active, is_assessable, weight, max_score, metadata_json, created_at, updated_at, maturity_level, evidence_type, acceptance_criteria, acceptance_criteria_en, spec_references, priority, assessment_type) VALUES ('51714e4b-8ba1-4a43-99ae-22f803a248df', 'b2c124a4-92e9-4fae-bf22-ad5424209b6b', 'a9e14340-e494-47bc-99e5-649a061193aa', 'Requirement', 'S5.18.4.R2', '2) Issue automated reports from interactive digital tools showing service delivery percentages, service counts, completion rates, and response times.', '2) إصدار تقارير آلية من الأدوات الرقمية التفاعلية، توضح نسبة تقديم الخدمات للمستفيدين عبر هذه
INSERT INTO public.framework_nodes (id, framework_id, parent_id, node_type, reference_code, name, name_ar, description, description_ar, guidance, guidance_ar, sort_order, path, depth, is_active, is_assessable, weight, max_score, metadata_json, created_at, updated_at, maturity_level, evidence_type, acceptance_criteria, acceptance_criteria_en, spec_references, priority, assessment_type) VALUES ('17cec701-628b-4d1d-9aa4-9374b5a45dc8', 'b2c124a4-92e9-4fae-bf22-ad5424209b6b', '87f166cd-1dd4-4f01-8d02-033e5709b821', 'Requirement', 'S5.20.4.R3', '3) Comparisons based on approved beneficiary experience measurement KPIs.', '3) المقارنات وفقًا لمؤشرات أداء قياس تجربة المستفيد المعتمدة للخدمات المحسنة قبل وبعد التحسين.', NULL, NULL, NULL, NULL, 3, '/f8a69d5b-caeb-4dbd-b746-b483f0570fb4/355108bd-50ab-461c-81a7-0169b4c985f0/87f166cd-1dd4-4f01-8d02-033e5709b821/17cec701-628b-4d1d-9aa4-9374b5a45dc8/', 3, true, true, 1.00, NULL, NULL, '2026-04-11 04:22:33.685716+00', '2026-04-11 04:28:59.393297+00', NULL, NULL, '3) إرفاق التقارير الحديثة التي توضح المقارنات للخدمات المحسنة قبل وبعد التحسين وفقًا لمؤشرات أداء قياس تجربة المستفيد المعتمدة.', '3) Attach recent reports showing comparisons for improved services.', NULL, NULL, NULL);
INSERT INTO public.framework_nodes (id, framework_id, parent_id, node_type, reference_code, name, name_ar, description, description_ar, guidance, guidance_ar, sort_order, path, depth, is_active, is_assessable, weight, max_score, metadata_json, created_at, updated_at, maturity_level, evidence_type, acceptance_criteria, acceptance_criteria_en, spec_references, priority, assessment_type) VALUES ('bc308ff3-4e65-4a93-904c-0915cbb6e171', 'b2c124a4-92e9-4fae-bf22-ad5424209b6b', 'b4e07417-e60e-4856-8ecd-3fc98ef72657', 'Requirement', 'S5.19.3.R2', '2) Conduct joint marketing campaigns with linked government entities, included in beneficiary relationship programs.', '2) القيام بحمالت تسويقية مشتركة مع الجهات الحكومية المرتبطة معها في الخدمات التي تقدمها، وتضمين هذه األنشطة ضمن برامج تعزيز العالقة مع المستفيد.', NULL, NULL, NULL, NULL, 2, '/f8a69d5b-caeb-4dbd-b746-b483f0570fb4/8a2b7c88-b8b5-45ab-aa1c-4f9fc2edc596/b4e07417-e60e-4856-8ecd-3fc98ef72657/bc308ff3-4e65-4a93-904c-0915cbb6e171/', 3, true, true, 1.00, NULL, NULL, '2026-04-11 04:22:33.566155+00', '2026-04-11 04:28:59.32768+00', NULL, NULL, '2) إرفاق الوثائق الحديثة والعينات الكافية من التقارير ومحاضر االجتماعات والقرارات التي تثبت أن الجهة قامت بحمالت تسويقية مشتركة مع الجهات الحكومية المرتبطة معها في الخدمات التي تقدمها.', '2) Attach recent documents, reports, meeting minutes, and decisions proving joint marketing campaigns.', NULL, NULL, NULL);
INSERT INTO public.framework_nodes (id, framework_id, parent_id, node_type, reference_code, name, name_ar, description, description_ar, guidance, guidance_ar, sort_order, path, depth, is_active, is_assessable, weight, max_score, metadata_json, created_at, updated_at, maturity_level, evidence_type, acceptance_criteria, acceptance_criteria_en, spec_references, priority, assessment_type) VALUES ('29c53adb-962b-4043-9492-67d9b3bffbb0', 'b2c124a4-92e9-4fae-bf22-ad5424209b6b', '6fc8962a-054f-4b1b-9f6c-a3680c520209', 'Requirement', 'S5.10.4.R3', '3) Review recovery strategies at least annually or upon material change.', '3) مراجعة إستراتيجيات التعافي بشكل سنوي على الأقل، أو عند حدوث تغيير جوهري للأهداف التشغيلية أو الإستراتيجية لدى الجهة.', NULL, NULL, NULL, NULL, 3, '/1da7ecaf-95c5-4402-aa7b-f34786019aa6/1f95de6d-8d99-409f-bf82-49fde52aa796/6fc8962a-054f-4b1b-9f6c-a3680c520209/29c53adb-962b-4043-9492-67d9b3bffbb0/', 3, true, true, 1.00, NULL, NULL, '2026-04-11 04:22:31.346473+00', '2026-04-11 04:28:57.595204+00', NULL, NULL, '3) إرفاق ما يثبت مراجعة الإستراتيجيات المعتمدة لدى الجهة.', '3) Attach proof of reviewing the entity''s approved strategies.', NULL, NULL, NULL);
INSERT INTO public.framework_nodes (id, framework_id, parent_id, node_type, reference_code, name, name_ar, description, description_ar, guidance, guidance_ar, sort_order, path, depth, is_active, is_assessable, weight, max_score, metadata_json, created_at, updated_at, maturity_level, evidence_type, acceptance_criteria, acceptance_criteria_en, spec_references, priority, assessment_type) VALUES ('31c26dc4-a48f-46d3-9f83-2ece9dd26fa7', 'b2c124a4-92e9-4fae-bf22-ad5424209b6b', '68c4b895-b3bd-42fd-9b0e-55998dd44766', 'Requirement', 'S5.20.5.R2', '2) Map current and future state for priority journeys aligned with approved inventory, clarifying beneficiary touchpoints.', '2) رسم الوضع الراهن والمستقبلي للرحالت ذات األولوية بما يتوافق مع الحصر المعتمد، وتوضيح نقاط اتصال المستفيد، والذي يشمل الخدمات واإلجراءات المقدمة من الجهات المالكة لها.', NULL, NULL, NULL, NULL, 2, '/f8a69d5b-caeb-4dbd-b746-b483f0570fb4/355108bd-50ab-461c-81a7-0169b4c985f0/68c4b895-b3bd-42fd-9b0e-55998dd44766/31c26dc4-a48f-46d3-9f83-2ece9dd26fa7/', 3, true, true, 1.00, NULL, NULL, '2026-04-11 04:22:33.71426+00', '2026-04-11 04:28:59.408638+00', NULL, NULL, '2) إرفاق نموذج رسم الوضع الراهن والمستهدف المعتمد لرحالت الحياة، وفق متطلبات تطبيق هذا المعيار.', '2) Attach the approved current and target state mapping model for life journeys per this standard''s requirements.', NULL, NULL, NULL);
