INSERT INTO public.framework_nodes (id, framework_id, parent_id, node_type, reference_code, name, name_ar, description, description_ar, guidance, guidance_ar, sort_order, path, depth, is_active, is_assessable, weight, max_score, metadata_json, created_at, updated_at, maturity_level, evidence_type, acceptance_criteria, acceptance_criteria_en, spec_references, priority, assessment_type) VALUES ('ada4c51f-dcc7-4f9f-8560-3499df609870', 'b2c124a4-92e9-4fae-bf22-ad5424209b6b', 'e533e340-c7fa-4d6e-816a-a753b0d94de6', 'Requirement', 'S5.3.4.R3', '3) Prepare a periodic report by the enterprise architecture organizational unit.', '3) إعداد تقرير دوري من قِبل الوحدة التنظيمية المسؤولة عن البنية المؤسسية يوضح النتائج المرتبطة بكفاءة الإنفاق والاستدامة المالية والتقنية للجهة.', NULL, NULL, NULL, NULL, 3, '/633ea9b9-b470-4be6-94c9-362bfd768aba/4fe1ba35-8844-4f32-9cb5-7cd7255464bd/e533e340-c7fa-4d6e-816a-a753b0d94de6/ada4c51f-dcc7-4f9f-8560-3499df609870/', 3, true, true, 1.00, NULL, NULL, '2026-04-11 04:22:30.029199+00', '2026-04-11 04:28:56.67388+00', NULL, NULL, 'تقرير دوري من قِبل الوحدة التنظيمية المسؤولة عن البنية المؤسسية، يوضح نتائج قياس الأثر من تطبيق ممارسة البنية المؤسسية، وفق متطلبات تطبيق هذا المعيار.', 'Periodic report by the EA organizational unit per this standard''s requirements.', NULL, NULL, NULL);
