INSERT INTO public.framework_nodes (id, framework_id, parent_id, node_type, reference_code, name, name_ar, description, description_ar, guidance, guidance_ar, sort_order, path, depth, is_active, is_assessable, weight, max_score, metadata_json, created_at, updated_at, maturity_level, evidence_type, acceptance_criteria, acceptance_criteria_en, spec_references, priority, assessment_type) VALUES ('a188e46d-189a-4664-b1c3-e74e87ed0935', 'b2c124a4-92e9-4fae-bf22-ad5424209b6b', '43402acd-9f1a-4c85-9f5c-b6e3a25f077e', 'Requirement', 'S5.13.1.R4', '4) Form a cloud computing unit governance committee and clarify its working mechanism.', '4) تشكيل لجنة حوكمة وحدة الحوسبة السحابية وتوضيح آلية عملها في إدارة وتفعيل أعمال تبني الحوسبة السحابية بما يشمل مراجعة واعتماد خطط التحول السحابى، إقرار سياسات الحوكمة السحابية، تقييم الأداء الدوري لأعمال ومهام التبني السحابي.', NULL, NULL, NULL, NULL, 4, '/eaa87d00-46fc-440d-b0af-6fb89269407c/3bbdd786-9e2b-4b93-a20b-cc6dd282e49c/43402acd-9f1a-4c85-9f5c-b6e3a25f077e/a188e46d-189a-4664-b1c3-e74e87ed0935/', 3, true, true, 1.00, NULL, NULL, '2026-04-11 04:22:32.174289+00', '2026-04-11 04:28:58.250387+00', NULL, NULL, '4) إرفاق قرار معتمد لتشكيل لجنة حوكمة وحدة الحوسبة السحابية وآلية عملها وفق متطلبات تطبيق هذا المعيار.', '4) Attach approved governance committee formation decision.', NULL, NULL, NULL);
INSERT INTO public.framework_nodes (id, framework_id, parent_id, node_type, reference_code, name, name_ar, description, description_ar, guidance, guidance_ar, sort_order, path, depth, is_active, is_assessable, weight, max_score, metadata_json, created_at, updated_at, maturity_level, evidence_type, acceptance_criteria, acceptance_criteria_en, spec_references, priority, assessment_type) VALUES ('4fa0867c-4e97-4190-a2f7-a16532f59636', 'b2c124a4-92e9-4fae-bf22-ad5424209b6b', '9a506447-12c0-457f-8633-0bd9d2ad9691', 'Requirement', 'S5.16.4.R4', '4) Make priority services available on all possible channels leveraging modern technologies.', '4) إتاحة الخدمة ذات الأولوية على جميع القنوات الممكنة وتوظيف التقنيات الناشئة قدر الإمكان في تقديم الخدمة.', NULL, NULL, NULL, NULL, 4, '/66dd45a8-6ec9-4d82-9d56-a83c75b23a47/b076a4bd-224c-404e-8487-79c076b10168/9a506447-12c0-457f-8633-0bd9d2ad9691/4fa0867c-4e97-4190-a2f7-a16532f59636/', 3, true, true, 1.00, NULL, NULL, '2026-04-11 04:22:32.948907+00', '2026-04-11 04:28:58.898932+00', NULL, NULL, '4) إرفاق عينة حديثة لكل خدمة من الخدمات ذات الأولوية توضح الإتاحة على جميع القنوات الممكنة، وتوظيف التقنيات الناشئة قدر الإمكان في تقديم الخدمة.', '4) Attach recent samples per priority service showing channel availability and technology usage.', NULL, NULL, NULL);
