INSERT INTO public.framework_nodes (id, framework_id, parent_id, node_type, reference_code, name, name_ar, description, description_ar, guidance, guidance_ar, sort_order, path, depth, is_active, is_assessable, weight, max_score, metadata_json, created_at, updated_at, maturity_level, evidence_type, acceptance_criteria, acceptance_criteria_en, spec_references, priority, assessment_type) VALUES ('77b38744-c06d-44cd-8355-59ac0fbf1084', 'b2c124a4-92e9-4fae-bf22-ad5424209b6b', 'b34f422e-8b5f-4a0d-8d55-078e67245c3c', 'Requirement', 'S5.4.2.R4', '4) Prepare periodic reports on awareness activities and events executed for digital transformation adoption.', '4) إعداد تقارير دورية عن الأنشطة والفعاليات المنفذة، لزيادة الوعي ومتابعتها من قِبل لجنة التعاملات الإلكترونية الحكومية -لجنة التحول الرقمي- في الجهة أو من ينوب عنهم من لجان أخرى، واتخاذ الإجراءات التصحيحية.', NULL, NULL, NULL, NULL, 4, '/5530232e-d754-4d10-a280-2f2cc285340d/56b7daaf-c5b7-4054-9c1c-ba55a211577c/b34f422e-8b5f-4a0d-8d55-078e67245c3c/77b38744-c06d-44cd-8355-59ac0fbf1084/', 3, true, true, 1.00, NULL, NULL, '2026-04-11 04:22:30.127333+00', '2026-04-11 04:28:56.738768+00', NULL, NULL, 'إرفاق عينات حديثة من تقارير الإنجاز ومحاضر اللجان والقرارات التصحيحية المتعلقة ببرامج رفع الوعي بالتحول الرقمي، وفق متطلبات تطبيق هذا المعيار.', 'Attach recent achievement reports, committee minutes, and decisions.', NULL, NULL, NULL);
