INSERT INTO public.framework_nodes (id, framework_id, parent_id, node_type, reference_code, name, name_ar, description, description_ar, guidance, guidance_ar, sort_order, path, depth, is_active, is_assessable, weight, max_score, metadata_json, created_at, updated_at, maturity_level, evidence_type, acceptance_criteria, acceptance_criteria_en, spec_references, priority, assessment_type) VALUES ('d855b13d-1950-4bf1-b640-be8d3551f5e7', 'b2c124a4-92e9-4fae-bf22-ad5424209b6b', '7504c7bb-ab66-4cd3-996d-7e48886981cc', 'Requirement', 'S5.17.2.R4', '3) Prepare a comprehensive service guide on the entity''s platform with clear, detailed information.', '3) إعداد دليل شامل للخدمات على منصة الجهة، يقدم معلومات واضحة حول الخدمات الرقمية بحيث تتواءم مع كافة الحقول المطلوبة فى النسيج الرقمى، مع مراعاة توفير المحتوى باللغتين العربية والإنجليزية، واعتماد مسميات واضحة وذات معنى للخدمات، دون استخدام الاختصارات التقنية أو العلامات التجارية أو الأسماء التسويقية.', NULL, NULL, NULL, NULL, 4, '/66dd45a8-6ec9-4d82-9d56-a83c75b23a47/fbd949a4-48e1-44f2-851a-3243efed765b/7504c7bb-ab66-4cd3-996d-7e48886981cc/d855b13d-1950-4bf1-b640-be8d3551f5e7/', 3, true, true, 1.00, NULL, NULL, '2026-04-11 04:22:33.043178+00', '2026-04-11 04:28:58.977573+00', NULL, NULL, '3) إرفاق الرابط الإلكترونى لدليل الخدمات الشامل (service catalogue) وفق متطلبات تطبيق هذا المعيار.', '3) Attach the electronic link for the comprehensive service guide (service catalog).', NULL, NULL, NULL);
INSERT INTO public.framework_nodes (id, framework_id, parent_id, node_type, reference_code, name, name_ar, description, description_ar, guidance, guidance_ar, sort_order, path, depth, is_active, is_assessable, weight, max_score, metadata_json, created_at, updated_at, maturity_level, evidence_type, acceptance_criteria, acceptance_criteria_en, spec_references, priority, assessment_type) VALUES ('a2fd3d01-1bfd-4b12-b721-2349ab1bc620', 'b2c124a4-92e9-4fae-bf22-ad5424209b6b', '408341a3-484a-4e39-ad18-0d1c95689892', 'Requirement', 'S5.12.2.R4', '4) Monitor and measure internal SLA effectiveness and continuously evaluate and improve.', '4) متابعة فعالية اتفاقيات مستوى الخدمة الداخلية وقياسها وتقييمها بشكل دوري (سنوياً على الأقل).', NULL, NULL, NULL, NULL, 4, '/eaa87d00-46fc-440d-b0af-6fb89269407c/7288b767-2e63-43e6-9f39-6e1abb5e45eb/408341a3-484a-4e39-ad18-0d1c95689892/a2fd3d01-1bfd-4b12-b721-2349ab1bc620/', 3, true, true, 1.00, NULL, NULL, '2026-04-11 04:22:31.928875+00', '2026-04-11 04:28:58.061691+00', NULL, NULL, '4) إرفاق ما يثبت متابعة اتفاقيات مستوى الخدمة الداخلية وقياسها وتقييمها بشكل دوري.', '4) Attach proof of monitoring and measuring internal SLAs and continuous evaluation.', NULL, NULL, NULL);
