INSERT INTO public.framework_nodes (id, framework_id, parent_id, node_type, reference_code, name, name_ar, description, description_ar, guidance, guidance_ar, sort_order, path, depth, is_active, is_assessable, weight, max_score, metadata_json, created_at, updated_at, maturity_level, evidence_type, acceptance_criteria, acceptance_criteria_en, spec_references, priority, assessment_type) VALUES ('23198d54-6262-476f-b823-1cc4b90871f0', 'b2c124a4-92e9-4fae-bf22-ad5424209b6b', 'a4cfa6f9-5f2d-41bb-a8f1-11a751df6ac6', 'Requirement', 'S5.3.1.R4', '4) Define enterprise architecture unit services and build a service directory.', '4) تحديد خدمات الوحدة التنظيمية للبنية المؤسسية، وبناء دليل إجراءات عمل ممارسة البنية المؤسسية.', NULL, NULL, NULL, NULL, 4, '/633ea9b9-b470-4be6-94c9-362bfd768aba/4fe1ba35-8844-4f32-9cb5-7cd7255464bd/a4cfa6f9-5f2d-41bb-a8f1-11a751df6ac6/23198d54-6262-476f-b823-1cc4b90871f0/', 3, true, true, 1.00, NULL, NULL, '2026-04-11 04:22:29.80469+00', '2026-04-11 04:28:56.483746+00', NULL, NULL, 'وثيقة معتمدة لإجراءات وخدمات البنية المؤسسية.', 'Approved document for enterprise architecture procedures and services.', NULL, NULL, NULL);
INSERT INTO public.framework_nodes (id, framework_id, parent_id, node_type, reference_code, name, name_ar, description, description_ar, guidance, guidance_ar, sort_order, path, depth, is_active, is_assessable, weight, max_score, metadata_json, created_at, updated_at, maturity_level, evidence_type, acceptance_criteria, acceptance_criteria_en, spec_references, priority, assessment_type) VALUES ('c83f3d10-971a-4ac3-93c9-0e202692e302', 'b2c124a4-92e9-4fae-bf22-ad5424209b6b', 'd7148143-0459-4d92-8016-76a0669cb240', 'Requirement', 'S5.2.2.R4', '4) Issue corrective decisions and actions based on periodic report results.', '4)إصدار قرارات وإجراءات تصحيحية بناءً على نتائج التقارير الدورية والحوكمة.', NULL, NULL, NULL, NULL, 4, '/633ea9b9-b470-4be6-94c9-362bfd768aba/b7320dd0-fc03-4ffc-a2e1-8c624b165952/d7148143-0459-4d92-8016-76a0669cb240/c83f3d10-971a-4ac3-93c9-0e202692e302/', 3, true, true, 1.00, NULL, NULL, '2026-04-11 04:22:29.684809+00', '2026-04-11 04:28:56.393856+00', NULL, NULL, '(3) عينات حديثة من القرارات والإجراءات التصحيحية.', '(3) recent corrective decision and action samples.', NULL, NULL, NULL);
INSERT INTO public.framework_nodes (id, framework_id, parent_id, node_type, reference_code, name, name_ar, description, description_ar, guidance, guidance_ar, sort_order, path, depth, is_active, is_assessable, weight, max_score, metadata_json, created_at, updated_at, maturity_level, evidence_type, acceptance_criteria, acceptance_criteria_en, spec_references, priority, assessment_type) VALUES ('e124b91d-4310-4f5e-8414-0593542031e3', 'b2c124a4-92e9-4fae-bf22-ad5424209b6b', '9c0fff37-30c9-4aef-917f-166e5a2683db', 'Requirement', 'S5.14.3.R4', '2) Continuously monitor new systems and services to ensure they meet requirements.', '2) المتابعة المستمرة للأنظمة والخدمات الجديدة للتأكّد من أنّ البنية التحتية وجميع الخدمات المرتبطة بالأنظمة والخدمات المشتركة مبنية بما يضمن استمرارية تشغيلها.', NULL, NULL, NULL, NULL, 4, '/d2a77bfc-3828-4697-8f64-c837e89ff585/bb206aae-4d83-494b-bb48-2d4ae3111473/9c0fff37-30c9-4aef-917f-166e5a2683db/e124b91d-4310-4f5e-8414-0593542031e3/', 3, true, true, 1.00, NULL, NULL, '2026-04-11 04:22:32.532828+00', '2026-04-11 04:28:58.507555+00', NULL, NULL, '2) إرفاق التقارير التى توضح المتابعة المستمرة للأنظمة والخدمات الجديدة وفق متطلبات تطبيق هذا المعیار.', '2) Attach reports showing continuous monitoring of new systems and services.', NULL, NULL, NULL);
INSERT INTO public.framework_nodes (id, framework_id, parent_id, node_type, reference_code, name, name_ar, description, description_ar, guidance, guidance_ar, sort_order, path, depth, is_active, is_assessable, weight, max_score, metadata_json, created_at, updated_at, maturity_level, evidence_type, acceptance_criteria, acceptance_criteria_en, spec_references, priority, assessment_type) VALUES ('3afdbba8-a0b9-48e9-91bd-94f2d0667511', 'b2c124a4-92e9-4fae-bf22-ad5424209b6b', 'b2263ae9-da7e-4f37-ba07-e6039ffd812e', 'Requirement', 'S5.12.4.R4', '12) Publish (100%) of deposited software on the government software repository.', '12) نشر (100%) من البرمجيات المودعة فى منصة مستودع البرمجيات الحكومية، بما يتوافق مع متطلبات
INSERT INTO public.framework_nodes (id, framework_id, parent_id, node_type, reference_code, name, name_ar, description, description_ar, guidance, guidance_ar, sort_order, path, depth, is_active, is_assessable, weight, max_score, metadata_json, created_at, updated_at, maturity_level, evidence_type, acceptance_criteria, acceptance_criteria_en, spec_references, priority, assessment_type) VALUES ('c5b51462-7c46-44d1-81bd-4e506bc442c3', 'b2c124a4-92e9-4fae-bf22-ad5424209b6b', 'a551835a-dc19-4d88-9517-9305ef6a413e', 'Requirement', 'S5.14.2.R4', '3) Activate the shared electronic payment service technical resource.', '3) تفعيل المورد التقني المشترك لخدمة الدفع الإلكتروني المقدَّمة من وزارة المالية في جميع المنصات والتطبيقات الحكومية التى تقدم خدمات رقمية تتطلب دفع مقابل مالى أو رسوم لتنفيذ الخدمة، وتمكين الدفع بالبطاقات البنكية من منصات الجهة الحكومية مباشرة.', NULL, NULL, NULL, NULL, 4, '/d2a77bfc-3828-4697-8f64-c837e89ff585/bb206aae-4d83-494b-bb48-2d4ae3111473/a551835a-dc19-4d88-9517-9305ef6a413e/c5b51462-7c46-44d1-81bd-4e506bc442c3/', 3, true, true, 1.00, NULL, NULL, '2026-04-11 04:22:32.436332+00', '2026-04-11 04:28:58.42341+00', NULL, NULL, '3) لا يتطلب إرفاق مستند إثبات، وسيتم التحقق داخليا من تفعيل خدمة الدفع الإلكتروني للخدمات الرقمية المقدَّمة للمستفیدین.', '3) No proof document required. Internal verification of electronic payment service activation.', NULL, NULL, NULL);
INSERT INTO public.framework_nodes (id, framework_id, parent_id, node_type, reference_code, name, name_ar, description, description_ar, guidance, guidance_ar, sort_order, path, depth, is_active, is_assessable, weight, max_score, metadata_json, created_at, updated_at, maturity_level, evidence_type, acceptance_criteria, acceptance_criteria_en, spec_references, priority, assessment_type) VALUES ('fdd04bb0-6fb8-416a-bf00-4e0080798872', 'b2c124a4-92e9-4fae-bf22-ad5424209b6b', '8d81109d-42fa-450f-a1a0-fe3f4dd978f6', 'Requirement', 'S5.17.5.R4', '4) Include beneficiary care centers as service delivery channels integrated with entity systems.', '4) تضمين مراكز رعاية المستفيدين كقنوات تقديم الخدمة وربطها بنظم إدارة علاقات المستفيدين.', NULL, NULL, NULL, NULL, 4, '/66dd45a8-6ec9-4d82-9d56-a83c75b23a47/fbd949a4-48e1-44f2-851a-3243efed765b/8d81109d-42fa-450f-a1a0-fe3f4dd978f6/fdd04bb0-6fb8-416a-bf00-4e0080798872/', 3, true, true, 1.00, NULL, NULL, '2026-04-11 04:22:33.203789+00', '2026-04-11 04:28:59.115478+00', NULL, NULL, '4) إرفاق العينات الكافية التي توضح عملية الربط والتكامل بين مراكز رعاية المستفيدين ونظم إدارة علاقات المستفيدين.', '4) Attach sufficient samples showing integration between beneficiary care centers and entity systems.', NULL, NULL, NULL);
INSERT INTO public.framework_nodes (id, framework_id, parent_id, node_type, reference_code, name, name_ar, description, description_ar, guidance, guidance_ar, sort_order, path, depth, is_active, is_assessable, weight, max_score, metadata_json, created_at, updated_at, maturity_level, evidence_type, acceptance_criteria, acceptance_criteria_en, spec_references, priority, assessment_type) VALUES ('190edb90-04de-4a58-9cad-f773e79d6907', 'b2c124a4-92e9-4fae-bf22-ad5424209b6b', 'b8d1c09a-100e-4bc7-ac17-d7067ee507a0', 'Requirement', 'S5.3.2.R4', '4) Document enterprise architecture viewpoints of various types (list, matrix, diagram).', '4) توثيق مناظير البنية المؤسسية بأنواعها المختلفة (قائمة، مصفوفة، رسم مرئي) بحيث تغطي هذه المناظير مختلف مجالات البنية المؤسسية وفقاً للنموذج العام من خلال تحليل احتياجات أصحاب العلاقة، وتحديد الهدف من المنظور، ومستوى التفصيل.', NULL, NULL, NULL, NULL, 4, '/633ea9b9-b470-4be6-94c9-362bfd768aba/4fe1ba35-8844-4f32-9cb5-7cd7255464bd/b8d1c09a-100e-4bc7-ac17-d7067ee507a0/190edb90-04de-4a58-9cad-f773e79d6907/', 3, true, true, 1.00, NULL, NULL, '2026-04-11 04:22:29.880664+00', '2026-04-11 04:28:56.543876+00', NULL, NULL, 'وثيقة مناظير البنية المؤسسية.', 'Enterprise architecture viewpoints document.', NULL, NULL, NULL);
INSERT INTO public.framework_nodes (id, framework_id, parent_id, node_type, reference_code, name, name_ar, description, description_ar, guidance, guidance_ar, sort_order, path, depth, is_active, is_assessable, weight, max_score, metadata_json, created_at, updated_at, maturity_level, evidence_type, acceptance_criteria, acceptance_criteria_en, spec_references, priority, assessment_type) VALUES ('b93d743b-1200-4c10-8f3c-9e9d63eadffa', 'b2c124a4-92e9-4fae-bf22-ad5424209b6b', 'f6156b29-9ce5-403b-84cf-78b6ae3a50a4', 'Requirement', 'S5.8.3.R4', '4) Obtain exemption from the Government Procurement and Competition Law.', '4) الحصول على الاستثناء من نظام المنافسات والمشتريات الحكومية.', NULL, NULL, NULL, NULL, 4, '/67c04d75-3ce8-4615-9784-464e399ce0cb/3059ba0d-feee-46b8-9640-bf112a65f1d6/f6156b29-9ce5-403b-84cf-78b6ae3a50a4/b93d743b-1200-4c10-8f3c-9e9d63eadffa/', 3, true, true, 1.00, NULL, NULL, '2026-04-11 04:22:30.673703+00', '2026-04-11 04:28:57.070211+00', NULL, NULL, '4) إرفاق ما يثبت الموافقة على الاستثناء من نظام المنافسات والمشتريات الحكومية.', '4) Attach proof of exemption approval from the Government Procurement Law.', NULL, NULL, NULL);
INSERT INTO public.framework_nodes (id, framework_id, parent_id, node_type, reference_code, name, name_ar, description, description_ar, guidance, guidance_ar, sort_order, path, depth, is_active, is_assessable, weight, max_score, metadata_json, created_at, updated_at, maturity_level, evidence_type, acceptance_criteria, acceptance_criteria_en, spec_references, priority, assessment_type) VALUES ('9b778556-769e-4115-9cb0-e7b9d3c749dd', 'b2c124a4-92e9-4fae-bf22-ad5424209b6b', '76d34117-74cf-49ae-8b2b-f763e8359722', 'Requirement', 'S5.7.4.R4', '4) Issue periodic reports showing automated process success rates.', '4) إصدار تقارير دورية توضح نسب نجاح العمليات والإجراءات المؤتمتة جزئيًّا أو كليًّا للتعرف على مستويات التقدم فى أتمتة العمليات والإجراءات.', NULL, NULL, NULL, NULL, 4, '/67c04d75-3ce8-4615-9784-464e399ce0cb/29e6d76c-cfb0-4d11-853e-f87ce2cc6297/76d34117-74cf-49ae-8b2b-f763e8359722/9b778556-769e-4115-9cb0-e7b9d3c749dd/', 3, true, true, 1.00, NULL, NULL, '2026-04-11 04:22:30.538615+00', '2026-04-11 04:28:56.971109+00', NULL, NULL, '4) إرفاق (3) عينات من تقارير المراقبة الدورية التى تتابع نسب نجاح العمليات والإجراءات المؤتمتة.', '4) Attach (3) periodic monitoring report samples tracking automated process success rates.', NULL, NULL, NULL);
INSERT INTO public.framework_nodes (id, framework_id, parent_id, node_type, reference_code, name, name_ar, description, description_ar, guidance, guidance_ar, sort_order, path, depth, is_active, is_assessable, weight, max_score, metadata_json, created_at, updated_at, maturity_level, evidence_type, acceptance_criteria, acceptance_criteria_en, spec_references, priority, assessment_type) VALUES ('47dd2abe-64ca-4ca9-8cec-391bbf01d97e', 'b2c124a4-92e9-4fae-bf22-ad5424209b6b', 'bb725532-459b-4355-931e-868d2a523768', 'Requirement', 'S5.9.5.R5', '5) Prepare the due diligence template in coordination with relevant departments.', '5) إعداد نموذج الفحص النافي للجهالة بالتنسيق مع الإدارات ذات الصلة داخل الجهة وتوقيعه من الشركات المزمع التعاقد معها بصورة مباشرة أو غير مباشرة لتقديم خدمات تقنية المعلومات وتحديثه بشكل سنوي، بحيث تشمل البيانات التعريفية بالشركة، الهيكل الإداري والملكية، بيانات الاتصال وبما يتوافق مع ضوابط حوكمة تقنية المعلومات الصادرة عن الهيئة.', NULL, NULL, NULL, NULL, 5, '/1da7ecaf-95c5-4402-aa7b-f34786019aa6/779584e2-ddb4-45cc-b4a5-e366b1d57e80/bb725532-459b-4355-931e-868d2a523768/47dd2abe-64ca-4ca9-8cec-391bbf01d97e/', 3, true, true, 1.00, NULL, NULL, '2026-04-11 04:22:31.039001+00', '2026-04-11 04:28:57.356195+00', NULL, NULL, '5) إرفاق الحصر المعتمد من المسؤول الأول في الجهة أو من ينوب عنه بقائمة الشركات المزمع التعاقد معها بصورة مباشرة أو غير مباشرة لتقديم خدمات تقنية، مع التأكيد على توقيع كل شركة على نموذج الفحص النافي للجهالة، وعينة موقعة وفق النموذج المعتمد.', '5) Attach approved inventory from the entity''s top official or delegate.', NULL, NULL, NULL);
INSERT INTO public.framework_nodes (id, framework_id, parent_id, node_type, reference_code, name, name_ar, description, description_ar, guidance, guidance_ar, sort_order, path, depth, is_active, is_assessable, weight, max_score, metadata_json, created_at, updated_at, maturity_level, evidence_type, acceptance_criteria, acceptance_criteria_en, spec_references, priority, assessment_type) VALUES ('68c4b895-b3bd-42fd-9b0e-55998dd44766', 'b2c124a4-92e9-4fae-bf22-ad5424209b6b', '355108bd-50ab-461c-81a7-0169b4c985f0', 'Standard', 'S5.20.5', 'Applying the Life Journeys Concept', 'تطبيق مفهوم رحلات الحياة', NULL, NULL, NULL, NULL, 5, '/f8a69d5b-caeb-4dbd-b746-b483f0570fb4/355108bd-50ab-461c-81a7-0169b4c985f0/68c4b895-b3bd-42fd-9b0e-55998dd44766/', 2, true, false, NULL, NULL, NULL, '2026-04-11 04:22:33.694612+00', '2026-04-11 04:22:33.694615+00', NULL, NULL, NULL, NULL, NULL, NULL, NULL);
INSERT INTO public.framework_nodes (id, framework_id, parent_id, node_type, reference_code, name, name_ar, description, description_ar, guidance, guidance_ar, sort_order, path, depth, is_active, is_assessable, weight, max_score, metadata_json, created_at, updated_at, maturity_level, evidence_type, acceptance_criteria, acceptance_criteria_en, spec_references, priority, assessment_type) VALUES ('639976a1-d5e2-4c67-9782-90f40e85557d', 'b2c124a4-92e9-4fae-bf22-ad5424209b6b', 'dd5619fa-e0b6-47bb-9424-dd3899ddf678', 'Requirement', 'S5.9.1.R5', '13) Create the entity''s risk champions document clarifying roles and responsibilities.', '13) إنشاء وثيقة رواد المخاطر فى الجهة، لتوضيح الأدوار والمسؤوليات، وذلك لتنسيق وتنفيذ ومتابعة أعمال إدارة المخاطر ورفع التقارير ذات العلاقة.', NULL, NULL, NULL, NULL, 5, '/1da7ecaf-95c5-4402-aa7b-f34786019aa6/779584e2-ddb4-45cc-b4a5-e366b1d57e80/dd5619fa-e0b6-47bb-9424-dd3899ddf678/639976a1-d5e2-4c67-9782-90f40e85557d/', 3, true, true, 1.00, NULL, NULL, '2026-04-11 04:22:30.745487+00', '2026-04-11 04:28:57.11355+00', NULL, NULL, '13) إرفاق وثيقة رواد المخاطر المعتمدة، وفق متطلبات تطبيق هذا المعيار.', '13) Attach approved risk champions document per this standard''s requirements.', NULL, NULL, NULL);
INSERT INTO public.framework_nodes (id, framework_id, parent_id, node_type, reference_code, name, name_ar, description, description_ar, guidance, guidance_ar, sort_order, path, depth, is_active, is_assessable, weight, max_score, metadata_json, created_at, updated_at, maturity_level, evidence_type, acceptance_criteria, acceptance_criteria_en, spec_references, priority, assessment_type) VALUES ('5e9355aa-9a5f-42bd-87ce-e71cf1c51716', 'b2c124a4-92e9-4fae-bf22-ad5424209b6b', '7504c7bb-ab66-4cd3-996d-7e48886981cc', 'Requirement', 'S5.17.2.R5', '4) Make digital services accessible to all beneficiary segments including persons with disabilities and elderly.', '4) إتاحة الخدمات الرقمية لجميع شرائح المستفيدين، وضمان وصول الأشخاص ذوى الإعاقة وكبار السن لها.', NULL, NULL, NULL, NULL, 5, '/66dd45a8-6ec9-4d82-9d56-a83c75b23a47/fbd949a4-48e1-44f2-851a-3243efed765b/7504c7bb-ab66-4cd3-996d-7e48886981cc/5e9355aa-9a5f-42bd-87ce-e71cf1c51716/', 3, true, true, 1.00, NULL, NULL, '2026-04-11 04:22:33.052363+00', '2026-04-11 04:28:58.986761+00', NULL, NULL, '4) إرفاق ما يثبت إتاحة الخدمات الرقمية لجميع شرائح المستفيدين مثل (صور الشاشات وروابط فيديوهات)، بما يضمن إمكانية وصول الأشخاص ذوي الإعاقة وكبار السن لها، وفق متطلبات تطبيق هذا المعیار.', '4) Attach proof of making digital services accessible to all segments including persons with disabilities.', NULL, NULL, NULL);
INSERT INTO public.framework_nodes (id, framework_id, parent_id, node_type, reference_code, name, name_ar, description, description_ar, guidance, guidance_ar, sort_order, path, depth, is_active, is_assessable, weight, max_score, metadata_json, created_at, updated_at, maturity_level, evidence_type, acceptance_criteria, acceptance_criteria_en, spec_references, priority, assessment_type) VALUES ('bb725532-459b-4355-931e-868d2a523768', 'b2c124a4-92e9-4fae-bf22-ad5424209b6b', '779584e2-ddb4-45cc-b4a5-e366b1d57e80', 'Standard', 'S5.9.5', 'Continuous Development and Improvement of Risk Management', 'التطوير والتحسين المستمر لإدارة المخاطر', NULL, NULL, NULL, NULL, 5, '/1da7ecaf-95c5-4402-aa7b-f34786019aa6/779584e2-ddb4-45cc-b4a5-e366b1d57e80/bb725532-459b-4355-931e-868d2a523768/', 2, true, false, NULL, NULL, NULL, '2026-04-11 04:22:30.993193+00', '2026-04-11 04:22:30.993195+00', NULL, NULL, NULL, NULL, NULL, NULL, NULL);
INSERT INTO public.framework_nodes (id, framework_id, parent_id, node_type, reference_code, name, name_ar, description, description_ar, guidance, guidance_ar, sort_order, path, depth, is_active, is_assessable, weight, max_score, metadata_json, created_at, updated_at, maturity_level, evidence_type, acceptance_criteria, acceptance_criteria_en, spec_references, priority, assessment_type) VALUES ('2e1a5465-4b0e-48f1-90df-8634d4dc6e48', 'b2c124a4-92e9-4fae-bf22-ad5424209b6b', 'dbc6cba4-062e-4058-9b87-47a60b79dcf2', 'Requirement', 'S5.10.1.R5', '5) Prepare and approve the business continuity policy and review periodically.', '5) إعداد واعتماد سياسة استمرارية الأعمال ومراجعتها بشكل دوري، أو عند حدوث تغيير جوهري في بيئة التشغيل أو الأهداف الإستراتيجية للجهة.', NULL, NULL, NULL, NULL, 5, '/1da7ecaf-95c5-4402-aa7b-f34786019aa6/1f95de6d-8d99-409f-bf82-49fde52aa796/dbc6cba4-062e-4058-9b87-47a60b79dcf2/2e1a5465-4b0e-48f1-90df-8634d4dc6e48/', 3, true, true, 1.00, NULL, NULL, '2026-04-11 04:22:31.114612+00', '2026-04-11 04:28:57.405897+00', NULL, NULL, '5) إرفاق سياسة إدارة استمرارية الأعمال موثَّقة ومعتمدة، وما يثبت مراجعتها بشكل دوري، وفق متطلبات تطبيق هذا المعيار.', '5) Attach documented and approved business continuity policy and proof of sharing with staff.', NULL, NULL, NULL);
