INSERT INTO public.framework_nodes (id, framework_id, parent_id, node_type, reference_code, name, name_ar, description, description_ar, guidance, guidance_ar, sort_order, path, depth, is_active, is_assessable, weight, max_score, metadata_json, created_at, updated_at, maturity_level, evidence_type, acceptance_criteria, acceptance_criteria_en, spec_references, priority, assessment_type) VALUES ('47d6396a-affb-4f6f-b1a3-395d8f9dd4a3', 'b2c124a4-92e9-4fae-bf22-ad5424209b6b', '408341a3-484a-4e39-ad18-0d1c95689892', 'Requirement', 'S5.12.2.R6', '6) Establish electronic controls limiting staff downloading of unauthorized software.', '6) وضع الضوابط والقيود الإلكترونية التي تحد من تحميل منسوبي الجهة ملفات شخصية كبيرة، أو برامج غير معتمدة إلا حسب ما يتوافق مع اللوائح ذات العلاقة، ومشاركتها مع منسوبي الجهة.', NULL, NULL, NULL, NULL, 6, '/eaa87d00-46fc-440d-b0af-6fb89269407c/7288b767-2e63-43e6-9f39-6e1abb5e45eb/408341a3-484a-4e39-ad18-0d1c95689892/47d6396a-affb-4f6f-b1a3-395d8f9dd4a3/', 3, true, true, 1.00, NULL, NULL, '2026-04-11 04:22:31.947029+00', '2026-04-11 04:28:58.080746+00', NULL, NULL, '6) إرفاق الآلية المستخدمة وما يثبت مشاركتها مع المنسوبين والتي تتضمن الالتزام بالضوابط المعتمدة فيما يتعلق باستخدام الأصول التقنية وأجهزة الحاسب الآلي في الجهة، ومنع استخدام البرامج غير المرخصة.', '6) Attach the mechanism used and proof of sharing with staff and stakeholders.', NULL, NULL, NULL);
INSERT INTO public.framework_nodes (id, framework_id, parent_id, node_type, reference_code, name, name_ar, description, description_ar, guidance, guidance_ar, sort_order, path, depth, is_active, is_assessable, weight, max_score, metadata_json, created_at, updated_at, maturity_level, evidence_type, acceptance_criteria, acceptance_criteria_en, spec_references, priority, assessment_type) VALUES ('750ad048-979b-48df-a142-67c2d5bd4db0', 'b2c124a4-92e9-4fae-bf22-ad5424209b6b', 'b8d1c09a-100e-4bc7-ac17-d7067ee507a0', 'Requirement', 'S5.3.2.R6', '6) Document current state of business, application, and technology architectures.', '6) توثيق الوضع الحالي لبنية الأعمال وبنية التطبيقات وبنية البيانات والبنية التقنية في الجهة، ومستوى التوثيق المطلوب (مستوى مفاهيمي، مستوى منطقي، مستوى فيزيائي).', NULL, NULL, NULL, NULL, 6, '/633ea9b9-b470-4be6-94c9-362bfd768aba/4fe1ba35-8844-4f32-9cb5-7cd7255464bd/b8d1c09a-100e-4bc7-ac17-d7067ee507a0/750ad048-979b-48df-a142-67c2d5bd4db0/', 3, true, true, 1.00, NULL, NULL, '2026-04-11 04:22:29.897555+00', '2026-04-11 04:28:56.56302+00', NULL, NULL, 'وثائق الوضع الحالي لبنية الأعمال وبنية التطبيقات والبنية التقنية في الجهة.', 'Current state documents for business, application, and technology architectures.', NULL, NULL, NULL);
INSERT INTO public.framework_nodes (id, framework_id, parent_id, node_type, reference_code, name, name_ar, description, description_ar, guidance, guidance_ar, sort_order, path, depth, is_active, is_assessable, weight, max_score, metadata_json, created_at, updated_at, maturity_level, evidence_type, acceptance_criteria, acceptance_criteria_en, spec_references, priority, assessment_type) VALUES ('aca5fe9b-a1b6-482d-97e7-023bfb01133c', 'b2c124a4-92e9-4fae-bf22-ad5424209b6b', 'a551835a-dc19-4d88-9517-9305ef6a413e', 'Requirement', 'S5.14.2.R6', '5) Integration with the General Audit Bureau''s electronic oversight system.', '5) الارتباط بمنظومة الرقابة الإلكترونية بالديوان العام للمحاسبة "شامل"', NULL, NULL, NULL, NULL, 6, '/d2a77bfc-3828-4697-8f64-c837e89ff585/bb206aae-4d83-494b-bb48-2d4ae3111473/a551835a-dc19-4d88-9517-9305ef6a413e/aca5fe9b-a1b6-482d-97e7-023bfb01133c/', 3, true, true, 1.00, NULL, NULL, '2026-04-11 04:22:32.454883+00', '2026-04-11 04:28:58.439203+00', NULL, NULL, '5) لا يتطلب إرفاق مستند إثبات، وسيتم التحقق من خلال قوائم الالتزام التي تصدر من الديوان العام للمحاسبة.', '5) No proof document required. Verification through integration lists.', NULL, NULL, NULL);
INSERT INTO public.framework_nodes (id, framework_id, parent_id, node_type, reference_code, name, name_ar, description, description_ar, guidance, guidance_ar, sort_order, path, depth, is_active, is_assessable, weight, max_score, metadata_json, created_at, updated_at, maturity_level, evidence_type, acceptance_criteria, acceptance_criteria_en, spec_references, priority, assessment_type) VALUES ('42b3f251-23be-4009-9efa-5edc6e05c954', 'b2c124a4-92e9-4fae-bf22-ad5424209b6b', '9c0fff37-30c9-4aef-917f-166e5a2683db', 'Requirement', 'S5.14.3.R6', '4) Designate a department for auditing shared systems and services.', '4) تحديد إدارة ضمن الهيكل التنظيمي للجهة، تكّلّف بالتدقيق والمتابعة على أداء الأنظمة والخدمات المشترکة.', NULL, NULL, NULL, NULL, 6, '/d2a77bfc-3828-4697-8f64-c837e89ff585/bb206aae-4d83-494b-bb48-2d4ae3111473/9c0fff37-30c9-4aef-917f-166e5a2683db/42b3f251-23be-4009-9efa-5edc6e05c954/', 3, true, true, 1.00, NULL, NULL, '2026-04-11 04:22:32.551149+00', '2026-04-11 04:28:58.523113+00', NULL, NULL, '4) إرفاق الهيكل التنظيمى ووصف المهام للإدارة المكلفة بالتدقيق والمتابعة على أداء الأنظمة والخدمات المشتركة.', '4) Attach organizational structure and task description for the auditing department.', NULL, NULL, NULL);
