INSERT INTO public.framework_nodes (id, framework_id, parent_id, node_type, reference_code, name, name_ar, description, description_ar, guidance, guidance_ar, sort_order, path, depth, is_active, is_assessable, weight, max_score, metadata_json, created_at, updated_at, maturity_level, evidence_type, acceptance_criteria, acceptance_criteria_en, spec_references, priority, assessment_type) VALUES ('fa821df7-2bd8-4929-9512-c1cf114daeaf', 'b2c124a4-92e9-4fae-bf22-ad5424209b6b', '5073c23a-5f37-4ada-9cc3-ae7f43db015e', 'Requirement', 'S5.2.1.R6', '6) Form the e-Government/Digital Transformation Committee chaired by entity head.', '6) تكوين لجنة التعاملات الإلكترونية / التحول الرقمي برئاسة المسؤول الأول بالجهة أو من ينيبه وعضوية
INSERT INTO public.framework_nodes (id, framework_id, parent_id, node_type, reference_code, name, name_ar, description, description_ar, guidance, guidance_ar, sort_order, path, depth, is_active, is_assessable, weight, max_score, metadata_json, created_at, updated_at, maturity_level, evidence_type, acceptance_criteria, acceptance_criteria_en, spec_references, priority, assessment_type) VALUES ('44b5c1b8-21e0-4f33-9b2a-06d29c3658d9', 'b2c124a4-92e9-4fae-bf22-ad5424209b6b', 'd0e54444-6bd5-49c6-bfc5-ca6e0c3e2740', 'Requirement', 'S5.15.2.R6', '6) Prepare and update the implementation plan for unifying and merging entity platforms.', '6) إعداد الخطة التنفيذية وتحديثها؛ لتوحيد ودمج المنصات الخاصة بالجهة ضمن منصة موحدة بحسب طبيعة المستفيد.', NULL, NULL, NULL, NULL, 6, '/d2a77bfc-3828-4697-8f64-c837e89ff585/ab80a93b-c219-43bb-aaea-5700eee62ef2/d0e54444-6bd5-49c6-bfc5-ca6e0c3e2740/44b5c1b8-21e0-4f33-9b2a-06d29c3658d9/', 3, true, true, 1.00, NULL, NULL, '2026-04-11 04:22:32.732243+00', '2026-04-11 04:28:58.674175+00', NULL, NULL, '6) إرفاق الخطة التنفيذية لتوحيد ودمج المنصات الخاصة بالجهة وفق متطلبات تطبيق هذا المعيار.', '6) Attach the implementation plan for unifying and merging entity platforms.', NULL, NULL, NULL);
INSERT INTO public.framework_nodes (id, framework_id, parent_id, node_type, reference_code, name, name_ar, description, description_ar, guidance, guidance_ar, sort_order, path, depth, is_active, is_assessable, weight, max_score, metadata_json, created_at, updated_at, maturity_level, evidence_type, acceptance_criteria, acceptance_criteria_en, spec_references, priority, assessment_type) VALUES ('d891ccf1-4ae4-48c1-bddd-a3ceb3466612', 'b2c124a4-92e9-4fae-bf22-ad5424209b6b', '23149bbf-e7ac-44b5-b28c-c5a6c92d121c', 'Requirement', 'S5.18.1.R6', '6) Develop entity website with technical tools enabling interactive planning.', '6) تطوير الموقع الإلكتروني للجهة ليتضمن أدوات تقنية تمكّن مختلف شرائح المستفيدين من المشاركة بفاعلية، بما يشمل تخصيص قسم مخصص للمشاركة الإلكترونية، وتمكين سهولة المشاركة عبر وسائل التواصل الاجتماعي، وبما يدعم تطبيق "ضوابط المشاركة الإلكترونية".', NULL, NULL, NULL, NULL, 6, '/f8a69d5b-caeb-4dbd-b746-b483f0570fb4/12905427-3213-4f5f-8f08-94db72538b17/23149bbf-e7ac-44b5-b28c-c5a6c92d121c/d891ccf1-4ae4-48c1-bddd-a3ceb3466612/', 3, true, true, 1.00, NULL, NULL, '2026-04-11 04:22:33.286994+00', '2026-04-11 04:28:59.164678+00', NULL, NULL, '6) لا يتطلب إرفاق مستند إثبات، ويتم متابعة التزام الجهات الحكومية مباشرةً من هيئة الحكومة الرقمية حسب التقارير الدورية التي تصدرها الهيئة وبما يتوافق مع "ضوابط تطوير جودة المحتوى الرقمي للمواقع والمنصات الحكومية الرقمية لتحسين ظهورها على محركات البحث".', '6) No proof document required. Compliance monitored directly by DGA.', NULL, NULL, NULL);
INSERT INTO public.framework_nodes (id, framework_id, parent_id, node_type, reference_code, name, name_ar, description, description_ar, guidance, guidance_ar, sort_order, path, depth, is_active, is_assessable, weight, max_score, metadata_json, created_at, updated_at, maturity_level, evidence_type, acceptance_criteria, acceptance_criteria_en, spec_references, priority, assessment_type) VALUES ('8155e9ab-2f3f-420a-a406-531d880e3d1c', 'b2c124a4-92e9-4fae-bf22-ad5424209b6b', '0d64734f-eef0-44b7-bf59-a75e010d533e', 'Requirement', 'S5.8.1.R6', '6) Government entity registers communications contracts on the relevant platform.', '6) قيام الجهة الحكومية بتسجيل عقودها المتعلقة بخدمات الاتصالات سواء أكانت نفقات عامة أم برامج أم مشاريع على منصة "اعتماد".', NULL, NULL, NULL, NULL, 6, '/67c04d75-3ce8-4615-9784-464e399ce0cb/3059ba0d-feee-46b8-9640-bf112a65f1d6/0d64734f-eef0-44b7-bf59-a75e010d533e/8155e9ab-2f3f-420a-a406-531d880e3d1c/', 3, true, true, 1.00, NULL, NULL, '2026-04-11 04:22:30.602365+00', '2026-04-11 04:28:57.021718+00', NULL, NULL, '6) إرفاق صورة من منصة "اعتماد" توضح الرقم المرجعى للعقد واسم العقد ورقم المنافسة المرتبط بالعقد المشار إليه.', '6) Attach ''Etimad'' screenshot showing contract reference number and name.', NULL, NULL, NULL);
INSERT INTO public.framework_nodes (id, framework_id, parent_id, node_type, reference_code, name, name_ar, description, description_ar, guidance, guidance_ar, sort_order, path, depth, is_active, is_assessable, weight, max_score, metadata_json, created_at, updated_at, maturity_level, evidence_type, acceptance_criteria, acceptance_criteria_en, spec_references, priority, assessment_type) VALUES ('bbee28f7-ed60-474d-b2fa-9d3ba4ccbc26', 'b2c124a4-92e9-4fae-bf22-ad5424209b6b', 'a4cfa6f9-5f2d-41bb-a8f1-11a751df6ac6', 'Requirement', 'S5.3.1.R6', '6) Form an EA governance committee including representatives of relevant organizational units.', '6) تشكيل لجنة لحوكمة البنية المؤسسية، وتضمين ممثلين الوحدات التنظيمية ذات العلاقة.', NULL, NULL, NULL, NULL, 6, '/633ea9b9-b470-4be6-94c9-362bfd768aba/4fe1ba35-8844-4f32-9cb5-7cd7255464bd/a4cfa6f9-5f2d-41bb-a8f1-11a751df6ac6/bbee28f7-ed60-474d-b2fa-9d3ba4ccbc26/', 3, true, true, 1.00, NULL, NULL, '2026-04-11 04:22:29.825574+00', '2026-04-11 04:28:56.504772+00', NULL, NULL, 'وثيقة معتمدة تثبت تشكيل لجنة لحوكمة البنية المؤسسية وآلية عملها.', 'Approved document proving EA governance committee formation and working mechanism.', NULL, NULL, NULL);
