INSERT INTO public.framework_nodes (id, framework_id, parent_id, node_type, reference_code, name, name_ar, description, description_ar, guidance, guidance_ar, sort_order, path, depth, is_active, is_assessable, weight, max_score, metadata_json, created_at, updated_at, maturity_level, evidence_type, acceptance_criteria, acceptance_criteria_en, spec_references, priority, assessment_type) VALUES ('973c7a78-f72e-4d67-9faf-b904b70607a7', 'b2c124a4-92e9-4fae-bf22-ad5424209b6b', '9c0fff37-30c9-4aef-917f-166e5a2683db', 'Requirement', 'S5.14.3.R8', '6) Monitor usage data per a comprehensive entity-defined methodology.', '6) متابعة بيانات الاستخدام وفقاً لمنهجية شاملة تحددها الجهة المسؤولة، واستخلاص النتائج والمرئيات من تلك البيانات والاستفادة منها.', NULL, NULL, NULL, NULL, 8, '/d2a77bfc-3828-4697-8f64-c837e89ff585/bb206aae-4d83-494b-bb48-2d4ae3111473/9c0fff37-30c9-4aef-917f-166e5a2683db/973c7a78-f72e-4d67-9faf-b904b70607a7/', 3, true, true, 1.00, NULL, NULL, '2026-04-11 04:22:32.569799+00', '2026-04-11 04:28:58.54036+00', NULL, NULL, '6) إرفاق الوثائق والعينات من التقارير ومحاضر الاجتماعات والقرارات التي تثبت أن الجهة تتابع بيانات الاستخدام، وفق متطلبات تطبيق هذا المعيار.', '6) Attach documents and report samples showing usage monitoring.', NULL, NULL, NULL);
