INSERT INTO public.framework_nodes (id, framework_id, parent_id, node_type, reference_code, name, name_ar, description, description_ar, guidance, guidance_ar, sort_order, path, depth, is_active, is_assessable, weight, max_score, metadata_json, created_at, updated_at, maturity_level, evidence_type, acceptance_criteria, acceptance_criteria_en, spec_references, priority, assessment_type) VALUES ('ae666969-f65a-42f2-b22e-75bf413cabd1', 'b2c124a4-92e9-4fae-bf22-ad5424209b6b', '031993d8-6b02-49be-983b-9dcc723aad3f', 'Requirement', 'S5.10.5.R8', '4) Provide backup data centers for critical platforms and applications.', '4) توفير مراكز البيانات الاحتياطية للمنصات والتطبيقات الحرجة والحساسة لدى الجهة، وفق نتائج تحليل أثر انقطاع الأعمال.', NULL, NULL, NULL, NULL, 8, '/1da7ecaf-95c5-4402-aa7b-f34786019aa6/1f95de6d-8d99-409f-bf82-49fde52aa796/031993d8-6b02-49be-983b-9dcc723aad3f/ae666969-f65a-42f2-b22e-75bf413cabd1/', 3, true, true, 1.00, NULL, NULL, '2026-04-11 04:22:31.450978+00', '2026-04-11 04:28:57.696688+00', NULL, NULL, '4) إرفاق عقود الصيانة والتشغيل التي تشمل بنود المراكز الاحتياطية البديلة (DR) لحفظ البيانات، ومراكز الأنظمة الحساسة لحفظ وتشغيل البيانات وإجراءات اختيارها وفق المعايير الدولية لدى الجهة، أو ما يثبت توفير مراكز البيانات الاحتياطية داخل الجهة.', '4) Attach maintenance and operation contracts including backup center provisions.', NULL, NULL, NULL);
INSERT INTO public.framework_nodes (id, framework_id, parent_id, node_type, reference_code, name, name_ar, description, description_ar, guidance, guidance_ar, sort_order, path, depth, is_active, is_assessable, weight, max_score, metadata_json, created_at, updated_at, maturity_level, evidence_type, acceptance_criteria, acceptance_criteria_en, spec_references, priority, assessment_type) VALUES ('60be0050-c2d8-4e56-a8e3-61153bd7ca89', 'b2c124a4-92e9-4fae-bf22-ad5424209b6b', '031993d8-6b02-49be-983b-9dcc723aad3f', 'Requirement', 'S5.10.5.R9', '5) Prepare and approve IT and communications disaster recovery plans.', '5) إعداد واعتماد خطط التعافي لتقنية المعلومات والاتصالات، لاستعادة المنصات والتطبيقات والخدمات الرقمية والبيانات في الوقت المناسب، لتحقيق وقت الاسترجاع المستهدف للجهة بما يستوفي جميع متطلبات التطبيق.', NULL, NULL, NULL, NULL, 9, '/1da7ecaf-95c5-4402-aa7b-f34786019aa6/1f95de6d-8d99-409f-bf82-49fde52aa796/031993d8-6b02-49be-983b-9dcc723aad3f/60be0050-c2d8-4e56-a8e3-61153bd7ca89/', 3, true, true, 1.00, NULL, NULL, '2026-04-11 04:22:31.459947+00', '2026-04-11 04:28:57.706761+00', NULL, NULL, '5) إرفاق خطط التعافي من الكوارث تقنية المعلومات والاتصالات المرتبطة بالمنصات والتطبيقات والخدمات الرقمية والبيانات المعتمدة لدى الجهة، وفق متطلبات تطبيق هذا المعيار.', '5) Attach approved IT disaster recovery plans.', NULL, NULL, NULL);
