INSERT INTO public.framework_nodes (id, framework_id, parent_id, node_type, reference_code, name, name_ar, description, description_ar, guidance, guidance_ar, sort_order, path, depth, is_active, is_assessable, weight, max_score, metadata_json, created_at, updated_at, maturity_level, evidence_type, acceptance_criteria, acceptance_criteria_en, spec_references, priority, assessment_type) VALUES ('d7a82435-f4d2-400c-8477-2ec255cda579', 'b2c124a4-92e9-4fae-bf22-ad5424209b6b', 'd4575564-4f57-408e-9d88-23cb143189e9', 'Requirement', 'S5.10.3.R10', '9) Define Maximum Tolerable Period of Disruption (MTPD) for each critical process.', '9) تحديد الفترة الزمنية القصوى المسموح بها (MTPD) لانقطاع الأعمال للمنتجات، والخدمات والعمليات والأنشطة، والحد الأدنى من مستوى تقديم الخدمة (MBCO).', NULL, NULL, NULL, NULL, 10, '/1da7ecaf-95c5-4402-aa7b-f34786019aa6/1f95de6d-8d99-409f-bf82-49fde52aa796/d4575564-4f57-408e-9d88-23cb143189e9/d7a82435-f4d2-400c-8477-2ec255cda579/', 3, true, true, 1.00, NULL, NULL, '2026-04-11 04:22:31.31073+00', '2026-04-11 04:28:57.568906+00', NULL, NULL, '9) إرفاق عينات من التقارير التي توضح نتائج تحليل أثر انقطاع الأعمال بما يشمل تحديد الفترة الزمنية القصوى المسموح بها (MTPD)، والحد الأدنى من أهداف استمرارية الأعمال (MBCO).', '9) Attach report samples showing business impact analysis results including MTPD.', NULL, NULL, NULL);
INSERT INTO public.framework_nodes (id, framework_id, parent_id, node_type, reference_code, name, name_ar, description, description_ar, guidance, guidance_ar, sort_order, path, depth, is_active, is_assessable, weight, max_score, metadata_json, created_at, updated_at, maturity_level, evidence_type, acceptance_criteria, acceptance_criteria_en, spec_references, priority, assessment_type) VALUES ('8cc4b785-22ab-4115-a423-802956f1abd5', 'b2c124a4-92e9-4fae-bf22-ad5424209b6b', 'a551835a-dc19-4d88-9517-9305ef6a413e', 'Requirement', 'S5.14.2.R10', '9) Include usage agreements including consequences of system/resource misuse.', '9) إدراج اتفاقية الاستخدام متضمنة ما يترتب على إساءة استخدام النظم والموارد المعلوماتية والروابط الإلكترونية للأنظمة واللوائح ذات العلاقة.', NULL, NULL, NULL, NULL, 10, '/d2a77bfc-3828-4697-8f64-c837e89ff585/bb206aae-4d83-494b-bb48-2d4ae3111473/a551835a-dc19-4d88-9517-9305ef6a413e/8cc4b785-22ab-4115-a423-802956f1abd5/', 3, true, true, 1.00, NULL, NULL, '2026-04-11 04:22:32.490877+00', '2026-04-11 04:28:58.473485+00', NULL, NULL, '9) إرفاق نسخة من اتفاقية الاستخدام وفق متطلبات تطبيق هذا المعيار.', '9) Attach usage agreement copy per this standard''s requirements.', NULL, NULL, NULL);
