INSERT INTO public.framework_nodes (id, framework_id, parent_id, node_type, reference_code, name, name_ar, description, description_ar, guidance, guidance_ar, sort_order, path, depth, is_active, is_assessable, weight, max_score, metadata_json, created_at, updated_at, maturity_level, evidence_type, acceptance_criteria, acceptance_criteria_en, spec_references, priority, assessment_type) VALUES ('0a775f96-6ba0-4129-9837-2bf186e4540e', 'b2c124a4-92e9-4fae-bf22-ad5424209b6b', '031993d8-6b02-49be-983b-9dcc723aad3f', 'Requirement', 'S5.10.5.R11', '7) Communicate with DGA in case of service disruption.', '7) التواصل مع هيئة الحكومة الرقمية في حال وجود انقطاع للخدمات الرقمية حسب دليل المستخدم للإبلاغ عن انقطاع الخدمات الحكومية الرقمية عبر بوابة رقمي.', NULL, NULL, NULL, NULL, 11, '/1da7ecaf-95c5-4402-aa7b-f34786019aa6/1f95de6d-8d99-409f-bf82-49fde52aa796/031993d8-6b02-49be-983b-9dcc723aad3f/0a775f96-6ba0-4129-9837-2bf186e4540e/', 3, true, true, 1.00, NULL, NULL, '2026-04-11 04:22:31.479041+00', '2026-04-11 04:28:57.724601+00', NULL, NULL, '7) لا يتطلب إرفاق مستند إثبات، وسيتم التحقق داخلياً من منصة "رقمي".', '7) No proof document required. Internal verification from the platform.', NULL, NULL, NULL);
