INSERT INTO public.assessment_responses (id, instance_id, node_id, template_id, status, response_data, computed_score, computed_score_label, scored_by, reviewed_by, scored_at, reviewed_at, created_at, updated_at, ai_product_id, current_review_round) VALUES ('dc93ac92-b9ac-4c87-a607-8761916b24b3', '2bc91cb1-a4d1-48a4-98c4-bd9aeb854c3b', 'f2907f90-c656-4a05-aa34-b1c0586f5133', 'b2c3d4e5-f6a7-8901-bcde-f12345678901', 'answered', '{"doc_signed": false, "doc_approved": false, "ai_assessment": {"confidence": 100, "justification": "The requirement specifies providing records that trace decisions back to their data sources and algorithms, including timestamps, data points used, and intermediate processing steps. The document explicitly states non-compliance due to the absence of such mechanisms in the system. There is no evidence provided to demonstrate compliance with these criteria.", "_ai_product_id": "26148612-c82e-4529-846e-91dadb24f48a", "recommendations": "Implement a logging mechanism to record all interactions, data sources consulted, applied algorithms, and intermediate processing steps. Ensure that this log includes timestamps for each step. Regularly review logs to ensure they are complete and accurate.", "review_feedback": "The provided document does not meet the requirements for internal audit logs as outlined in R1.5. The answer clearly states that the MOTLS Chatbot for Employees implementation is non-compliant, lacking any mechanism to trace decisions back to their data sources and algorithms. There are no records of timestamps, data points used, or intermediate processing steps.", "compliance_status": "Non-Compliant", "document_analysis": [{"notes": "The document is dated but lacks formal approval and signatures, making it weak evidence.", "file_name": "MOTLS_Chatbot_AC_Non_Compliant.docx", "approved_by": null, "is_approved": false, "document_date": "2026-04-XX", "has_signature": false}]}, "justification": "The requirement specifies providing records that trace decisions back to their data sources and algorithms, including timestamps, data points used, and intermediate processing steps. The document explicitly states non-compliance due to the absence of such mechanisms in the system. There is no evidence provided to demonstrate compliance with these criteria.", "recommendation": "Implement a logging mechanism to record all interactions, data sources consulted, applied algorithms, and intermediate processing steps. Ensure that this log includes timestamps for each step. Regularly review logs to ensure they are complete and accurate.", "review_feedback": "The provided document does not meet the requirements for internal audit logs as outlined in R1.5. The answer clearly states that the MOTLS Chatbot for Employees implementation is non-compliant, lacking any mechanism to trace decisions back to their data sources and algorithms. There are no records of timestamps, data points used, or intermediate processing steps.", "compliance_status": "Semi-Compliant"}', 0.00, 'Semi-Compliant', 'e711b119-d9bf-4b40-9553-be7d9acf7fa7', NULL, '2026-04-12 09:30:27.012714+00', NULL, '2026-04-11 16:40:07.251191+00', '2026-04-12 09:30:27.014331+00', '26148612-c82e-4529-846e-91dadb24f48a', 0);
