INSERT INTO public.assessment_responses (id, instance_id, node_id, template_id, status, response_data, computed_score, computed_score_label, scored_by, reviewed_by, scored_at, reviewed_at, created_at, updated_at, ai_product_id, current_review_round) VALUES ('2fc2ab83-8d07-4a4d-a98e-76e5970c282c', '2bc91cb1-a4d1-48a4-98c4-bd9aeb854c3b', '40b14599-671e-4171-a13d-c8e27856a519', 'b2c3d4e5-f6a7-8901-bcde-f12345678901', 'draft', '{"doc_signed": false, "doc_approved": false, "ai_assessment": {"confidence": 100, "justification": "The control requires providing detailed logs of training sessions, including dates, attendees, materials, objectives, and topics. The sole supporting evidence provided, ''hierarchy (10).xlsx'', is a specification matrix outlining various compliance requirements across different data management domains. This document does not contain any records, logs, or reports pertaining to the execution or documentation of training sessions for the Road Congestion prediction product. Therefore, the evidence is insufficient to meet the acceptance criteria.", "_ai_product_id": "4ff85909-7d19-436f-9179-128418b4c582", "recommendations": "To achieve compliance, provide a formal Training Session Report or a collection of detailed logs. This evidence must explicitly list: 1) The date of each session; 2) A comprehensive list of all attendees; 3) The specific materials utilized (e.g., presentation decks, manuals); 4) The defined objectives for the training; and 5) The detailed topics covered during each session.", "review_feedback": "The assessment lacks any supporting documentation related to training sessions for the AI product. The provided evidence document is a compliance matrix detailing various data governance specifications, but it does not contain the required operational records.\n\nTo demonstrate compliance with this control, detailed logs are necessary. These logs must systematically document the entire training lifecycle, including who attended, what was taught, and the materials used. The absence of such records means the acceptance criteria cannot be verified.", "compliance_status": "Non-Compliant", "document_analysis": [{"notes": "This document is a compliance matrix/specification sheet and does not contain evidence of training logs.", "file_name": "hierarchy (10).xlsx", "approved_by": null, "is_approved": false, "document_date": null, "has_signature": false}]}, "justification": "The control requires providing detailed logs of training sessions, including dates, attendees, materials, objectives, and topics. The sole supporting evidence provided, ''hierarchy (10).xlsx'', is a specification matrix outlining various compliance requirements across different data management domains. This document does not contain any records, logs, or reports pertaining to the execution or documentation of training sessions for the Road Congestion prediction product. Therefore, the evidence is insufficient to meet the acceptance criteria.", "recommendation": "To achieve compliance, provide a formal Training Session Report or a collection of detailed logs. This evidence must explicitly list: 1) The date of each session; 2) A comprehensive list of all attendees; 3) The specific materials utilized (e.g., presentation decks, manuals); 4) The defined objectives for the training; and 5) The detailed topics covered during each session.", "review_feedback": "The assessment lacks any supporting documentation related to training sessions for the AI product. The provided evidence document is a compliance matrix detailing various data governance specifications, but it does not contain the required operational records.\n\nTo demonstrate compliance with this control, detailed logs are necessary. These logs must systematically document the entire training lifecycle, including who attended, what was taught, and the materials used. The absence of such records means the acceptance criteria cannot be verified.", "compliance_status": "Non-Compliant"}', 2.00, 'Non-Compliant', 'e711b119-d9bf-4b40-9553-be7d9acf7fa7', NULL, '2026-04-11 19:41:01.333832+00', NULL, '2026-04-11 16:40:07.251269+00', '2026-04-11 19:41:01.334397+00', '4ff85909-7d19-436f-9179-128418b4c582', 0);
