INSERT INTO public.assessment_responses (id, instance_id, node_id, template_id, status, response_data, computed_score, computed_score_label, scored_by, reviewed_by, scored_at, reviewed_at, created_at, updated_at, ai_product_id, current_review_round) VALUES ('ef156163-ebdd-4209-b046-908b27599f54', '2bc91cb1-a4d1-48a4-98c4-bd9aeb854c3b', '40b14599-671e-4171-a13d-c8e27856a519', 'b2c3d4e5-f6a7-8901-bcde-f12345678901', 'answered', '{"doc_signed": false, "doc_approved": true, "ai_assessment": {"confidence": 100, "justification": "The control requires evidence of a ''Training Session Report'' detailing specific elements: dates, attendees, materials, objectives, and topics. The supporting document, ''od_m1_evidence.docx'', is an ''Open Dataset List'' and discusses data governance and inventory management. This document fails to provide any evidence regarding the scheduling, participation, content, or objectives of any training sessions. Consequently, the acceptance criteria for R2.1 are not met.", "_ai_product_id": "26148612-c82e-4529-846e-91dadb24f48a", "recommendations": "To achieve compliance, evidence must be provided in the form of formal, dated, and approved training session reports. These reports must explicitly contain detailed logs covering the dates, a list of attendees, documentation of materials used, and clear articulation of the objectives and topics covered for each training instance.", "review_feedback": "The evidence provided pertains to the inventory and status of open datasets, which is unrelated to the control requirement for documenting training sessions. The documentation reviewed details data assets and their publication status, rather than records of training activities.\n\nThe acceptance criteria mandate detailed logs including session dates, attendee lists, materials used, and specific objectives/topics. The evidence reviewed does not contain any information corresponding to these required training records.\n\nTo demonstrate compliance, evidence must directly address the lifecycle and documentation of training sessions conducted for the AI product.", "compliance_status": "Non-Compliant", "document_analysis": [{"notes": "Document is dated and marked as ''Approved'' (معتمد), but lacks explicit signatures.", "file_name": "od_m1_evidence.docx", "approved_by": null, "is_approved": true, "document_date": "2025-01-15", "has_signature": false}]}, "justification": "The control requires evidence of a ''Training Session Report'' detailing specific elements: dates, attendees, materials, objectives, and topics. The supporting document, ''od_m1_evidence.docx'', is an ''Open Dataset List'' and discusses data governance and inventory management. This document fails to provide any evidence regarding the scheduling, participation, content, or objectives of any training sessions. Consequently, the acceptance criteria for R2.1 are not met.", "recommendation": "To achieve compliance, evidence must be provided in the form of formal, dated, and approved training session reports. These reports must explicitly contain detailed logs covering the dates, a list of attendees, documentation of materials used, and clear articulation of the objectives and topics covered for each training instance.", "review_feedback": "The evidence provided pertains to the inventory and status of open datasets, which is unrelated to the control requirement for documenting training sessions. The documentation reviewed details data assets and their publication status, rather than records of training activities.\n\nThe acceptance criteria mandate detailed logs including session dates, attendee lists, materials used, and specific objectives/topics. The evidence reviewed does not contain any information corresponding to these required training records.\n\nTo demonstrate compliance, evidence must directly address the lifecycle and documentation of training sessions conducted for the AI product.", "compliance_status": "Non-Compliant"}', 2.00, 'Non-Compliant', 'e711b119-d9bf-4b40-9553-be7d9acf7fa7', NULL, '2026-04-11 19:40:15.7112+00', NULL, '2026-04-11 16:40:07.251193+00', '2026-04-11 19:40:15.71269+00', '26148612-c82e-4529-846e-91dadb24f48a', 0);
