INSERT INTO public.assessment_scale_levels (id, scale_id, value, label, label_ar, description, description_ar, color, sort_order, min_threshold, max_threshold) VALUES ('6e6c1ec2-d3a0-4444-a905-9b8169d8a330', 'f080a8ca-eac9-4b66-816b-f74a3385301a', 0.00, 'Absence of Capabilities', 'غياب القدرات', 'No AI efforts or capabilities exist within the organization. Score range: 0% - 4.9%', 'لم يتم بعد ترسيخ الذكاء الاصطناعي داخل المنظمة. لا يوجد جهود أو قدرات في المجال', '#C0392B', 0, NULL, NULL);
INSERT INTO public.assessment_scale_levels (id, scale_id, value, label, label_ar, description, description_ar, color, sort_order, min_threshold, max_threshold) VALUES ('83f9c19e-4cf7-4f9f-bd37-3ec4dee6b1d9', 'f080a8ca-eac9-4b66-816b-f74a3385301a', 1.00, 'Building Phase', 'مرحلة البناء', 'Organization recognizes AI importance. Limited pilot projects without clear organizational structure. Score range: 5% - 24.9%', 'تعترف المنظمة بأهمية الذكاء الاصطناعي. يتم بناء مبادرات أو مشاريع تجريبية محدودة دون هيكل تنظيمي واضح أو تكامل شامل', '#E67E22', 1, NULL, NULL);
INSERT INTO public.assessment_scale_levels (id, scale_id, value, label, label_ar, description, description_ar, color, sort_order, min_threshold, max_threshold) VALUES ('12983dc0-7154-467a-89f8-5472b0638ae8', 'f080a8ca-eac9-4b66-816b-f74a3385301a', 2.00, 'Activation Phase', 'مرحلة التفعيل', 'Regulatory frameworks, strategies, and governance mechanisms activated. Initial implementation across multiple departments. Score range: 25% - 49.9%', 'تم تفعيل الأطر التنظيمية والاستراتيجيات وآليات الحوكمة للذكاء الاصطناعي. بدأ التطبيق الأولي على مستوى عدة إدارات مع ممارسات قياس ناشئة', '#F1C40F', 2, NULL, NULL);
