INSERT INTO public.assessment_scale_levels (id, scale_id, value, label, label_ar, description, description_ar, color, sort_order, min_threshold, max_threshold) VALUES ('7d587602-edb6-44d7-9dc4-3ac3add676b1', '618feeca-0404-420b-8cab-1302ebc29e69', 4.00, 'Managed', 'التمكن', NULL, NULL, '#1D9E75', 4, NULL, NULL);
INSERT INTO public.assessment_scale_levels (id, scale_id, value, label, label_ar, description, description_ar, color, sort_order, min_threshold, max_threshold) VALUES ('35373692-361e-418f-860b-33437d1b9df2', '618feeca-0404-420b-8cab-1302ebc29e69', 5.00, 'Pioneer', 'الريادة', NULL, NULL, '#0F6E56', 5, NULL, NULL);
INSERT INTO public.assessment_scale_levels (id, scale_id, value, label, label_ar, description, description_ar, color, sort_order, min_threshold, max_threshold) VALUES ('894a1cac-ae77-4f56-a8e4-12a881169d23', 'f080a8ca-eac9-4b66-816b-f74a3385301a', 3.00, 'Proficiency Phase', 'مرحلة التمكن', 'AI integrated into operations and institutional decision-making. Strategy and infrastructure aligned, adoption built on performance indicators and governance. Score range: 50% - 79.9%', 'يتم دمج الذكاء الاصطناعي في العمليات واتخاذ القرار المؤسسي. وتتكامل الاستراتيجية والبنية التحتية والمهارات يتم التبني بناءً على مؤشرات أداء وحوكمة', '#0091DA', 3, NULL, NULL);
INSERT INTO public.assessment_scale_levels (id, scale_id, value, label, label_ar, description, description_ar, color, sort_order, min_threshold, max_threshold) VALUES ('bf7f4c11-c3b6-4a37-ab90-27017beb1c4b', 'f080a8ca-eac9-4b66-816b-f74a3385301a', 4.00, 'Excellence Phase', 'مرحلة التميز', 'AI contributes to leading strategic transformation, enabling digital services, and achieving measurable impact. Initiatives expanded and evaluated periodically. Score range: 80% - 94.9%', 'يُسهم الذكاء الاصطناعي في قيادة التحول الاستراتيجي، وتمكين الخدمات الرقمية، وتحقيق أثر ملموس. يتم توسيع نطاق المبادرات وتقييمها بشكل دوري', '#27AE60', 4, NULL, NULL);
INSERT INTO public.assessment_scale_levels (id, scale_id, value, label, label_ar, description, description_ar, color, sort_order, min_threshold, max_threshold) VALUES ('1253c5a0-e002-4e39-8778-ef8d3942e17c', 'f080a8ca-eac9-4b66-816b-f74a3385301a', 5.00, 'Leadership Phase', 'مرحلة الريادة', 'Organization leads the national AI landscape with advanced adoption, sustained innovation, and measurable impact. Score range: 95% - 100%', 'تتصدر المنظمة المشهد الوطني في نضج الذكاء الاصطناعي. وتُطور مستوى متقدماً من التبني والابتكار المستمر وتحقيق الأثر القابل للقياس', '#00338D', 5, NULL, NULL);
